// ── Logo — accurate SVG recreation of the uploaded shield logo ─
// Studied pixel by pixel: tall shield, pointed bottom, navy left, teal-green right,
// bright highlight top-right face, white rounded "e" with horizontal dash bar
function EvidentraLogo({ size=36, showText=true, light=false }) {
  // Evidentra360 — segmented ring logo matching brand asset
  // 6 arc segments with gaps, clockwise from top-left
  const cx = 50, cy = 50, r = 36, sw = 11;
  const segs = [
    { s:210, e:278, c: light ? 'rgba(255,255,255,0.92)' : '#062B7A' },
    { s:283, e:351, c: '#16B5B8' },
    { s:356, e:424, c: '#63D6D9' },
    { s:429, e:497, c: '#FF9A2F' },
    { s:502, e:570, c: '#FF5A6E' },
    { s:575, e:643, c: '#7A57D1' },
  ];
  const pt = (deg, rad) => {
    const a = (deg - 90) * Math.PI / 180;
    return { x: cx + rad * Math.cos(a), y: cy + rad * Math.sin(a) };
  };
  const arc = (s, e) => {
    const a = pt(s, r), b = pt(e, r);
    return `M ${a.x.toFixed(2)} ${a.y.toFixed(2)} A ${r} ${r} 0 ${(e-s)>180?1:0} 1 ${b.x.toFixed(2)} ${b.y.toFixed(2)}`;
  };

  return (
    <div style={{display:"flex", alignItems:"center", gap: showText ? Math.round(size*0.32) : 0}}>
      <svg width={size} height={size} viewBox="0 0 100 100" fill="none"
        style={{flexShrink:0, filter: light
          ? "drop-shadow(0 0 8px rgba(99,214,217,0.4))"
          : "drop-shadow(0 2px 8px rgba(6,43,122,0.18))"}}>
        {segs.map((seg,i) => (
          <path key={i} d={arc(seg.s, seg.e)}
            stroke={seg.c} strokeWidth={sw} strokeLinecap="round" fill="none"/>
        ))}
      </svg>
      {showText && (
        <div style={{lineHeight:1, userSelect:"none"}}>
          <div style={{display:"flex", alignItems:"baseline",
            fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif"}}>
            <span style={{
              fontSize: Math.round(size * 0.52), fontWeight: 700,
              color: light ? "#FFFFFF" : "#062B7A",
              letterSpacing: "-0.5px", lineHeight: 1,
            }}>EVIDENTRA</span>
            <span style={{
              fontSize: Math.round(size * 0.52), fontWeight: 900,
              color: light ? "#63D6D9" : "#16B5B8",
              letterSpacing: "-0.5px", lineHeight: 1,
            }}>360</span>
          </div>
          <div style={{
            fontSize: Math.round(size * 0.21), fontWeight: 500,
            color: light ? "rgba(255,255,255,0.45)" : "#6B7280",
            fontFamily: "'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif",
            letterSpacing: "2px", textTransform: "uppercase", marginTop: 3,
          }}>Governance · Compliance · Assurance</div>
        </div>
      )}
    </div>
  );
}


