// ── Small helpers ─────────────────────────────────────────────
const kloeColor = d => ({Safe:B.danger,Effective:B.warning,Caring:B.success,Responsive:B.info,"Well-led":"#7A57D1"}[d]||B.textMid);
const priColor  = p => ({High:{bg:"#FDF0F0",fg:B.danger},Medium:{bg:"#FDF8EE",fg:B.warning},Low:{bg:"#F0FDF4",fg:B.success}}[p]||{bg:B.silver,fg:B.textMid});

function Tag({text}){
  const c = kloeColor(text) || priColor(text).fg;
  const bg= ({Safe:"#FDF0F0",Effective:"#FDF8EE",Caring:"#F0FDF4",Responsive:"#EDF5FE","Well-led":"#F3F0FD",High:"#FDF0F0",Medium:"#FDF8EE",Low:"#F0FDF4"})[text]||B.silver;
  return <span style={{background:bg,color:c,padding:"2px 8px",borderRadius:20,fontSize:11,fontWeight:600,whiteSpace:"nowrap"}}>{text}</span>;
}

function CircleScore({score,size=110}){
  const r=size*0.37, circ=2*Math.PI*r, fill=(score/100)*circ;
  const color=score>=85?B.success:score>=70?B.warning:B.danger;
  return(
    <svg width={size} height={size} style={{transform:"rotate(-90deg)"}}>
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={B.silver} strokeWidth={size*0.085}/>
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={color}
        strokeWidth={size*0.085} strokeDasharray={`${fill} ${circ}`} strokeLinecap="round"/>
      <text x={size/2} y={size/2} textAnchor="middle" dominantBaseline="middle"
        fill={B.textDark} fontSize={size*0.21} fontWeight={700}
        style={{transform:`rotate(90deg)`,transformOrigin:`${size/2}px ${size/2}px`}}>
        {score}%
      </text>
    </svg>
  );
}

function KloeBar({domain,score}){
  const color=kloeColor(domain);
  return(
    <div style={{marginBottom:9}}>
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
        <span style={{fontSize:12,fontWeight:500,color:B.textMid}}>{domain}</span>
        <span style={{fontSize:12,fontWeight:700,color}}>{score}%</span>
      </div>
      <div style={{height:5,background:B.silver,borderRadius:3,overflow:"hidden"}}>
        <div style={{height:"100%",width:`${score}%`,background:color,borderRadius:3}}/>
      </div>
    </div>
  );
}

