// ── SIDEBAR — Premium navigation ──────────────────────────────
function Sidebar({role,active,onNav,collapsed}){
  const items   = NAV_BY_ROLE[role]||[];
  const user    = DEMO_USERS[role];
  const cfg     = APP_CONFIG;
  const setting = cfg?CARE_SETTINGS[cfg.settingId]:null;
  const _rawAlerts = generateLiveAlerts();
  const _sidebarBadges = getModuleAlertCounts(_rawAlerts);

  // Nav groups with labels and separators
  const GROUP_MAP = {
    dashboard:   "home",
    briefing:    "home",
    digest:      "home",
    tasks:       "compliance",
    audits:      "compliance",
    mock:        "compliance",
    inspection:  "compliance",
    calendar:    "compliance",
    pir:         "compliance",
    evidence:    "records",
    staff:       "records",
    staffroles:  "records",
    serviceusers:"records",
    safeguarding:"clinical",
    medication:  "clinical",
    workforce:   "intelligence",
    accountability:"intelligence",
    delegation:  "intelligence",
    reports:     "intelligence",
    profdev:     "growth",
    companies:   "admin",
    onboarding:  "admin",
    billing:     "admin",
    users:       "admin",
    systemlogs:  "admin",
    settings:    "admin",
    multisite:   "admin",
    compliance:  "admin",
  };
  const GROUP_LABELS = {
    home:        "",
    compliance:  "Compliance",
    records:     "Records",
    clinical:    "Clinical",
    intelligence:"Intelligence",
    growth:      "Development",
    admin:       "Administration",
  };

  // Build grouped nav
  const groups = {};
  items.forEach(item=>{
    const g = GROUP_MAP[item.id]||"other";
    if(!groups[g]) groups[g]=[];
    groups[g].push(item);
  });
  const groupOrder = ["home","compliance","records","clinical","intelligence","growth","admin","other"];

  return(
    <div style={{
      width:collapsed?64:256,
      minHeight:"100vh",
      background:"linear-gradient(175deg,#041D56 0%,#031648 60%,#020F30 100%)",
      display:"flex",flexDirection:"column",
      transition:"width 0.22s cubic-bezier(0.4,0,0.2,1)",
      flexShrink:0,
      borderRight:"1px solid rgba(255,255,255,0.05)",
      position:"relative",
      zIndex:20,
      boxShadow:"3px 0 20px rgba(0,0,0,0.3)",
    }}>
      {/* Logo area */}
      <div style={{
        height:66,
        display:"flex",alignItems:"center",
        padding:collapsed?"0 17px":"0 20px",
        borderBottom:"1px solid rgba(255,255,255,0.06)",
        flexShrink:0,
        background:"linear-gradient(135deg,rgba(43,191,178,0.07),rgba(255,255,255,0.01))",
      }}>
        <EvidentraLogo size={collapsed?32:30} showText={!collapsed} light/>
      </div>

      {/* Setting badge */}
      {!collapsed&&setting&&(
        <div style={{padding:"8px 12px",borderBottom:"1px solid rgba(255,255,255,0.04)"}}>
          <div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 8px",background:`${setting.color}15`,borderRadius:6,border:`1px solid ${setting.color}25`}}>
            <span style={{fontSize:11}}>{setting.icon}</span>
            <div style={{minWidth:0}}>
              <div style={{fontSize:10,fontWeight:700,color:setting.color,lineHeight:1,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{setting.label}</div>
              {cfg?.serviceName&&<div style={{fontSize:9,color:"rgba(255,255,255,0.3)",lineHeight:1.3,marginTop:1,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{cfg.serviceName}</div>}
            </div>
          </div>
        </div>
      )}

      {/* Nav items */}
      <nav style={{flex:1,overflowY:"auto",padding:"6px 6px",scrollbarWidth:"none"}}>
        {groupOrder.map((g,gi)=>{
          const gItems = groups[g];
          if(!gItems||gItems.length===0) return null;
          const label = GROUP_LABELS[g];
          return(
            <div key={g} style={{marginBottom:4}}>
              {/* Group label */}
              {!collapsed&&label&&(
                <div style={{
                  fontSize:9,fontWeight:700,color:"rgba(255,255,255,0.18)",
                  letterSpacing:"1.5px",textTransform:"uppercase",
                  padding:"10px 10px 4px",
                }}>{label}</div>
              )}
              {/* Divider when collapsed */}
              {collapsed&&gi>0&&label&&(
                <div style={{height:"1px",background:"rgba(255,255,255,0.06)",margin:"6px 8px 4px"}}/>
              )}
              {gItems.map(item=>{
                const isActive = active===item.id;
                return(
                  <button key={item.id}
                    onClick={()=>onNav(item.id)}
                    title={collapsed?item.label:""}
                    style={{
                      display:"flex",alignItems:"center",
                      gap:9,width:"100%",
                      padding:collapsed?"10px 0":"8px 12px",
                      justifyContent:collapsed?"center":"flex-start",
                      borderRadius:8,border:"none",
                      background:isActive?"rgba(43,191,178,0.13)":"transparent",
                      color:isActive?"#FFFFFF":"rgba(255,255,255,0.45)",
                      cursor:"pointer",marginBottom:2,
                      fontSize:12,fontWeight:isActive?600:400,
                      fontFamily:"inherit",
                      transition:"all 0.15s ease",
                      position:"relative",
                      boxShadow:isActive?"inset 0 0 0 1px rgba(43,191,178,0.15)":"none",
                    }}
                    onMouseEnter={e=>{
                      if(!isActive){
                        e.currentTarget.style.background="rgba(255,255,255,0.07)";
                        e.currentTarget.style.color="rgba(255,255,255,0.85)";
                      }
                    }}
                    onMouseLeave={e=>{
                      if(!isActive){
                        e.currentTarget.style.background="transparent";
                        e.currentTarget.style.color="rgba(255,255,255,0.45)";
                      }
                    }}>
                    {/* Active indicator bar */}
                    {isActive&&<div style={{
                      position:"absolute",left:0,top:"15%",bottom:"15%",
                      width:3,borderRadius:"0 3px 3px 0",
                      background:"linear-gradient(180deg,#48D8CA,#16B5B8)",
                      boxShadow:"0 0 8px rgba(43,191,178,0.6)",
                    }}/>}
                    <Icon
                      name={item.icon}
                      size={14}
                      color={isActive?"#16B5B8":"rgba(255,255,255,0.38)"}
                      strokeWidth={isActive?2:1.5}
                    />
                    {!collapsed&&<span style={{lineHeight:1.2}}>{item.label}</span>}
                    {!collapsed&&_sidebarBadges&&_sidebarBadges[item.id]>0&&(
                      <span style={{background:"#FF5A6E",color:"#fff",borderRadius:"50%",minWidth:16,height:16,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,marginLeft:"auto",flexShrink:0,padding:"0 3px"}}>{_sidebarBadges[item.id]}</span>
                    )}
                  </button>
                );
              })}
            </div>
          );
        })}
      </nav>

      {/* User footer */}
      <div style={{
        padding:collapsed?"10px 6px":"12px 10px",
        borderTop:"1px solid rgba(255,255,255,0.06)",
        display:"flex",alignItems:"center",gap:8,
        flexShrink:0,
      }}>
        <div style={{
          width:30,height:30,borderRadius:"50%",flexShrink:0,
          background:`linear-gradient(135deg,${B.teal},${B.navy})`,
          display:"flex",alignItems:"center",justifyContent:"center",
          fontSize:11,fontWeight:700,color:"#fff",
          border:"1.5px solid rgba(255,255,255,0.15)",
        }}>{user?.initials||"?"}</div>
        {!collapsed&&(
          <>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:11,fontWeight:600,color:"rgba(255,255,255,0.85)",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{user?.name||"User"}</div>
              <div style={{fontSize:9,color:"rgba(255,255,255,0.3)",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{user?.sub||""}</div>
            </div>
            <button
              title="Sign out"
              style={{background:"none",border:"none",cursor:"pointer",padding:"4px",borderRadius:5,display:"flex",alignItems:"center",opacity:0.35,transition:"opacity 0.15s",flexShrink:0}}
              onMouseEnter={e=>e.currentTarget.style.opacity="0.7"}
              onMouseLeave={e=>e.currentTarget.style.opacity="0.35"}>
              <Icon name="logout" size={13} color="white" strokeWidth={1.5}/>
            </button>
          </>
        )}
      </div>
    </div>
  );
}

// ── TOP BAR — Clean, premium header ───────────────────────────
function TopBar({onToggle,page,role,onNavigate}){
  const [showNotifPanel,setShowNotifPanel] = useState(false);
  const [notifications,setNotifications]   = useState(NOTIFICATIONS_SEED);
  const markRead    = async id => {
    setNotifications(ns=>ns.map(n=>n.id===id?{...n,read:true}:n));
    if(hasSupabase()) await supabase.from("notifications").update({is_read:true}).eq("id",id);
  };
  const markAllRead = async () => {
    setNotifications(ns=>ns.map(n=>({...n,read:true})));
    if(hasSupabase()&&APP_CONFIG?.companyId&&APP_CONFIG.companyId!=="demo-company-001"){
      await supabase.from("notifications").update({is_read:true})
        .eq("company_id",APP_CONFIG.companyId).eq("is_read",false);
    }
  };

  // ── Supabase: fetch notifications + realtime subscription ──
  useEffect(()=>{
    if(!hasSupabase()) return;
    const cid = APP_CONFIG?.companyId;
    if(!cid||cid==="demo-company-001") return;
    // Initial load
    supabase.from("notifications").select("*")
      .eq("company_id",cid)
      .order("created_at",{ascending:false})
      .limit(50)
      .then(({data,error})=>{
        if(!error&&data&&data.length>0) setNotifications(data);
      });
    // Realtime subscription
    const channel = supabase.channel("notifications_"+cid)
      .on("postgres_changes",{
        event:"INSERT", schema:"public", table:"notifications",
        filter:"company_id=eq."+cid,
      },(payload)=>{
        setNotifications(prev=>[payload.new,...prev]);
      }).subscribe();
    return ()=>{ supabase.removeChannel(channel); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[APP_CONFIG?.companyId]);

  const PAGE_LABELS = {
    dashboard:"Dashboard",tasks:"Task Manager",audits:"KLoE Audit Builder",
    evidence:"Evidence Vault",staff:"Staff Records",serviceusers:"Service Users",
    safeguarding:"Safeguarding",medication:"Medication Audits",
    mock:"Mock Inspection",reports:"Reports",settings:"Settings",
    companies:"All Companies",onboarding:"Company Management",
    billing:"Billing & Subscriptions",users:"User Management",
    systemlogs:"System Logs",inspection:"CQC Inspection Mode",
    digest:"Weekly Digest",accountability:"Accountability Centre",
    briefing:"Daily Briefing",workforce:"Workforce Intelligence",
    delegation:"Delegation Centre",staffroles:"Staff Roles & Permissions",
    calendar:"Compliance Calendar",
    qualitystatements:"Quality Statements Audit",pir:"PIR Support Tool",
    profdev:"Professional Development",multisite:"My Services",
    compliance:"Compliance Overview",setup:"Service Setup",
  };

  const PAGE_ICONS = {
    dashboard:"dashboard",tasks:"tasks",audits:"audits",evidence:"evidence",
    staff:"staff",serviceusers:"serviceusers",safeguarding:"safeguarding",
    medication:"medication",mock:"mock",reports:"reports",
    inspection:"shield",digest:"trending",accountability:"shield",
    briefing:"clock",workforce:"staff",delegation:"bell",
    staffroles:"users",calendar:"calendar",pir:"audits",profdev:"trending",
    billing:"billing",onboarding:"onboarding",companies:"companies",
  };

  const user    = DEMO_USERS[role];
  const unread  = notifications.filter(n=>!n.read).length;
  const label   = PAGE_LABELS[page]||page;
  const icon    = PAGE_ICONS[page]||"dashboard";

  return(
    <div style={{
      height:58,background:"#ffffff",
      borderBottom:"1.5px solid #EDF0F5",
      display:"flex",alignItems:"center",
      padding:"0 22px 0 16px",gap:12,
      position:"sticky",top:0,zIndex:10,flexShrink:0,
      boxShadow:"0 1px 0 #E5E7EB, 0 2px 8px rgba(28,50,82,0.06)",
    }}>
      {/* Hamburger */}
      <button onClick={onToggle} style={{
        background:"none",border:"none",cursor:"pointer",
        padding:"6px",borderRadius:7,
        display:"flex",alignItems:"center",
        transition:"background 0.12s",flexShrink:0,
      }}
        onMouseEnter={e=>e.currentTarget.style.background="#F8FAFC"}
        onMouseLeave={e=>e.currentTarget.style.background="none"}>
        <Icon name="menu" size={16} color={B.textMid} strokeWidth={1.7}/>
      </button>

      {/* Page title */}
      <div style={{display:"flex",alignItems:"center",gap:8,flex:1}}>
        <div style={{
          width:28,height:28,borderRadius:7,
          background:"#F0FBFA",
          display:"flex",alignItems:"center",justifyContent:"center",
          flexShrink:0,
        }}>
          <Icon name={icon} size={13} color={B.teal} strokeWidth={2}/>
        </div>
        <div>
          <div style={{fontSize:14,fontWeight:700,color:B.navy,lineHeight:1.2,letterSpacing:"-0.2px"}}>{label}</div>
          <div style={{fontSize:10,color:B.textLight,lineHeight:1.2}}>{user?.service||""}{user?.sub?` · ${user.sub}`:""}</div>
        </div>
      </div>

      {/* Demo mode pill */}
      {APP_CONFIG?.isDemo&&(
        <div style={{display:"flex",alignItems:"center",gap:5,padding:"3px 10px",background:"rgba(43,191,178,0.08)",border:"1px solid rgba(43,191,178,0.2)",borderRadius:20}}>
          <div style={{width:5,height:5,borderRadius:"50%",background:"#16B5B8"}}/>
          <span style={{fontSize:10,fontWeight:700,color:"#16B5B8"}}>Demo</span>
        </div>
      )}

      {/* Notification bell */}
      <div style={{position:"relative",flexShrink:0}}>
        <button onClick={()=>setShowNotifPanel(p=>!p)} style={{
          background:"none",border:"none",cursor:"pointer",
          padding:"6px",borderRadius:7,display:"flex",alignItems:"center",
          transition:"background 0.12s",
        }}
          onMouseEnter={e=>e.currentTarget.style.background="#F8FAFC"}
          onMouseLeave={e=>e.currentTarget.style.background="none"}>
          <Icon name="bell" size={17} color={unread>0?B.teal:B.textMid} strokeWidth={1.7}/>
          {unread>0&&(
            <div style={{
              position:"absolute",top:4,right:4,
              width:14,height:14,borderRadius:"50%",
              background:B.danger,border:"2px solid #fff",
              fontSize:8,fontWeight:700,color:"#fff",
              display:"flex",alignItems:"center",justifyContent:"center",
            }}>{unread>9?"9+":unread}</div>
          )}
        </button>
        {showNotifPanel&&(
          <NotificationPanel
            notifications={notifications}
            onClose={()=>setShowNotifPanel(false)}
            onMarkRead={markRead}
            onMarkAllRead={markAllRead}
            onNavigate={p=>{if(onNavigate)onNavigate(p);}}
          />
        )}
      </div>

      {/* Avatar */}
      <div style={{
        width:32,height:32,borderRadius:"50%",flexShrink:0,
        background:`linear-gradient(135deg,${B.teal},${B.navy})`,
        display:"flex",alignItems:"center",justifyContent:"center",
        fontSize:11,fontWeight:700,color:"#fff",cursor:"pointer",
        border:"2px solid #E5E7EB",
        transition:"border-color 0.15s",
      }}
        onMouseEnter={e=>e.currentTarget.style.borderColor=B.teal}
        onMouseLeave={e=>e.currentTarget.style.borderColor="#E5E7EB"}>
        {user?.initials||"?"}
      </div>
    </div>
  );
}

