function ManagerDashboard(){
  const alerts = generateLiveAlerts();
  const health  = calcGovernanceHealth(alerts);
  const moduleCounts = getModuleAlertCounts(alerts);
  const navTo = (page) => window.dispatchEvent(new CustomEvent('evidentra-nav',{detail:{page}}));
  const critical = alerts.filter(a=>a.priority==="Critical").length;
  const high     = alerts.filter(a=>a.priority==="High").length;

  return(
    <div style={{padding:"24px 28px",maxWidth:1100,fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif",height:"100%",overflowY:"auto"}}>

      {/* Welcome row */}
      <div style={{marginBottom:24}}>
        <div style={{fontSize:18,fontWeight:800,color:"#062B7A",marginBottom:2}}>Good morning 👋</div>
        <div style={{fontSize:13,color:"#6B7280"}}>{new Date().toLocaleDateString("en-GB",{weekday:"long",day:"numeric",month:"long",year:"numeric"})}</div>
      </div>

      {/* Top row: health score + 3 KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"260px 1fr",gap:16,marginBottom:20}}>
        <GovernanceHealthScore alerts={alerts} onNavigate={navTo}/>
        <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12,alignContent:"start"}}>
          {[
            {label:"Open Alerts",    value:alerts.length, sub:critical>0?critical+" critical":"All under control", color:critical>0?"#FF5A6E":"#16B5B8", icon:"shield"},
            {label:"CQC Readiness",  value:"81%",         sub:"Based on evidence vault",                          color:"#7A57D1",                        icon:"audits"},
            {label:"Next Review",    value:"3 days",      sub:"Arthur Mensah — care plan",                        color:"#FF9A2F",                        icon:"calendar"},
          ].map((k,i)=>(
            <div key={i} style={{background:"#fff",borderRadius:10,padding:"16px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",borderLeft:"3px solid "+k.color}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
                <span style={{fontSize:11,fontWeight:600,color:"#6B7280"}}>{k.label}</span>
                <Icon name={k.icon} size={13} color={k.color} strokeWidth={1.5}/>
              </div>
              <div style={{fontSize:26,fontWeight:800,color:"#062B7A",lineHeight:1,marginBottom:4}}>{k.value}</div>
              <div style={{fontSize:11,color:k.color,fontWeight:500}}>{k.sub}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Main row: governance panel + right sidebar */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 260px",gap:16}}>
        <DashboardGovernancePanel alerts={alerts} onNavigate={navTo}/>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {/* Module alerts */}
          <div style={{background:"#fff",borderRadius:10,padding:"14px 16px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)"}}>
            <div style={{fontSize:12,fontWeight:700,color:"#062B7A",marginBottom:10}}>Alerts by Area</div>
            {[
              {module:"staff",       label:"Staff",         icon:"staff"},
              {module:"serviceusers",label:"Service Users", icon:"serviceusers"},
              {module:"safeguarding",label:"Safeguarding",  icon:"safeguarding"},
              {module:"medication",  label:"Medication",    icon:"medication"},
              {module:"audits",      label:"Audits",        icon:"audits"},
            ].map((m,i)=>{
              const cnt = moduleCounts[m.module]||0;
              return(
                <div key={m.module} onClick={()=>navTo(m.module)}
                  style={{display:"flex",alignItems:"center",gap:8,padding:"7px 6px",borderRadius:7,cursor:"pointer",marginBottom:2,transition:"background 0.12s"}}
                  onMouseEnter={e=>e.currentTarget.style.background="#F8FAFC"}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <Icon name={m.icon} size={12} color={cnt>0?"#FF5A6E":"#D1D5DB"} strokeWidth={cnt>0?2:1.5}/>
                  <span style={{flex:1,fontSize:12,color:cnt>0?"#062B7A":"#6B7280",fontWeight:cnt>0?600:400}}>{m.label}</span>
                  {cnt>0?(
                    <span style={{background:"#FF5A6E",color:"#fff",borderRadius:"50%",width:18,height:18,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700}}>{cnt}</span>
                  ):(
                    <span style={{color:"#16B5B8",fontSize:11}}>✓</span>
                  )}
                </div>
              );
            })}
          </div>
          {/* CQC domains */}
          <div style={{background:"linear-gradient(135deg,#062B7A,#2A4A7A)",borderRadius:10,padding:"14px 16px"}}>
            <div style={{fontSize:12,fontWeight:700,color:"#fff",marginBottom:10}}>CQC Readiness</div>
            {[["Safe",81],["Effective",88],["Caring",92],["Responsive",79],["Well-led",83]].map(([d,s])=>{
              const c = s>=85?"#6EE7B7":s>=70?"#93C5FD":"#FCA5A5";
              return(
                <div key={d} style={{marginBottom:7}}>
                  <div style={{display:"flex",justifyContent:"space-between",fontSize:10,marginBottom:3}}>
                    <span style={{color:"rgba(255,255,255,0.6)"}}>{d}</span>
                    <span style={{color:c,fontWeight:700}}>{s}%</span>
                  </div>
                  <div style={{height:3,background:"rgba(255,255,255,0.1)",borderRadius:2}}>
                    <div style={{height:"100%",width:s+"%",background:c,borderRadius:2}}/>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}


