function TaskDrawer({task,onClose,onSave,onDelete}){
  const [t,setT]=useState({...task});
  const changed=JSON.stringify(t)!==JSON.stringify(task);
  if(!task) return null;
  const inp=(f,v)=>setT(p=>({...p,[f]:v}));
  const today=new Date().toISOString().split("T")[0];
  const fs={width:"100%",padding:"9px 11px",borderRadius:7,border:"1.5px solid #D1D5DB",fontSize:13,color:"#062B7A",outline:"none",fontFamily:"inherit",background:"#fff",boxSizing:"border-box"};
  const lbl={fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.8px"};
  return(
    <div style={{position:"fixed",inset:0,zIndex:100,display:"flex"}}>
      <div onClick={onClose} style={{flex:1,background:"rgba(16,30,48,0.45)"}}/>
      <div style={{width:490,background:"#fff",height:"100vh",overflowY:"auto",boxShadow:"-8px 0 40px rgba(0,0,0,0.15)",display:"flex",flexDirection:"column"}}>
        <div style={{padding:"18px 24px",borderBottom:"1px solid #E5E7EB",display:"flex",justifyContent:"space-between",alignItems:"center",position:"sticky",top:0,background:"#fff",zIndex:1}}>
          <span style={{fontSize:15,fontWeight:700,color:"#062B7A"}}>Task Details</span>
          <div style={{display:"flex",gap:8}}>
            {changed&&<button onClick={()=>onSave(t)} style={{padding:"7px 16px",borderRadius:7,border:"none",background:"#16B5B8",color:"#fff",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Save</button>}
            <button onClick={onClose} style={{padding:"7px 14px",borderRadius:7,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>Close</button>
          </div>
        </div>
        <div style={{padding:24,flex:1}}>
          {/* Status selector */}
          <div style={{display:"flex",gap:7,marginBottom:20,flexWrap:"wrap"}}>
            {Object.keys(S_CFG).map(s=><button key={s} onClick={()=>inp("status",s)} style={{padding:"5px 12px",borderRadius:20,fontSize:12,fontWeight:600,border:`1.5px solid ${t.status===s?S_CFG[s].fg:"#D1D5DB"}`,background:t.status===s?S_CFG[s].bg:"#fff",color:t.status===s?S_CFG[s].fg:"#6B7280",cursor:"pointer",fontFamily:"inherit"}}>{s}</button>)}
          </div>
          {/* Title */}
          <div style={{marginBottom:14}}><label style={lbl}>Task Title</label><input value={t.title} onChange={e=>inp("title",e.target.value)} style={fs} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/></div>
          {/* Description */}
          <div style={{marginBottom:14}}><label style={lbl}>Description</label><textarea value={t.desc} onChange={e=>inp("desc",e.target.value)} rows={3} style={{...fs,resize:"vertical"}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/></div>
          {/* Grid */}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:14}}>
            {[{l:"Due Date",f:"due",t:"date"},{l:"Priority",f:"priority",t:"sel",o:["High","Medium","Low"]},{l:"KLoE Domain",f:"kloe",t:"sel",o:KLOE_DOMAINS},{l:"Category",f:"category",t:"sel",o:TASK_CATEGORIES},{l:"Assigned To",f:"assignee",t:"sel",o:STAFF_MEMBERS},{l:"Regulation",f:"regulation",t:"text"}].map(fl=>(
              <div key={fl.f}><label style={lbl}>{fl.l}</label>
                {fl.t==="sel"
                  ?<select value={t[fl.f]} onChange={e=>inp(fl.f,e.target.value)} style={{...fs,cursor:"pointer"}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}>{fl.o.map(o=><option key={o}>{o}</option>)}</select>
                  :<input type={fl.t} value={t[fl.f]} onChange={e=>inp(fl.f,e.target.value)} style={fs} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>}
              </div>
            ))}
          </div>
          {/* Notes */}
          <div style={{marginBottom:18}}><label style={lbl}>Notes / Progress Updates</label><textarea value={t.notes} onChange={e=>inp("notes",e.target.value)} rows={4} placeholder="Add notes, updates or actions taken…" style={{...fs,resize:"vertical"}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/></div>
          {/* Audit trail */}
          <div style={{padding:14,borderRadius:8,background:"#F8FAFC",border:"1px solid #E5E7EB",marginBottom:16}}>
            <div style={{fontSize:11,fontWeight:700,color:"#6B7280",marginBottom:8,textTransform:"uppercase",letterSpacing:"0.8px"}}>Audit Trail</div>
            <div style={{fontSize:12,color:"#374151",marginBottom:4}}><strong>Created:</strong> {task.created}</div>
            {task.completedAt&&<div style={{fontSize:12,color:"#16B5B8"}}><strong>Completed:</strong> {task.completedAt}</div>}
            <div style={{fontSize:12,color:"#374151",marginTop:4}}><strong>Regulation:</strong> {t.regulation||"—"}</div>
          </div>
          {/* Mark complete */}
          {t.status!=="Completed"&&<button onClick={()=>{const c={...t,status:"Completed",completedAt:today};onSave(c);onClose();}} style={{width:"100%",padding:"11px",borderRadius:8,border:"none",background:"linear-gradient(135deg,#16B5B8,#1F7A48)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",marginBottom:10,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}><Icon name="check" size={14} color="white" strokeWidth={2.5}/>Mark as Completed</button>}
          {/* Delete */}
          <button onClick={()=>{onDelete(task.id);onClose();}} style={{width:"100%",padding:"10px",borderRadius:8,border:"1px solid #FF5A6E33",background:"#FDF0F0",color:"#FF5A6E",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Delete Task</button>
        </div>
      </div>
    </div>
  );
}

