function TaskManagerPage(){
  const [tasks,setTasks]=useState(INITIAL_TASKS);

  // ── Supabase: load tasks for this company ──────────────────
  useEffect(()=>{
    if(!hasSupabase()) return;
    const cid = APP_CONFIG?.companyId;
    if(!cid || cid==="demo-company-001") return;
    supabase.from("tasks").select("*")
      .eq("company_id", cid)
      .order("created_at",{ascending:false})
      .then(({data,error})=>{ if(!error&&data) setTasks(data); });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[APP_CONFIG?.companyId]);
  const [filter,setFilter]=useState("All");
  const [search,setSearch]=useState("");
  const [priF,setPriF]=useState("All");
  const [kloeF,setKloeF]=useState("All");
  const [sortBy,setSort]=useState("due");
  const [selected,setSelected]=useState(null);
  const [showNew,setShowNew]=useState(false);
  const [view,setView]=useState("list");
  const today=new Date().toISOString().split("T")[0];
  const tabs=["All","To Do","In Progress","Overdue","Completed"];
  const counts=tabs.reduce((a,s)=>{a[s]=s==="All"?tasks.length:tasks.filter(t=>t.status===s).length;return a;},{});
  const isOD=t=>t.due<today&&t.status!=="Completed";
  const filtered=tasks
    .filter(t=>filter==="All"||t.status===filter)
    .filter(t=>priF==="All"||t.priority===priF)
    .filter(t=>kloeF==="All"||t.kloe===kloeF)
    .filter(t=>{const q=search.toLowerCase();return !q||t.title.toLowerCase().includes(q)||t.assignee.toLowerCase().includes(q)||t.category.toLowerCase().includes(q);})
    .sort((a,b)=>{
      if(sortBy==="due") return a.due.localeCompare(b.due);
      if(sortBy==="priority"){const o={High:0,Medium:1,Low:2};return o[a.priority]-o[b.priority];}
      if(sortBy==="status") return a.status.localeCompare(b.status);
      return a.title.localeCompare(b.title);
    });
  const saveTask=async u=>{setTasks(ts=>ts.map(t=>t.id===u.id?u:t));if(hasSupabase()&&APP_CONFIG?.companyId!=="demo-company-001"){const{id,...rest}=u;await supabase.from("tasks").update(rest).eq("id",u.id);}};
  const deleteTask=async id=>{setTasks(ts=>ts.filter(t=>t.id!==id));if(hasSupabase()&&APP_CONFIG?.companyId!=="demo-company-001"){await supabase.from("tasks").delete().eq("id",id);}};
  const addTask=async t=>{setTasks(ts=>[t,...ts]);if(hasSupabase()&&APP_CONFIG?.companyId!=="demo-company-001"){await supabase.from("tasks").insert({...t,company_id:APP_CONFIG.companyId});}};
  const quickDone=(e,id)=>{e.stopPropagation();setTasks(ts=>ts.map(t=>t.id===id?{...t,status:"Completed",completedAt:today}:t));};

  return(<DemoFeatureGate feature="tasks">
    <div style={{padding:24,fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif",maxWidth:1280}}>
      {/* Header */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:20}}>
        <div>
          <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:3}}>Task Manager</div>
          <div style={{fontSize:13,color:"#6B7280"}}>{counts["To Do"]+counts["In Progress"]} active · {counts["Overdue"]} overdue · {counts["Completed"]} completed</div>
        </div>
        <button onClick={()=>setShowNew(true)} style={{display:"flex",alignItems:"center",gap:8,padding:"10px 20px",borderRadius:9,border:"none",background:"linear-gradient(135deg,#16B5B8,#0E8F92)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",boxShadow:"0 3px 12px rgba(43,191,178,0.4)"}}>
          <Icon name="onboarding" size={14} color="white" strokeWidth={2.5}/> New Task
        </button>
      </div>

      {/* KPI cards */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:20}}>
        {[
          {label:"Total Tasks",  value:counts["All"],         color:"#062B7A",sub:"All tasks"},
          {label:"In Progress",  value:counts["In Progress"], color:"#7A57D1",sub:"Being worked on"},
          {label:"Overdue",      value:counts["Overdue"],     color:"#FF5A6E",sub:"Need immediate action"},
          {label:"Completed",    value:counts["Completed"],   color:"#16B5B8",sub:"This period"},
        ].map((k,i)=>(
          <div key={i} onClick={()=>setFilter(["All","In Progress","Overdue","Completed"][i])} style={{background:"#fff",borderRadius:9,padding:"14px 16px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",borderLeft:`3px solid ${k.color}`,cursor:"pointer",transition:"box-shadow 0.15s"}} onMouseEnter={e=>e.currentTarget.style.boxShadow="0 4px 14px rgba(0,0,0,0.1)"} onMouseLeave={e=>e.currentTarget.style.boxShadow="0 1px 4px rgba(0,0,0,0.05)"}>
            <div style={{fontSize:26,fontWeight:800,color:k.color,lineHeight:1}}>{k.value}</div>
            <div style={{fontSize:12,fontWeight:600,color:"#062B7A",marginTop:5}}>{k.label}</div>
            <div style={{fontSize:11,color:"#6B7280",marginTop:2}}>{k.sub}</div>
          </div>
        ))}
      </div>

      {/* Filter bar */}
      <div style={{background:"#fff",borderRadius:10,padding:"14px 18px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",marginBottom:14,display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
          {tabs.map(s=>{const c=S_CFG[s]||{bg:"#062B7A15",fg:"#062B7A"};return(
            <button key={s} onClick={()=>setFilter(s)} style={{padding:"5px 13px",borderRadius:20,fontSize:12,fontWeight:600,border:`1px solid ${filter===s?c.fg:"#D1D5DB"}`,background:filter===s?c.bg:"#fff",color:filter===s?c.fg:"#374151",cursor:"pointer",fontFamily:"inherit"}}>
              {s} {counts[s]>0&&<span style={{opacity:0.6}}>({counts[s]})</span>}
            </button>
          );})}
        </div>
        <div style={{width:1,height:22,background:"#E5E7EB"}}/>
        <div style={{position:"relative",flex:1,minWidth:160}}>
          <div style={{position:"absolute",left:9,top:"50%",transform:"translateY(-50%)"}}>
            <Icon name="mock" size={12} color="#6B7280" strokeWidth={1.8}/>
          </div>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search tasks…"
            style={{width:"100%",padding:"7px 10px 7px 28px",borderRadius:7,border:"1px solid #D1D5DB",fontSize:12,color:"#062B7A",outline:"none",fontFamily:"inherit",boxSizing:"border-box"}}
            onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
        </div>
        {[["Priority","All",["All","High","Medium","Low"],priF,setPriF],["KLoE","All",["All",...KLOE_DOMAINS],kloeF,setKloeF],["Sort","due",["due","priority","status","title"],sortBy,setSort]].map(([label,def,opts,val,set])=>(
          <select key={label} value={val} onChange={e=>set(e.target.value)}
            style={{padding:"7px 10px",borderRadius:7,border:"1px solid #D1D5DB",fontSize:12,color:"#374151",outline:"none",fontFamily:"inherit",cursor:"pointer",background:"#fff"}}>
            {opts.map(o=><option key={o} value={o}>{label==="Sort"?`Sort: ${o.charAt(0).toUpperCase()+o.slice(1)}`:o}</option>)}
          </select>
        ))}
        <div style={{display:"flex",border:"1px solid #D1D5DB",borderRadius:7,overflow:"hidden"}}>
          {[["list","List"],["board","Board"]].map(([v,l])=>(
            <button key={v} onClick={()=>setView(v)} style={{padding:"6px 14px",border:"none",fontSize:12,fontWeight:600,background:view===v?"#062B7A":"#fff",color:view===v?"#fff":"#374151",cursor:"pointer",fontFamily:"inherit"}}>{l}</button>
          ))}
        </div>
      </div>

      <div style={{fontSize:12,color:"#6B7280",marginBottom:10,paddingLeft:2}}>Showing {filtered.length} of {tasks.length} tasks</div>

      {/* LIST VIEW */}
      {view==="list"&&(
        <div style={{background:"#fff",borderRadius:10,boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",overflow:"hidden"}}>
          <div style={{display:"grid",gridTemplateColumns:"28px 1fr 110px 90px 90px 140px 100px 28px",padding:"10px 18px",borderBottom:"1px solid #E5E7EB",background:"#F8FAFC"}}>
            {["","Task","Due","Priority","KLoE","Assigned","Status",""].map((h,i)=>(
              <div key={i} style={{fontSize:11,fontWeight:700,color:"#6B7280",textTransform:"uppercase",letterSpacing:"0.5px"}}>{h}</div>
            ))}
          </div>
          {filtered.length===0&&<div style={{padding:40,textAlign:"center",color:"#6B7280",fontSize:13}}>No tasks match your filters.</div>}
          {filtered.map((t,i)=>{
            const overdue=isOD(t);
            return(
              <div key={t.id} onClick={()=>setSelected(t)}
                style={{display:"grid",gridTemplateColumns:"28px 1fr 110px 90px 90px 140px 100px 28px",padding:"13px 18px",borderBottom:i<filtered.length-1?"1px solid #E5E7EB":"none",background:overdue?"#FEFAFA":"#fff",cursor:"pointer",alignItems:"center",transition:"background 0.12s"}}
                onMouseEnter={e=>e.currentTarget.style.background="#F8FAFC"}
                onMouseLeave={e=>e.currentTarget.style.background=overdue?"#FEFAFA":"#fff"}>
                <div onClick={e=>quickDone(e,t.id)} style={{width:16,height:16,borderRadius:4,border:`1.5px solid ${t.status==="Completed"?"#16B5B8":"#D1D5DB"}`,background:t.status==="Completed"?"#16B5B8":"transparent",display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}>
                  {t.status==="Completed"&&<Icon name="check" size={9} color="white" strokeWidth={3}/>}
                </div>
                <div style={{minWidth:0,paddingRight:12}}>
                  <div style={{fontSize:13,fontWeight:500,color:t.status==="Completed"?"#6B7280":"#062B7A",textDecoration:t.status==="Completed"?"line-through":"none",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",marginBottom:2}}>{t.title}</div>
                  <div style={{display:"flex",gap:8,alignItems:"center"}}>
                    <span style={{fontSize:11,color:"#6B7280"}}>{t.category}</span>
                    {t.regulation&&<span style={{fontSize:10,color:"#6B7280",background:"#F8FAFC",padding:"1px 6px",borderRadius:4}}>{t.regulation}</span>}
                  </div>
                </div>
                <div style={{fontSize:12,fontWeight:500,color:overdue?"#FF5A6E":"#374151",display:"flex",alignItems:"center",gap:4}}>
                  {overdue&&<Icon name="alert" size={11} color="#FF5A6E" strokeWidth={2}/>}{t.due}
                </div>
                <div><PriPill priority={t.priority}/></div>
                <div><Tag text={t.kloe}/></div>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <div style={{width:24,height:24,borderRadius:"50%",background:"linear-gradient(135deg,rgba(43,191,178,0.4),rgba(28,50,82,0.5))",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,color:"#fff",flexShrink:0}}>{t.assignee.split(" ").map(n=>n[0]).join("")}</div>
                  <span style={{fontSize:12,color:"#374151",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",maxWidth:90}}>{t.assignee.split(" ")[0]}</span>
                </div>
                <div><StatusPill status={t.status}/></div>
                <div style={{display:"flex",justifyContent:"center"}}><Icon name="chevronDown" size={13} color="#D1D5DB" strokeWidth={2}/></div>
              </div>
            );
          })}
        </div>
      )}

      {/* BOARD VIEW */}
      {view==="board"&&(
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:14}}>
          {["To Do","In Progress","Overdue","Completed"].map(col=>{
            const cfg=S_CFG[col];
            const colTasks=filtered.filter(t=>t.status===col);
            return(
              <div key={col} style={{background:"#fff",borderRadius:10,boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",overflow:"hidden"}}>
                <div style={{padding:"12px 14px",borderBottom:"1px solid #E5E7EB",background:cfg.bg,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <span style={{width:7,height:7,borderRadius:"50%",background:cfg.dot}}/>
                    <span style={{fontSize:12,fontWeight:700,color:cfg.fg}}>{col}</span>
                  </div>
                  <span style={{fontSize:11,fontWeight:700,color:cfg.fg,background:"#fff",padding:"1px 8px",borderRadius:20,border:`1px solid ${cfg.dot}44`}}>{colTasks.length}</span>
                </div>
                <div style={{padding:10,display:"flex",flexDirection:"column",gap:8,minHeight:80,maxHeight:"calc(100vh - 340px)",overflowY:"auto"}}>
                  {colTasks.length===0&&<div style={{fontSize:12,color:"#6B7280",textAlign:"center",padding:"18px 10px"}}>No tasks</div>}
                  {colTasks.map(t=>(
                    <div key={t.id} onClick={()=>setSelected(t)} style={{background:"#fff",borderRadius:8,padding:"11px",border:"1px solid #E5E7EB",cursor:"pointer",boxShadow:"0 1px 3px rgba(0,0,0,0.04)",borderLeft:`3px solid ${P_CFG[t.priority]?.fg||"#E5E7EB"}`,transition:"box-shadow 0.15s"}}
                      onMouseEnter={e=>e.currentTarget.style.boxShadow="0 4px 12px rgba(0,0,0,0.1)"}
                      onMouseLeave={e=>e.currentTarget.style.boxShadow="0 1px 3px rgba(0,0,0,0.04)"}>
                      <div style={{fontSize:12,fontWeight:600,color:"#062B7A",lineHeight:1.4,marginBottom:8}}>{t.title}</div>
                      <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:8}}>
                        <Tag text={t.kloe}/><PriPill priority={t.priority}/>
                      </div>
                      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                        <div style={{display:"flex",alignItems:"center",gap:5}}>
                          <div style={{width:20,height:20,borderRadius:"50%",background:"linear-gradient(135deg,rgba(43,191,178,0.4),rgba(28,50,82,0.5))",display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:"#fff"}}>{t.assignee.split(" ").map(n=>n[0]).join("")}</div>
                          <span style={{fontSize:10,color:"#6B7280"}}>{t.assignee.split(" ")[0]}</span>
                        </div>
                        <span style={{fontSize:10,color:isOD(t)?"#FF5A6E":"#6B7280",display:"flex",alignItems:"center",gap:3}}>
                          <Icon name="calendar" size={9} color={isOD(t)?"#FF5A6E":"#6B7280"} strokeWidth={1.5}/>{t.due}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {selected&&<TaskDrawer task={selected} onClose={()=>setSelected(null)} onSave={t=>{saveTask(t);setSelected(t);}} onDelete={deleteTask}/>}
      {showNew&&<NewTaskModal onClose={()=>setShowNew(false)} onAdd={addTask}/>}
    </div>
  </DemoFeatureGate>);
}

