const TODAY = new Date().toISOString().split("T")[0];

function addMonths(dateStr, n){
  const d = new Date(dateStr);
  d.setMonth(d.getMonth()+n);
  return d.toISOString().split("T")[0];
}
function daysDiff(a, b="2026-05-27"){
  return Math.ceil((new Date(a)-new Date(b))/(1000*60*60*24));
}
function expiryLabel(dateStr){
  const d = daysDiff(dateStr);
  if(d < 0)  return { text:"Expired",          color:"#FF5A6E", bg:"#FDF0F0" };
  if(d <= 30) return { text:`Expires in ${d}d`, color:"#FF9A2F", bg:"#FDF8EE" };
  return       { text:`Valid · ${dateStr}`,     color:"#16B5B8", bg:"#F0FDF4" };
}

