// ════════════════════════════════════════════════════════════════
// SERVICE USERS — COMPLIANCE-FOCUSED MODULE
// Every section maps to a CQC regulation and KLoE domain
// Purpose: evidence that the service is Safe, Effective, Caring,
// Responsive and Well-led in relation to each service user
// ════════════════════════════════════════════════════════════════

const SU_COMPLIANCE_MAP = {
  carePlan:         { kloe:"Effective",  regs:["Reg 9","Reg 17"],   label:"Person-Centred Care Plan" },
  riskAssessment:   { kloe:"Safe",       regs:["Reg 12","Reg 17"],  label:"Risk Assessments" },
  medication:       { kloe:"Safe",       regs:["Reg 12","Reg 13"],  label:"Medication Management" },
  mentalCapacity:   { kloe:"Effective",  regs:["Reg 9","Reg 11"],   label:"Mental Capacity & Consent" },
  safeguarding:     { kloe:"Safe",       regs:["Reg 13"],           label:"Safeguarding" },
  healthMonitoring: { kloe:"Effective",  regs:["Reg 9","Reg 12"],   label:"Health Monitoring" },
  communicationLog: { kloe:"Responsive", regs:["Reg 9","Reg 16"],   label:"Communication & Involvement" },
  reviews:          { kloe:"Effective",  regs:["Reg 9","Reg 17"],   label:"Reviews & Reassessment" },
  complaints:       { kloe:"Responsive", regs:["Reg 16","Reg 17"],  label:"Complaints & Compliments" },
  doNotResuscitate: { kloe:"Caring",     regs:["Reg 9","Reg 11"],   label:"DNACPR & End of Life" },
  goals:            { kloe:"Effective",  regs:["Reg 9"],            label:"Outcomes & Goals" },
  hospitalAdmissions:{ kloe:"Safe",      regs:["Reg 12","Reg 15"],  label:"Hospital & Transfers" },
};

function sectionComplianceStatus(section, data){
  const issues = [], warnings = [];
  if(section==="carePlan"){
    if(!data.lastReview) issues.push("No care plan review date recorded");
    else if(daysDiff(data.nextReview)<0) issues.push("Care plan review is OVERDUE");
    else if(daysDiff(data.nextReview)<=30) warnings.push(`Review due in ${daysDiff(data.nextReview)} days`);
    if(!data.personalHistoryAndBackground) issues.push("Personal history not completed — Reg 9 requirement");
    if(!data.communicationNeeds) issues.push("Communication needs not documented — Reg 9 requirement");
    if(data.sections.length<3) warnings.push("Care plan sections appear incomplete");
  }
  if(section==="riskAssessment"){
    if(data.length===0) issues.push("No risk assessments completed — Regulation 12 breach risk");
    data.forEach(r=>{
      if(daysDiff(r.nextReview)<0) issues.push(`${r.area} risk assessment overdue`);
      else if(daysDiff(r.nextReview)<=30) warnings.push(`${r.area} review due soon`);
      if(!r.interventions) issues.push(`${r.area} has no documented interventions`);
    });
  }
  if(section==="mentalCapacity"){
    if(!data.capacityAssessmentDate) issues.push("No mental capacity assessment on record — Reg 11 requirement");
    if(data.dolsApplication&&!data.dolsGranted) warnings.push("DoLS application pending — chase local authority");
    if(data.dolsGranted&&data.dolsExpiryDate&&daysDiff(data.dolsExpiryDate)<0) issues.push("DoLS authorisation has EXPIRED — urgent renewal required");
    if(data.dolsGranted&&data.dolsExpiryDate&&daysDiff(data.dolsExpiryDate)<=60) warnings.push(`DoLS expires in ${daysDiff(data.dolsExpiryDate)} days`);
  }
  if(section==="medication"){
    data.forEach(m=>{ if(daysDiff(m.reviewDate)<0) warnings.push(`${m.name} — medication review overdue`); });
  }
  if(section==="safeguarding"){
    const open=data.filter(s=>s.status==="Open"||s.status==="Under Investigation");
    if(open.length>0) warnings.push(`${open.length} open safeguarding concern(s) require monitoring`);
  }
  if(section==="healthMonitoring"){
    if(!data.weight) issues.push("Weight not recorded — required for nutritional monitoring");
    if(!data.lastWeighDate) warnings.push("Weight monitoring date not set");
  }
  if(section==="reviews"){
    if(data.length===0) warnings.push("No formal reviews recorded yet");
  }
  if(section==="complaints"){
    const unresolved=data.filter(c=>c.type==="Complaint"&&!c.resolvedDate);
    if(unresolved.length>0) issues.push(`${unresolved.length} unresolved complaint(s) — Reg 16 requires timely resolution`);
  }
  if(section==="doNotResuscitate"){
    if(!data.dnrStatus) issues.push("DNACPR status not documented — Reg 9 & 11 requirement");
    if(!data.advanceDirective&&!data.advanceDirectiveDeclined) warnings.push("Advance care planning discussion not recorded");
  }
  if(issues.length>0) return {status:"Non-compliant",color:"#FF5A6E",bg:"#FDF0F0",issues,warnings};
  if(warnings.length>0) return {status:"Needs attention",color:"#FF9A2F",bg:"#FDF8EE",issues:[],warnings};
  return {status:"Compliant",color:"#16B5B8",bg:"#F0FDF4",issues:[],warnings:[]};
}

function CompBadge({status,color,bg}){
  return <span style={{background:bg,color,padding:"2px 9px",borderRadius:20,fontSize:11,fontWeight:700,whiteSpace:"nowrap"}}>{status==="Compliant"?"✓ ":status==="Non-compliant"?"✗ ":"⚠ "}{status}</span>;
}
function RegTag({reg}){
  return <span style={{background:"#F1F3F8",color:"#374151",padding:"2px 7px",borderRadius:4,fontSize:10,fontWeight:700,border:"1px solid #E5E7EB"}}>{reg}</span>;
}
function KloeTag({domain}){
  const c={Safe:"#FF5A6E",Effective:"#FF9A2F",Caring:"#16B5B8",Responsive:"#7A57D1","Well-led":"#7A57D1"}[domain]||"#374151";
  const bg={Safe:"#FDF0F0",Effective:"#FDF8EE",Caring:"#F0FDF4",Responsive:"#EDF5FE","Well-led":"#F3F0FD"}[domain]||"#F1F3F8";
  return <span style={{background:bg,color:c,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{domain}</span>;
}
function ComplianceIssues({issues,warnings}){
  if(!issues.length&&!warnings.length) return null;
  return(
    <div style={{marginBottom:14}}>
      {issues.map((iss,i)=>(
        <div key={i} style={{display:"flex",alignItems:"flex-start",gap:8,padding:"9px 12px",background:"#FDF0F0",border:"1px solid #FF5A6E33",borderRadius:8,marginBottom:5}}>
          <Icon name="alert" size={13} color="#FF5A6E" strokeWidth={2}/>
          <span style={{fontSize:12,color:"#062B7A"}}><strong style={{color:"#FF5A6E"}}>Non-compliant: </strong>{iss}</span>
        </div>
      ))}
      {warnings.map((w,i)=>(
        <div key={i} style={{display:"flex",alignItems:"flex-start",gap:8,padding:"9px 12px",background:"#FDF8EE",border:"1px solid #FF9A2F33",borderRadius:8,marginBottom:5}}>
          <Icon name="alert" size={13} color="#FF9A2F" strokeWidth={2}/>
          <span style={{fontSize:12,color:"#062B7A"}}>{w}</span>
        </div>
      ))}
    </div>
  );
}
function CompSection({title,mapKey,compData,children,action,defaultOpen=true}){
  const [open,setOpen]=useState(defaultOpen);
  const map=SU_COMPLIANCE_MAP[mapKey]||{};
  const comp=compData?sectionComplianceStatus(mapKey,compData):null;
  return(
    <div style={{background:"#fff",borderRadius:10,border:"1px solid #E5E7EB",marginBottom:12,overflow:"hidden"}}>
      <div style={{padding:"13px 16px",borderBottom:open?"1px solid #E5E7EB":"none",display:"flex",justifyContent:"space-between",alignItems:"center",cursor:"pointer",userSelect:"none"}} onClick={()=>setOpen(o=>!o)}>
        <div style={{display:"flex",alignItems:"center",gap:7,flexWrap:"wrap"}}>
          <span style={{fontSize:13,fontWeight:700,color:"#062B7A"}}>{title}</span>
          {map.kloe&&<KloeTag domain={map.kloe}/>}
          {map.regs&&map.regs.map(r=><RegTag key={r} reg={r}/>)}
          {comp&&<CompBadge {...comp}/>}
        </div>
        <div style={{display:"flex",alignItems:"center",gap:8}} onClick={e=>e.stopPropagation()}>
          {action&&<button onClick={action.fn} style={{padding:"5px 12px",borderRadius:6,border:"none",background:"#16B5B8",color:"#fff",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>{action.label}</button>}
          <div onClick={()=>setOpen(o=>!o)} style={{transform:open?"rotate(180deg)":"none",transition:"transform 0.2s",cursor:"pointer"}}><Icon name="chevronDown" size={14} color="#6B7280" strokeWidth={2}/></div>
        </div>
      </div>
      {open&&<div style={{padding:"16px"}}>{children}</div>}
    </div>
  );
}

