// ── Quality Statement helpers ─────────────────────────────────
function getAllQualityStatements(){
  return Object.entries(QUALITY_STATEMENTS).flatMap(([domain, data]) =>
    data.statements.map(s => ({ ...s, domain, domainColor: data.color, domainBg: data.bg }))
  );
}

function getQSByDomain(domain){
  return QUALITY_STATEMENTS[domain]?.statements || [];
}

function calcQSScore(responses){
  // responses = { QS_S1: {score: 0-4, notes: ""}, ... }
  const allQS = getAllQualityStatements();
  if(!responses || Object.keys(responses).length === 0) return null;
  let totalWeight = 0, weightedScore = 0;
  allQS.forEach(qs => {
    const r = responses[qs.id];
    if(r && r.score !== undefined){
      totalWeight += qs.ragWeight;
      weightedScore += (r.score / 4) * 100 * qs.ragWeight;
    }
  });
  return totalWeight > 0 ? Math.round(weightedScore / totalWeight) : null;
}

const QS_SCORE_LABELS = [
  { min:0,  max:24,  label:"Inadequate",            color:"#FF5A6E", bg:"#FDF0F0" },
  { min:25, max:49,  label:"Requires Improvement",  color:"#FF9A2F", bg:"#FDF8EE" },
  { min:50, max:74,  label:"Good",                  color:"#7A57D1", bg:"#EDF5FE" },
  { min:75, max:100, label:"Outstanding",            color:"#16B5B8", bg:"#F0FDF4" },
];

function getQSRating(score){
  if(score === null || score === undefined) return null;
  return QS_SCORE_LABELS.find(r => score >= r.min && score <= r.max) || QS_SCORE_LABELS[0];
}

// ── Quality Statements Audit Page ─────────────────────────────
function QualityStatementsPage(){
  const [activeTab,   setActiveTab]   = useState("audit");
  const [domain,      setDomain]      = useState("Safe");
  const [responses,   setResponses]   = useState({});
  const [notes,       setNotes]       = useState({});
  const [expandedQS,  setExpandedQS]  = useState(null);
  const [showGuide,   setShowGuide]   = useState(false);

  const SCORE_OPTIONS = [
    { value:0, label:"Not met",          color:"#FF5A6E", bg:"#FDF0F0", desc:"No evidence. Significant concern." },
    { value:1, label:"Partially met",    color:"#FF9A2F", bg:"#FDF8EE", desc:"Some evidence but gaps remain." },
    { value:2, label:"Mostly met",       color:"#7A57D1", bg:"#EDF5FE", desc:"Good evidence with minor gaps." },
    { value:3, label:"Fully met",        color:"#16B5B8", bg:"#F0FDF4", desc:"Strong evidence. Well embedded." },
    { value:4, label:"Exceeds standard", color:"#7A57D1", bg:"#F3F0FD", desc:"Outstanding evidence. Exemplary practice." },
  ];

  const setResponse = (qsId, score) => setResponses(p => ({ ...p, [qsId]: { ...p[qsId], score } }));
  const setNote     = (qsId, note) => setNotes(p => ({ ...p, [qsId]: note }));

  const overallScore  = calcQSScore(responses);
  const overallRating = getQSRating(overallScore);

  // Domain scores
  const domainScores = Object.keys(QUALITY_STATEMENTS).map(d => {
    const stmts = getQSByDomain(d);
    const answered = stmts.filter(s => responses[s.id]?.score !== undefined);
    if(answered.length === 0) return { domain: d, score: null, answered: 0, total: stmts.length };
    let tw = 0, ws = 0;
    answered.forEach(s => { tw += s.ragWeight; ws += (responses[s.id].score / 4) * 100 * s.ragWeight; });
    return { domain: d, score: Math.round(ws / tw), answered: answered.length, total: stmts.length };
  });

  const currentDomainStmts = getQSByDomain(domain);
  const currentDomainData  = QUALITY_STATEMENTS[domain];

  const answeredCount = getAllQualityStatements().filter(s => responses[s.id]?.score !== undefined).length;
  const totalCount    = getAllQualityStatements().length;
  const pctComplete   = Math.round((answeredCount / totalCount) * 100);

  return(
    <div style={{height:"100%",display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif"}}>
      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#062B7A,#2A4A7A)",padding:"16px 24px",flexShrink:0}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
          <div>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:2}}>
              <div style={{fontSize:16,fontWeight:800,color:"#fff"}}>CQC Quality Statements Audit</div>
              <span style={{background:"rgba(43,191,178,0.2)",color:"#16B5B8",padding:"2px 9px",borderRadius:20,fontSize:10,fontWeight:700,border:"1px solid rgba(43,191,178,0.3)"}}>2023 Framework</span>
            </div>
            <div style={{fontSize:12,color:"rgba(255,255,255,0.55)"}}>34 Quality Statements across 5 domains · Modern CQC inspection framework · Runs alongside KLoE</div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            {overallScore !== null && (
              <div style={{textAlign:"center",padding:"8px 16px",background:"rgba(255,255,255,0.08)",borderRadius:9}}>
                <div style={{fontSize:24,fontWeight:900,color:overallRating?.color||"#fff",lineHeight:1}}>{overallScore}%</div>
                <div style={{fontSize:10,color:"rgba(255,255,255,0.5)",marginTop:2}}>{overallRating?.label}</div>
              </div>
            )}
            <button onClick={()=>setShowGuide(true)} style={{padding:"7px 14px",borderRadius:8,border:"1px solid rgba(255,255,255,0.2)",background:"transparent",color:"rgba(255,255,255,0.7)",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Inspector Guide</button>
          </div>
        </div>
        {/* Progress */}
        <div style={{display:"flex",justifyContent:"space-between",marginBottom:4,fontSize:11}}>
          <span style={{color:"rgba(255,255,255,0.5)"}}>{answeredCount} of {totalCount} statements assessed</span>
          <span style={{color:pctComplete>=80?"#6EE7B7":"#FCD34D",fontWeight:700}}>{pctComplete}% complete</span>
        </div>
        <div style={{height:4,background:"rgba(255,255,255,0.1)",borderRadius:2,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${pctComplete}%`,background:"#16B5B8",borderRadius:2,transition:"width 0.5s"}}/>
        </div>
      </div>

      {/* Domain tabs */}
      <div style={{background:"#fff",borderBottom:"1px solid #E5E7EB",padding:"0 20px",display:"flex",gap:2,overflowX:"auto",flexShrink:0}}>
        {Object.entries(QUALITY_STATEMENTS).map(([d, data]) => {
          const ds = domainScores.find(x => x.domain === d);
          const isActive = domain === d;
          return(
            <button key={d} onClick={()=>setDomain(d)} style={{
              padding:"10px 14px",whiteSpace:"nowrap",borderRadius:"6px 6px 0 0",
              border:"none",background:isActive?"#F8FAFC":"transparent",
              color:isActive?"#062B7A":"#6B7280",
              fontSize:12,fontWeight:isActive?700:400,cursor:"pointer",fontFamily:"inherit",
              borderBottom:isActive?`2px solid ${data.color}`:"2px solid transparent",
              display:"flex",alignItems:"center",gap:6,
            }}>
              <div style={{width:8,height:8,borderRadius:"50%",background:data.color,flexShrink:0}}/>
              {d}
              <span style={{
                background:ds?.score !== null?getQSRating(ds?.score)?.bg||"#F1F3F8":"#F1F3F8",
                color:ds?.score !== null?getQSRating(ds?.score)?.color||"#6B7280":"#6B7280",
                padding:"0 6px",borderRadius:20,fontSize:10,fontWeight:700,
              }}>{ds?.answered||0}/{ds?.total}</span>
            </button>
          );
        })}
      </div>

      {/* Content */}
      <div style={{flex:1,overflowY:"auto",padding:"16px 24px",background:"#F8FAFC"}}>
        {/* Domain overview */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10,marginBottom:16}}>
          {domainScores.map(ds => {
            const r = getQSRating(ds.score);
            const dData = QUALITY_STATEMENTS[ds.domain];
            return(
              <div key={ds.domain} onClick={()=>setDomain(ds.domain)} style={{
                background:"#fff",borderRadius:9,padding:"12px 10px",textAlign:"center",
                cursor:"pointer",borderLeft:`3px solid ${dData?.color}`,
                boxShadow:"0 1px 3px rgba(0,0,0,0.05)",transition:"all 0.15s",
              }}
                onMouseEnter={e=>{e.currentTarget.style.transform="translateY(-1px)";}}
                onMouseLeave={e=>{e.currentTarget.style.transform="none";}}>
                <div style={{fontSize:9,fontWeight:700,color:"#6B7280",textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:4}}>{ds.domain}</div>
                <div style={{fontSize:22,fontWeight:800,color:r?.color||"#D1D5DB",lineHeight:1,marginBottom:3}}>{ds.score !== null ? `${ds.score}%` : "—"}</div>
                <div style={{fontSize:9,color:"#6B7280"}}>{ds.answered}/{ds.total} done</div>
              </div>
            );
          })}
        </div>

        {/* Statements for current domain */}
        <div style={{marginBottom:8,fontSize:13,fontWeight:700,color:"#062B7A",display:"flex",alignItems:"center",gap:8}}>
          <div style={{width:10,height:10,borderRadius:"50%",background:currentDomainData?.color}}/>
          {domain} — {currentDomainStmts.length} Quality Statements
        </div>

        {currentDomainStmts.map((qs, i) => {
          const resp    = responses[qs.id];
          const score   = resp?.score;
          const scoreOpt = score !== undefined ? SCORE_OPTIONS[score] : null;
          const isExpanded = expandedQS === qs.id;

          return(
            <div key={qs.id} style={{
              background:"#fff",borderRadius:10,marginBottom:10,overflow:"hidden",
              border:`1px solid ${scoreOpt ? scoreOpt.color+'33' : '#E5E7EB'}`,
              borderLeft:`4px solid ${scoreOpt ? scoreOpt.color : '#D1D5DB'}`,
              boxShadow:"0 1px 3px rgba(0,0,0,0.04)",
            }}>
              {/* Statement header */}
              <div style={{padding:"12px 16px",display:"flex",justifyContent:"space-between",alignItems:"flex-start",cursor:"pointer"}} onClick={()=>setExpandedQS(isExpanded?null:qs.id)}>
                <div style={{flex:1,marginRight:12}}>
                  <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4,flexWrap:"wrap"}}>
                    <span style={{background:currentDomainData?.bg,color:currentDomainData?.color,padding:"1px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{qs.code}</span>
                    <span style={{fontSize:13,fontWeight:700,color:"#062B7A"}}>{qs.title}</span>
                    <RegTag reg={qs.reg}/>
                    {scoreOpt&&<span style={{background:scoreOpt.bg,color:scoreOpt.color,padding:"1px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{scoreOpt.label}</span>}
                  </div>
                  <div style={{fontSize:12,color:"#374151",lineHeight:1.6,display:isExpanded?"block":"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical",overflow:isExpanded?"visible":"hidden"}}>{qs.full}</div>
                </div>
                <div style={{transform:isExpanded?"rotate(180deg)":"none",transition:"transform 0.2s",flexShrink:0}}>
                  <Icon name="chevronDown" size={14} color="#6B7280" strokeWidth={2}/>
                </div>
              </div>

              {/* Expanded content */}
              {isExpanded&&(
                <div style={{borderTop:"1px solid #E5E7EB",padding:"14px 16px"}}>
                  {/* Evidence needed */}
                  <div style={{marginBottom:14}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#6B7280",marginBottom:7,textTransform:"uppercase",letterSpacing:"0.5px"}}>Evidence CQC looks for</div>
                    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:4}}>
                      {qs.evidenceNeeded.map((ev,j)=>(
                        <div key={j} style={{display:"flex",gap:6,alignItems:"flex-start",padding:"5px 8px",background:"#F0FBFA",borderRadius:6,fontSize:11,color:"#0E8F92"}}>
                          <span style={{color:"#16B5B8",fontWeight:700,flexShrink:0}}>✓</span>{ev}
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Inspector questions */}
                  <div style={{marginBottom:14}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#6B7280",marginBottom:7,textTransform:"uppercase",letterSpacing:"0.5px"}}>Inspector may ask</div>
                    {qs.inspectorQuestions.map((q,j)=>(
                      <div key={j} style={{display:"flex",gap:6,alignItems:"flex-start",marginBottom:4,fontSize:12,color:"#374151"}}>
                        <span style={{color:"#7A57D1",fontWeight:700,flexShrink:0}}>Q</span>{q}
                      </div>
                    ))}
                  </div>

                  {/* Score selector */}
                  <div style={{marginBottom:10}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#6B7280",marginBottom:7,textTransform:"uppercase",letterSpacing:"0.5px"}}>Your Assessment</div>
                    <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                      {SCORE_OPTIONS.map(opt=>(
                        <button key={opt.value} onClick={()=>setResponse(qs.id, opt.value)} style={{
                          padding:"6px 12px",borderRadius:8,
                          border:`1.5px solid ${score===opt.value?opt.color:"#E5E7EB"}`,
                          background:score===opt.value?opt.bg:"#fff",
                          color:score===opt.value?opt.color:"#6B7280",
                          fontSize:11,fontWeight:score===opt.value?700:400,
                          cursor:"pointer",fontFamily:"inherit",transition:"all 0.15s",
                        }}>
                          {opt.label}
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Notes */}
                  <div>
                    <label style={{fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.5px"}}>Evidence notes</label>
                    <textarea
                      value={notes[qs.id]||""}
                      onChange={e=>setNote(qs.id, e.target.value)}
                      rows={2}
                      placeholder="Note your evidence, gaps, and planned actions…"
                      style={{width:"100%",padding:"8px 10px",borderRadius:7,border:"1.5px solid #D1D5DB",fontSize:12,color:"#062B7A",outline:"none",fontFamily:"inherit",resize:"vertical",lineHeight:1.5,boxSizing:"border-box"}}
                      onFocus={e=>e.target.style.borderColor="#16B5B8"}
                      onBlur={e=>e.target.style.borderColor="#D1D5DB"}
                    />
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Inspector guide modal */}
      {showGuide&&(
        <div style={{position:"fixed",inset:0,zIndex:200,background:"rgba(16,30,48,0.6)",display:"flex",alignItems:"center",justifyContent:"center"}}>
          <div style={{width:680,maxHeight:"90vh",background:"#fff",borderRadius:14,boxShadow:"0 20px 60px rgba(0,0,0,0.28)",overflow:"hidden",display:"flex",flexDirection:"column"}}>
            <div style={{padding:"16px 22px",borderBottom:"1px solid #E5E7EB",display:"flex",justifyContent:"space-between",alignItems:"center",background:"linear-gradient(135deg,#062B7A,#2A4A7A)"}}>
              <div>
                <div style={{fontSize:14,fontWeight:700,color:"#fff"}}>CQC Quality Statements — Manager Guide</div>
                <div style={{fontSize:11,color:"rgba(255,255,255,0.55)"}}>What changed in 2023 and what it means for your service</div>
              </div>
              <button onClick={()=>setShowGuide(false)} style={{background:"rgba(255,255,255,0.1)",border:"none",cursor:"pointer",color:"rgba(255,255,255,0.7)",fontSize:20,padding:"3px 8px",borderRadius:6}}>×</button>
            </div>
            <div style={{flex:1,overflowY:"auto",padding:"20px 22px"}}>
              {[
                {title:"What are Quality Statements?", text:"In 2023, CQC updated their inspection framework. While the five KLoE domains (Safe, Effective, Caring, Responsive, Well-led) remain, inspectors now assess services against 34 Quality Statements within those domains. These are more specific, more evidence-based, and more focused on outcomes for people rather than processes."},
                {title:"Do KLoEs still matter?", text:"Yes. KLoEs are still used and many commissioners, providers, and managers still think in KLoE terms. Quality Statements sit within the KLoE framework — they are more detailed evidence categories within each domain. Running both audits gives you the fullest picture of your compliance."},
                {title:"How are Quality Statements scored?", text:"Evidentra uses a 5-point scale: Not met (0), Partially met (1), Mostly met (2), Fully met (3), Exceeds standard (4). Scores are weighted by the significance of each statement. An overall percentage is calculated for each domain and for the service overall."},
                {title:"How do inspectors use Quality Statements?", text:"Inspectors gather evidence against each Quality Statement through observation, conversations with staff and service users, and document review. They triangulate evidence from multiple sources. A well-evidenced service will have documentary evidence, staff who can speak to each statement, and service users who confirm their experience matches what is documented."},
                {title:"What is the single biggest tip?", text:"The biggest shift in the 2023 framework is the emphasis on outcomes over processes. Having a policy is not enough — you need evidence that the policy makes a difference to the people you support. CQC inspectors will ask service users and staff, not just look at documents. The most powerful evidence is a service user who can describe how their care is person-centred, and a staff member who can explain why they do things the way they do."},
              ].map((item,i)=>(
                <div key={i} style={{marginBottom:16}}>
                  <div style={{fontSize:13,fontWeight:700,color:"#062B7A",marginBottom:5}}>{item.title}</div>
                  <div style={{fontSize:12,color:"#374151",lineHeight:1.7}}>{item.text}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

