const AUDIT_RESPONSES = ["Yes","Partial","No","N/A"];
const RESP_CONFIG = {
  "Yes":     {score:100, color:"#16B5B8", bg:"#F0FDF4"},
  "Partial": {score:50,  color:"#FF9A2F", bg:"#FDF8EE"},
  "No":      {score:0,   color:"#FF5A6E", bg:"#FDF0F0"},
  "N/A":     {score:null,color:"#6B7280", bg:"#F1F3F8"},
};

function calcAuditScore(answers){
  const scorable = Object.values(answers).filter(a=>a.response&&a.response!=="N/A");
  if(!scorable.length) return null;
  const total = scorable.reduce((s,a)=>s+(RESP_CONFIG[a.response]?.score||0),0);
  return Math.round(total/scorable.length);
}

function calcDomainScore(domain, answers){
  const domainQs = AUDIT_KLOE_DATA[domain].subdomains.flatMap(sd=>sd.questions.map(q=>q.id));
  const scorable  = domainQs.filter(id=>answers[id]?.response&&answers[id].response!=="N/A");
  if(!scorable.length) return null;
  const total = scorable.reduce((s,id)=>s+(RESP_CONFIG[answers[id].response]?.score||0),0);
  return Math.round(total/scorable.length);
}

function ScorePill({score}){
  if(score===null||score===undefined) return <span style={{fontSize:12,color:"#6B7280"}}>—</span>;
  const color = score>=85?"#16B5B8":score>=70?"#FF9A2F":"#FF5A6E";
  const bg    = score>=85?"#F0FDF4":score>=70?"#FDF8EE":"#FDF0F0";
  return <span style={{background:bg,color,padding:"3px 10px",borderRadius:20,fontSize:12,fontWeight:700}}>{score}%</span>;
}

// ── Audit Question Row ────────────────────────────────────────
function AuditQuestion({q, answer, onChange}){
  const [showNotes, setShowNotes] = useState(!!(answer?.notes));
  const [showEvidence, setShowEvidence] = useState(false);
  const fileRef = useRef();
  const resp = answer?.response;
  const rc = resp ? RESP_CONFIG[resp] : null;

  return(
    <div style={{
      padding:"14px 16px",
      background: rc ? rc.bg : "#F8FAFC",
      borderRadius:8, marginBottom:8,
      border:`1px solid ${rc ? rc.color+"33" : "#E5E7EB"}`,
      borderLeft:`4px solid ${rc ? rc.color : "#E5E7EB"}`,
    }}>
      <div style={{display:"flex",gap:12,alignItems:"flex-start",marginBottom:10}}>
        <div style={{flex:1}}>
          <div style={{fontSize:13,color:"#062B7A",fontWeight:500,lineHeight:1.5,marginBottom:4}}>{q.text}</div>
          <div style={{display:"flex",gap:6,alignItems:"center"}}>
            <RegTag reg={q.reg}/>
            {answer?.evidence&&<span style={{fontSize:10,background:"#F0FDF4",color:"#16B5B8",padding:"1px 7px",borderRadius:20,fontWeight:600}}>Evidence uploaded</span>}
          </div>
        </div>
        {/* Response buttons */}
        <div style={{display:"flex",gap:5,flexShrink:0}}>
          {AUDIT_RESPONSES.map(r=>(
            <button key={r} onClick={()=>onChange({...answer,response:r})} style={{
              padding:"5px 12px",borderRadius:7,border:`1.5px solid ${resp===r?RESP_CONFIG[r].color:"#D1D5DB"}`,
              background:resp===r?RESP_CONFIG[r].bg:"#fff",
              color:resp===r?RESP_CONFIG[r].color:"#6B7280",
              fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"inherit",
              transition:"all 0.15s",
            }}>{r}</button>
          ))}
        </div>
      </div>

      {/* Notes + Evidence toggle row */}
      <div style={{display:"flex",gap:10,paddingTop:6,borderTop:"1px solid rgba(0,0,0,0.05)"}}>
        <button onClick={()=>setShowNotes(n=>!n)} style={{background:"none",border:"none",cursor:"pointer",fontSize:11,color:"#6B7280",fontFamily:"inherit",padding:0,display:"flex",alignItems:"center",gap:4}}>
          <Icon name="tasks" size={11} color="#6B7280" strokeWidth={1.8}/>
          {showNotes?"Hide notes":"Add notes"}
        </button>
        <button onClick={()=>setShowEvidence(e=>!e)} style={{background:"none",border:"none",cursor:"pointer",fontSize:11,color:"#6B7280",fontFamily:"inherit",padding:0,display:"flex",alignItems:"center",gap:4}}>
          <Icon name="evidence" size={11} color="#6B7280" strokeWidth={1.8}/>
          {answer?.evidence?"Evidence: "+answer.evidence:"Attach evidence"}
        </button>
      </div>

      {showNotes&&(
        <textarea value={answer?.notes||""} onChange={e=>onChange({...answer,notes:e.target.value})}
          placeholder="Add notes, context or action required…"
          rows={2}
          style={{width:"100%",marginTop:8,padding:"8px 10px",borderRadius:7,border:"1.5px solid #D1D5DB",fontSize:12,color:"#062B7A",outline:"none",fontFamily:"inherit",resize:"vertical",boxSizing:"border-box"}}
          onFocus={e=>e.target.style.borderColor="#16B5B8"}
          onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
      )}

      {showEvidence&&(
        <div style={{display:"flex",alignItems:"center",gap:8,marginTop:8}}>
          <button onClick={()=>fileRef.current.click()} style={{padding:"6px 14px",borderRadius:7,border:"1px dashed #D1D5DB",background:"#F8FAFC",color:"#374151",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>
            {answer?.evidence?"Replace file":"Choose file…"}
          </button>
          {answer?.evidence&&<span style={{fontSize:11,color:"#16B5B8",fontWeight:500}}>✓ {answer.evidence}</span>}
          <input ref={fileRef} type="file" style={{display:"none"}} onChange={e=>onChange({...answer,evidence:e.target.files[0]?.name||""})}/>
        </div>
      )}
    </div>
  );
}

// ── Active Audit Form ─────────────────────────────────────────
function AuditForm({audit, onSave, onSubmit, onBack}){
  const [answers, setAnswers] = useState(audit.answers||{});
  const [activeDomain, setActiveDomain] = useState(audit.activeDomain||"Safe");
  const [saving, setSaving] = useState(false);

  const setAnswer = (qId, val) => setAnswers(prev=>({...prev,[qId]:val}));

  const totalScore   = calcAuditScore(answers);
  const domainScore  = calcDomainScore(activeDomain, answers);
  const domainData   = AUDIT_KLOE_DATA[activeDomain];

  const totalQs      = Object.values(AUDIT_KLOE_DATA).flatMap(d=>d.subdomains.flatMap(sd=>sd.questions)).length;
  const answeredQs   = Object.values(answers).filter(a=>a.response).length;
  const progress     = Math.round((answeredQs/totalQs)*100);

  const handleSave = () => {
    setSaving(true);
    setTimeout(()=>{onSave({...audit, answers, activeDomain, lastSaved:new Date().toISOString(), status:"In Progress"});setSaving(false);},600);
  };

  const handleSubmit = () => {
    const score = calcAuditScore(answers);
    onSubmit({...audit, answers, status:"Completed", score, completedAt:new Date().toISOString().split("T")[0],
      domainScores:{
        Safe:        calcDomainScore("Safe",answers),
        Effective:   calcDomainScore("Effective",answers),
        Caring:      calcDomainScore("Caring",answers),
        Responsive:  calcDomainScore("Responsive",answers),
        "Well-led":  calcDomainScore("Well-led",answers),
      }
    });
  };

  return(
    <div style={{height:"100%",display:"flex",flexDirection:"column",overflow:"hidden"}}>
      {/* Header */}
      <div style={{background:"#fff",borderBottom:"1px solid #E5E7EB",padding:"14px 22px",flexShrink:0}}>
        <button onClick={onBack} style={{display:"flex",alignItems:"center",gap:5,background:"none",border:"none",cursor:"pointer",color:"#6B7280",fontSize:12,fontWeight:600,fontFamily:"inherit",marginBottom:10,padding:0}}>
          ← Back to audits
        </button>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
          <div>
            <div style={{fontSize:17,fontWeight:800,color:"#062B7A",marginBottom:2}}>{audit.name}</div>
            <div style={{fontSize:12,color:"#6B7280"}}>Started: {audit.startedAt} · {audit.conductedBy} · {audit.careType}</div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <div style={{textAlign:"center",padding:"6px 14px",background:"#F8FAFC",borderRadius:8}}>
              <div style={{fontSize:11,color:"#6B7280",marginBottom:2}}>Progress</div>
              <div style={{fontSize:14,fontWeight:800,color:"#062B7A"}}>{progress}%</div>
            </div>
            <div style={{textAlign:"center",padding:"6px 14px",background:"#F8FAFC",borderRadius:8}}>
              <div style={{fontSize:11,color:"#6B7280",marginBottom:2}}>Current Score</div>
              <ScorePill score={totalScore}/>
            </div>
            <button onClick={handleSave} style={{padding:"8px 16px",borderRadius:8,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>
              {saving?"Saving…":"Save Draft"}
            </button>
            <button onClick={handleSubmit} disabled={answeredQs<5} style={{padding:"8px 18px",borderRadius:8,border:"none",background:answeredQs>=5?"linear-gradient(135deg,#16B5B8,#0E8F92)":"#D1D5DB",color:"#fff",fontSize:13,fontWeight:700,cursor:answeredQs>=5?"pointer":"not-allowed",fontFamily:"inherit"}}>
              Submit Audit
            </button>
          </div>
        </div>

        {/* Progress bar */}
        <div style={{height:5,background:"#E5E7EB",borderRadius:3,marginBottom:12}}>
          <div style={{height:"100%",width:`${progress}%`,background:"linear-gradient(90deg,#16B5B8,#0E8F92)",borderRadius:3,transition:"width 0.3s"}}/>
        </div>

        {/* Domain tabs */}
        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
          {Object.entries(AUDIT_KLOE_DATA).map(([domain,d])=>{
            const ds = calcDomainScore(domain,answers);
            const isActive = activeDomain===domain;
            return(
              <button key={domain} onClick={()=>setActiveDomain(domain)} style={{
                display:"flex",alignItems:"center",gap:6,
                padding:"7px 14px",borderRadius:8,border:`1.5px solid ${isActive?d.color:"#D1D5DB"}`,
                background:isActive?d.bg:"#fff",
                color:isActive?d.color:"#6B7280",
                fontSize:12,fontWeight:isActive?700:500,
                cursor:"pointer",fontFamily:"inherit",transition:"all 0.15s",
              }}>
                {domain}
                {ds!==null&&<span style={{fontSize:10,fontWeight:700,background:isActive?"rgba(255,255,255,0.7)":"#F1F3F8",color:isActive?d.color:"#6B7280",padding:"1px 6px",borderRadius:20}}>{ds}%</span>}
              </button>
            );
          })}
        </div>
      </div>

      {/* Questions body */}
      <div style={{flex:1,overflowY:"auto",padding:"18px 22px",background:"#F8FAFC"}}>
        <div style={{maxWidth:900}}>
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:16,padding:"12px 16px",background:"#fff",borderRadius:10,border:`1px solid ${domainData.color}22`}}>
            <KloeTag domain={activeDomain}/>
            <span style={{fontSize:13,color:"#374151",lineHeight:1.5}}>{domainData.description}</span>
            <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:6}}>
              <span style={{fontSize:11,color:"#6B7280"}}>Domain score:</span>
              <ScorePill score={domainScore}/>
            </div>
          </div>

          {domainData.subdomains.map(sd=>(
            <div key={sd.id} style={{marginBottom:20}}>
              <div style={{fontSize:13,fontWeight:700,color:"#062B7A",marginBottom:10,padding:"8px 12px",background:"#fff",borderRadius:8,border:"1px solid #E5E7EB",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span>{sd.title}</span>
                <ScorePill score={calcDomainScore(activeDomain, Object.fromEntries(sd.questions.map(q=>[q.id, answers[q.id]]).filter(([_,v])=>v)))}/>
              </div>
              {sd.questions.map(q=>(
                <AuditQuestion key={q.id} q={q} answer={answers[q.id]||{}}
                  onChange={val=>setAnswer(q.id,val)}/>
              ))}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── Audit Report / Results ────────────────────────────────────
function AuditReport({audit, onBack}){
  const overallColor = audit.score>=85?"#16B5B8":audit.score>=70?"#FF9A2F":"#FF5A6E";
  const overallBg    = audit.score>=85?"#F0FDF4":audit.score>=70?"#FDF8EE":"#FDF0F0";
  const ragLabel     = audit.score>=85?"Good":audit.score>=70?"Requires Improvement":"Inadequate";

  const allQuestions = Object.values(AUDIT_KLOE_DATA).flatMap(d=>
    d.subdomains.flatMap(sd=>sd.questions.map(q=>({...q, domain:Object.keys(AUDIT_KLOE_DATA).find(dk=>AUDIT_KLOE_DATA[dk].subdomains.some(s=>s.questions.some(qq=>qq.id===q.id)))})))
  );
  const noAnswers    = allQuestions.filter(q=>audit.answers[q.id]?.response==="No");
  const partialAnswers = allQuestions.filter(q=>audit.answers[q.id]?.response==="Partial");

  return(
    <div style={{height:"100%",overflowY:"auto",background:"#F8FAFC",padding:"22px"}}>
      <button onClick={onBack} style={{display:"flex",alignItems:"center",gap:5,background:"none",border:"none",cursor:"pointer",color:"#6B7280",fontSize:12,fontWeight:600,fontFamily:"inherit",marginBottom:18,padding:0}}>
        ← Back to audits
      </button>

      <div style={{maxWidth:900}}>
        {/* Report header */}
        <div style={{background:"#fff",borderRadius:12,padding:"24px",marginBottom:16,border:"1px solid #E5E7EB"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:20}}>
            <div>
              <div style={{fontSize:18,fontWeight:800,color:"#062B7A",marginBottom:4}}>{audit.name}</div>
              <div style={{fontSize:12,color:"#6B7280"}}>Completed: {audit.completedAt} · Conducted by: {audit.conductedBy}</div>
              <div style={{fontSize:12,color:"#6B7280"}}>Service: {audit.serviceName} · {audit.careType}</div>
            </div>
            <div style={{textAlign:"center",padding:"16px 24px",background:overallBg,borderRadius:12,border:`2px solid ${overallColor}33`}}>
              <div style={{fontSize:36,fontWeight:800,color:overallColor,lineHeight:1}}>{audit.score}%</div>
              <div style={{fontSize:12,fontWeight:700,color:overallColor,marginTop:4}}>{ragLabel}</div>
              <div style={{fontSize:10,color:"#6B7280",marginTop:2}}>Overall Score</div>
            </div>
          </div>

          {/* Domain scores */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10}}>
            {Object.entries(AUDIT_KLOE_DATA).map(([domain,d])=>{
              const score = audit.domainScores?.[domain];
              const sc = score>=85?"#16B5B8":score>=70?"#FF9A2F":"#FF5A6E";
              const bg = score>=85?"#F0FDF4":score>=70?"#FDF8EE":"#FDF0F0";
              return(
                <div key={domain} style={{padding:"12px 10px",background:bg,borderRadius:8,textAlign:"center",border:`1px solid ${sc}22`}}>
                  <div style={{fontSize:20,fontWeight:800,color:sc,lineHeight:1}}>{score!==null?`${score}%`:"—"}</div>
                  <div style={{fontSize:11,fontWeight:700,color:"#062B7A",marginTop:4}}>{domain}</div>
                  <div style={{fontSize:10,color:sc,marginTop:2}}>{score>=85?"Good":score>=70?"Improve":"Poor"}</div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Areas of non-compliance */}
        {noAnswers.length>0&&(
          <div style={{background:"#fff",borderRadius:12,padding:"20px",marginBottom:16,border:"1px solid #FF5A6E33"}}>
            <div style={{fontSize:14,fontWeight:700,color:"#FF5A6E",marginBottom:14,display:"flex",alignItems:"center",gap:7}}>
              <Icon name="alert" size={15} color="#FF5A6E" strokeWidth={2}/> Areas of Non-Compliance ({noAnswers.length})
              <span style={{fontSize:11,color:"#6B7280",fontWeight:400,marginLeft:4}}>Immediate action required</span>
            </div>
            {noAnswers.map((q,i)=>(
              <div key={q.id} style={{padding:"10px 12px",background:"#FDF0F0",borderRadius:8,marginBottom:6,display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                <div style={{flex:1}}>
                  <div style={{fontSize:12,color:"#062B7A",fontWeight:500,lineHeight:1.4,marginBottom:3}}>{q.text}</div>
                  <div style={{display:"flex",gap:6}}><KloeTag domain={q.domain}/><RegTag reg={q.reg}/></div>
                  {audit.answers[q.id]?.notes&&<div style={{fontSize:11,color:"#FF5A6E",marginTop:4}}>Note: {audit.answers[q.id].notes}</div>}
                </div>
                <span style={{background:"#FDF0F0",color:"#FF5A6E",padding:"2px 9px",borderRadius:20,fontSize:11,fontWeight:700,flexShrink:0,marginLeft:8}}>No</span>
              </div>
            ))}
          </div>
        )}

        {/* Partial compliance */}
        {partialAnswers.length>0&&(
          <div style={{background:"#fff",borderRadius:12,padding:"20px",marginBottom:16,border:"1px solid #FF9A2F33"}}>
            <div style={{fontSize:14,fontWeight:700,color:"#FF9A2F",marginBottom:14,display:"flex",alignItems:"center",gap:7}}>
              <Icon name="alert" size={15} color="#FF9A2F" strokeWidth={2}/> Partial Compliance ({partialAnswers.length})
              <span style={{fontSize:11,color:"#6B7280",fontWeight:400,marginLeft:4}}>Improvement needed</span>
            </div>
            {partialAnswers.map((q,i)=>(
              <div key={q.id} style={{padding:"10px 12px",background:"#FDF8EE",borderRadius:8,marginBottom:6,display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                <div style={{flex:1}}>
                  <div style={{fontSize:12,color:"#062B7A",fontWeight:500,lineHeight:1.4,marginBottom:3}}>{q.text}</div>
                  <div style={{display:"flex",gap:6}}><KloeTag domain={q.domain}/><RegTag reg={q.reg}/></div>
                  {audit.answers[q.id]?.notes&&<div style={{fontSize:11,color:"#FF9A2F",marginTop:4}}>Note: {audit.answers[q.id].notes}</div>}
                </div>
                <span style={{background:"#FDF8EE",color:"#FF9A2F",padding:"2px 9px",borderRadius:20,fontSize:11,fontWeight:700,flexShrink:0,marginLeft:8}}>Partial</span>
              </div>
            ))}
          </div>
        )}

        {/* Action plan summary */}
        <div style={{background:"#fff",borderRadius:12,padding:"20px",border:"1px solid #E5E7EB"}}>
          <div style={{fontSize:14,fontWeight:700,color:"#062B7A",marginBottom:14,display:"flex",alignItems:"center",gap:7}}>
            <Icon name="tasks" size={15} color="#16B5B8" strokeWidth={2}/> Suggested Action Plan
          </div>
          {noAnswers.length===0&&partialAnswers.length===0
            ? <div style={{fontSize:13,color:"#16B5B8",background:"#F0FDF4",padding:"14px",borderRadius:8,fontWeight:500}}>✓ Excellent — no areas of non-compliance or partial compliance identified in this audit.</div>
            : (
              <div>
                <div style={{fontSize:12,color:"#374151",marginBottom:12,lineHeight:1.6}}>
                  Based on this audit, the following actions are recommended to improve compliance before the next CQC inspection:
                </div>
                {[...noAnswers.slice(0,3).map(q=>({priority:"High",action:`Address non-compliance: ${q.text.slice(0,80)}…`,domain:q.domain,reg:q.reg})),
                  ...partialAnswers.slice(0,3).map(q=>({priority:"Medium",action:`Improve partial compliance: ${q.text.slice(0,80)}…`,domain:q.domain,reg:q.reg}))
                ].map((item,i)=>(
                  <div key={i} style={{display:"flex",gap:10,padding:"9px 0",borderBottom:"1px solid #E5E7EB",alignItems:"flex-start"}}>
                    <span style={{background:item.priority==="High"?"#FDF0F0":"#FDF8EE",color:item.priority==="High"?"#FF5A6E":"#FF9A2F",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700,flexShrink:0,marginTop:2}}>{item.priority}</span>
                    <div style={{flex:1}}>
                      <div style={{fontSize:12,color:"#062B7A",marginBottom:3}}>{item.action}</div>
                      <div style={{display:"flex",gap:5}}><KloeTag domain={item.domain}/><RegTag reg={item.reg}/></div>
                    </div>
                  </div>
                ))}
              </div>
            )
          }
        </div>
      </div>
    </div>
  );
}

