function AuditCentrePage(){
  const [audits, setAudits]     = useState(INITIAL_AUDITS);

  // ── Supabase: load audits for this company ─────────────────
  useEffect(()=>{
    if(!hasSupabase()) return;
    const cid = APP_CONFIG?.companyId;
    if(!cid || cid==="demo-company-001") return;
    supabase.from("audits").select("*")
      .eq("company_id", cid)
      .order("created_at",{ascending:false})
      .then(({data,error})=>{ if(!error&&data) setAudits(data); });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[APP_CONFIG?.companyId]);
  const [view, setView]         = useState("list"); // list | form | report
  const [activeAudit, setActive]= useState(null);
  const [showNew, setShowNew]   = useState(false);
  const [newAuditName, setNewAuditName] = useState("");

  const saveAudit  = updated => { setAudits(a=>a.map(x=>x.id===updated.id?updated:x)); setActive(updated);
      if(hasSupabase()&&APP_CONFIG?.companyId!=="demo-company-001"){const{id,...rest}=updated;supabase.from("audits").update(rest).eq("id",updated.id);}
    };
  const submitAudit= completed =>{ setAudits(a=>a.map(x=>x.id===completed.id?completed:x)); setActive(completed); setView("report");
      if(hasSupabase()&&APP_CONFIG?.companyId!=="demo-company-001"){const{id,...rest}=completed;supabase.from("audits").update(rest).eq("id",completed.id);} };

  if(view==="form"&&activeAudit) return <AuditForm audit={activeAudit} onSave={saveAudit} onSubmit={submitAudit} onBack={()=>{setView("list");setActive(null);}}/>;
  if(view==="report"&&activeAudit) return <AuditReport audit={activeAudit} onBack={()=>{setView("list");setActive(null);}}/>;

  const completed = audits.filter(a=>a.status==="Completed");
  const avgScore  = completed.length ? Math.round(completed.reduce((s,a)=>s+a.score,0)/completed.length) : null;

  return(
    <div style={{padding:24,fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif",maxWidth:1280,height:"100%",overflowY:"auto"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:20}}>
        <div>
          <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:3}}>Audit Centre</div>
          <div style={{fontSize:13,color:"#6B7280"}}>{completed.length} completed · {audits.filter(a=>a.status==="In Progress").length} in progress · Average score: {avgScore?`${avgScore}%`:"—"}</div>
        </div>
        <button onClick={()=>setShowNew(true)} style={{display:"flex",alignItems:"center",gap:8,padding:"10px 20px",borderRadius:9,border:"none",background:"linear-gradient(135deg,#16B5B8,#0E8F92)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",boxShadow:"0 3px 12px rgba(43,191,178,0.4)"}}>
          <Icon name="onboarding" size={14} color="white" strokeWidth={2.5}/> Start New Audit
        </button>
      </div>

      {/* KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:12,marginBottom:20}}>
        {Object.entries(AUDIT_KLOE_DATA).map(([domain,d])=>{
          const latest = completed[0];
          const score  = latest?.domainScores?.[domain];
          const sc = score>=85?"#16B5B8":score>=70?"#FF9A2F":"#FF5A6E";
          const bg = score>=85?"#F0FDF4":score>=70?"#FDF8EE":"#FDF0F0";
          return(
            <div key={domain} style={{background:"#fff",borderRadius:10,padding:"14px 16px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",borderLeft:`3px solid ${d.color}`}}>
              <div style={{fontSize:11,fontWeight:500,color:"#6B7280",marginBottom:6}}>{domain}</div>
              <div style={{fontSize:24,fontWeight:800,color:score!=null?sc:"#D1D5DB",lineHeight:1}}>{score!=null?`${score}%`:"—"}</div>
              <div style={{fontSize:10,color:"#6B7280",marginTop:4}}>Latest audit</div>
            </div>
          );
        })}
      </div>

      {/* Trend chart */}
      {completed.length>=2&&(
        <div style={{background:"#fff",borderRadius:10,padding:"20px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",marginBottom:20}}>
          <div style={{fontSize:13,fontWeight:700,color:"#062B7A",marginBottom:14,display:"flex",alignItems:"center",gap:7}}>
            <Icon name="trending" size={14} color="#16B5B8" strokeWidth={2}/> Compliance Score Trend
          </div>
          <div style={{display:"flex",gap:20,alignItems:"flex-end",height:80}}>
            {[...completed].reverse().slice(0,6).map((a,i)=>{
              const pct=(a.score/100)*100;
              const color=a.score>=85?"#16B5B8":a.score>=70?"#FF9A2F":"#FF5A6E";
              return(
                <div key={a.id} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"flex-end",gap:4}}>
                  <div style={{fontSize:11,fontWeight:700,color}}>{a.score}%</div>
                  <div style={{width:"60%",background:color,borderRadius:"4px 4px 0 0",height:`${pct}%`,minHeight:8,opacity:0.85}}/>
                  <div style={{fontSize:10,color:"#6B7280",textAlign:"center",whiteSpace:"nowrap",overflow:"hidden",maxWidth:"100%"}}>{a.completedAt?.slice(5)||"—"}</div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Audit list */}
      <div style={{background:"#fff",borderRadius:10,boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",overflow:"hidden"}}>
        <div style={{padding:"14px 18px",borderBottom:"1px solid #E5E7EB",fontSize:13,fontWeight:700,color:"#062B7A",display:"flex",alignItems:"center",gap:7}}>
          <Icon name="audits" size={14} color="#16B5B8" strokeWidth={2}/> Audit History
        </div>
        {audits.map((a,i)=>{
          const sc=a.score>=85?"#16B5B8":a.score>=70?"#FF9A2F":"#FF5A6E";
          const statusConfig={"Completed":{bg:"#F0FDF4",fg:"#16B5B8"},"In Progress":{bg:"#EDF5FE",fg:"#7A57D1"},"Draft":{bg:"#F1F3F8",fg:"#6B7280"}};
          const stc=statusConfig[a.status]||statusConfig.Draft;
          return(
            <div key={a.id} style={{display:"flex",alignItems:"center",gap:14,padding:"14px 18px",borderBottom:i<audits.length-1?"1px solid #E5E7EB":"none",cursor:"pointer",transition:"background 0.12s"}}
              onMouseEnter={e=>e.currentTarget.style.background="#F8FAFC"}
              onMouseLeave={e=>e.currentTarget.style.background="#fff"}>
              <div style={{flex:1}}>
                <div style={{fontSize:13,fontWeight:600,color:"#062B7A",marginBottom:3}}>{a.name}</div>
                <div style={{fontSize:11,color:"#6B7280"}}>{a.type} · {a.conductedBy} · Started: {a.startedAt}</div>
              </div>
              {/* Domain score mini pills */}
              <div style={{display:"flex",gap:4}}>
                {Object.entries(AUDIT_KLOE_DATA).map(([d])=>{
                  const ds=a.domainScores?.[d];
                  const dcolor=ds>=85?"#16B5B8":ds>=70?"#FF9A2F":ds>=0?"#FF5A6E":"#D1D5DB";
                  return <div key={d} style={{width:8,height:8,borderRadius:"50%",background:dcolor}} title={`${d}: ${ds!=null?ds+"%":"—"}`}/>;
                })}
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                {a.score!=null?<span style={{fontSize:14,fontWeight:800,color:sc}}>{a.score}%</span>:<span style={{fontSize:12,color:"#6B7280"}}>—</span>}
                <span style={{background:stc.bg,color:stc.fg,padding:"2px 9px",borderRadius:20,fontSize:11,fontWeight:600}}>{a.status}</span>
              </div>
              <div style={{display:"flex",gap:6}}>
                {a.status==="Completed"&&(
                  <button onClick={()=>{setActive(a);setView("report");}} style={{padding:"5px 14px",borderRadius:7,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>View Report</button>
                )}
                {(a.status==="In Progress"||a.status==="Draft")&&(
                  <button onClick={()=>{setActive(a);setView("form");}} style={{padding:"5px 14px",borderRadius:7,border:"none",background:"linear-gradient(135deg,#16B5B8,#0E8F92)",color:"#fff",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Continue →</button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* New audit modal */}
      {showNew&&(
        <div style={{position:"fixed",inset:0,zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",background:"rgba(16,30,48,0.5)"}}>
          <div style={{width:480,background:"#fff",borderRadius:14,boxShadow:"0 20px 60px rgba(0,0,0,0.2)",overflow:"hidden"}}>
            <div style={{padding:"18px 24px",borderBottom:"1px solid #E5E7EB",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={{fontSize:15,fontWeight:700,color:"#062B7A"}}>Start New Audit</span>
              <button onClick={()=>setShowNew(false)} style={{background:"none",border:"none",cursor:"pointer",fontSize:22,color:"#6B7280",lineHeight:1}}>×</button>
            </div>
            <div style={{padding:"22px 24px"}}>
              <div style={{marginBottom:14}}>
                <label style={{fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.8px"}}>Audit Name</label>
                <input value={newAuditName} onChange={e=>setNewAuditName(e.target.value)}
                  placeholder="e.g. Monthly Compliance Audit — June 2026"
                  style={{width:"100%",padding:"11px 13px",borderRadius:8,border:"1.5px solid #D1D5DB",fontSize:13,color:"#062B7A",outline:"none",fontFamily:"inherit",boxSizing:"border-box"}}
                  onFocus={e=>e.target.style.borderColor="#16B5B8"}
                  onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
              </div>
              <div style={{padding:"14px",background:"#F8FAFC",borderRadius:8,marginBottom:18,fontSize:12,color:"#374151",lineHeight:1.6}}>
                This will create a full KLoE audit covering all 5 CQC domains — Safe, Effective, Caring, Responsive and Well-led — with {Object.values(AUDIT_KLOE_DATA).flatMap(d=>d.subdomains.flatMap(sd=>sd.questions)).length} questions mapped to CQC regulations.
              </div>
              <div style={{display:"flex",gap:10,justifyContent:"flex-end"}}>
                <button onClick={()=>setShowNew(false)} style={{padding:"9px 20px",borderRadius:8,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Cancel</button>
                <button disabled={!newAuditName.trim()} onClick={()=>{
                  const newAudit={
                    id:`AUD${Date.now()}`, name:newAuditName,
                    type:"Full KLoE Audit", status:"In Progress",
                    startedAt:new Date().toISOString().split("T")[0], completedAt:null,
                    conductedBy:"Sarah Mitchell", serviceName:"Sunrise Support Living",
                    careType:"Supported Living", score:null,
                    domainScores:{}, activeDomain:"Safe", answers:{},
                  };
                  setAudits(a=>[newAudit,...a]);
      if(hasSupabase()&&APP_CONFIG?.companyId!=="demo-company-001"){supabase.from("audits").insert({...newAudit,company_id:APP_CONFIG.companyId}).then(({data})=>{if(data?.[0])setAudits(a=>a.map(x=>x.id===newAudit.id?data[0]:x));});}
                  setActive(newAudit);
                  setShowNew(false);
                  setNewAuditName("");
                  setView("form");
                }} style={{padding:"9px 24px",borderRadius:8,border:"none",background:newAuditName.trim()?"linear-gradient(135deg,#16B5B8,#0E8F92)":"#D1D5DB",color:"#fff",fontSize:13,fontWeight:700,cursor:newAuditName.trim()?"pointer":"not-allowed",fontFamily:"inherit"}}>Start Audit →</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

