// ════════════════════════════════════════════════════════════════
// MOCK INSPECTION MODULE
// Simulates a full CQC inspection across all 5 KLoE domains
// Generates RAG ratings, CQC-style score, inspection report,
// and prioritised improvement action plan
// ════════════════════════════════════════════════════════════════

// CQC_RATINGS defined at module level above

function getRating(score){
  if(score===null||score===undefined) return null;
  if(score>=90) return "Outstanding";
  if(score>=75) return "Good";
  if(score>=50) return "Requires Improvement";
  return "Inadequate";
}

// Full mock inspection question bank — 8 questions per domain
// Each question has weighting, evidence prompt, and improvement text
