// REPORTS MODULE — Management Intelligence & Export Centre
// Pulls live data from all modules:
// - Compliance overview, audit trends, safeguarding summary,
//   medication trends, staff compliance, service user summary,
//   CQC readiness report, director multi-site comparison
// ════════════════════════════════════════════════════════════════

// ── Mini bar chart component ──────────────────────────────────
function MiniBar({ values, labels, colors, height=60, showValues=true }){
  const max = Math.max(...values.filter(v=>v!=null), 1);
  return(
    <div style={{display:"flex",gap:8,alignItems:"flex-end",height}}>
      {values.map((v,i)=>{
        const pct = v!=null ? (v/max)*100 : 0;
        const color = Array.isArray(colors) ? colors[i%colors.length] : colors;
        return(
          <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"flex-end",gap:3}}>
            {showValues&&v!=null&&<div style={{fontSize:10,fontWeight:700,color}}>{v}%</div>}
            <div style={{width:"100%",background:color,borderRadius:"3px 3px 0 0",height:`${Math.max(pct,4)}%`,opacity:0.85,transition:"height 0.5s"}}/>
            {labels&&<div style={{fontSize:9,color:"#6B7280",textAlign:"center",whiteSpace:"nowrap",overflow:"hidden",maxWidth:"100%"}}>{labels[i]}</div>}
          </div>
        );
      })}
    </div>
  );
}

// ── Trend arrow ───────────────────────────────────────────────
function TrendArrow({ current, previous }){
  if(current==null||previous==null) return null;
  const diff = current - previous;
  if(diff===0) return <span style={{fontSize:11,color:"#6B7280"}}>→ No change</span>;
  const up = diff>0;
  return(
    <span style={{fontSize:11,fontWeight:700,color:up?"#16B5B8":"#FF5A6E"}}>
      {up?"↑":"↓"} {Math.abs(diff)}% vs last period
    </span>
  );
}

// ── Report section wrapper ────────────────────────────────────
function ReportSection({ title, icon, subtitle, children, action }){
  return(
    <div style={{background:"#fff",borderRadius:10,boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",marginBottom:16,overflow:"hidden"}}>
      <div style={{padding:"14px 20px",borderBottom:"1px solid #E5E7EB",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div>
          <div style={{fontSize:13,fontWeight:700,color:"#062B7A",display:"flex",alignItems:"center",gap:7}}>
            <Icon name={icon} size={14} color="#16B5B8" strokeWidth={2}/>
            {title}
          </div>
          {subtitle&&<div style={{fontSize:11,color:"#6B7280",marginTop:2,paddingLeft:21}}>{subtitle}</div>}
        </div>
        {action&&<button onClick={action.fn} style={{padding:"5px 14px",borderRadius:7,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",gap:5}}>
          <Icon name="reports" size={12} color="#374151" strokeWidth={1.8}/>{action.label}
        </button>}
      </div>
      <div style={{padding:"16px 20px"}}>{children}</div>
    </div>
  );
}

// ── Stat row ──────────────────────────────────────────────────
function StatRow({ label, value, sub, color, reg, ok }){
  return(
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"9px 0",borderBottom:"1px solid #E5E7EB"}}>
      <div style={{flex:1}}>
        <div style={{fontSize:13,fontWeight:500,color:"#062B7A"}}>{label}</div>
        {sub&&<div style={{fontSize:11,color:"#6B7280",marginTop:1}}>{sub}</div>}
      </div>
      <div style={{display:"flex",gap:8,alignItems:"center"}}>
        {reg&&<RegTag reg={reg}/>}
        {ok!=null&&<VerifiedBadge ok={ok}/>}
        {value!=null&&<span style={{fontSize:13,fontWeight:700,color:color||"#062B7A"}}>{value}</span>}
      </div>
    </div>
  );
}

// ── Reports Page ──────────────────────────────────────────────
function ReportsPage({ role }){
  const [activeReport, setActiveReport] = useState("overview");
  const [printMode,    setPrintMode]    = useState(false);

  // ── Live data pulled from seeded module data ──────────────
  // Audit trend data (from INITIAL_AUDITS & INITIAL_MED_AUDITS)
  const auditTrend = [
    {month:"Feb",overall:72,safe:68,effective:76,caring:88,responsive:71,wellLed:74},
    {month:"Mar",overall:76,safe:72,effective:80,caring:89,responsive:74,wellLed:78},
    {month:"Apr",overall:79,safe:75,effective:82,caring:90,responsive:74,wellLed:78},
    {month:"May",overall:84,safe:81,effective:88,caring:92,responsive:79,wellLed:83},
  ];
  const latestAudit  = auditTrend[auditTrend.length-1];
  const previousAudit= auditTrend[auditTrend.length-2];

  // Medication trend
  const medTrend = [
    {month:"Jan",score:72,errors:8,highSeverity:1},
    {month:"Feb",score:78,errors:6,highSeverity:0},
    {month:"Mar",score:81,errors:5,highSeverity:0},
    {month:"Apr",score:79,errors:4,highSeverity:1},
    {month:"May",score:94,errors:4,highSeverity:0},
  ];

  // Staff compliance summary
  const staffCompliance = {
    total:5, active:5,
    dbsValid:3, dbsExpired:2, dbsExpiring:0,
    trainingCurrent:18, trainingExpired:2, trainingExpiring:1,
    supervisionOnSchedule:4, supervisionOverdue:1,
    appraisalComplete:4, appraisalOverdue:1,
    competencyChecksComplete:5, competencyChecksPending:1,
  };

  // Service user summary
  const suCompliance = {
    total:2, active:2,
    carePlansCurrent:2, carePlansOverdue:0, carePlansReviewDue:1,
    riskAssessmentsCurrent:5, riskAssessmentsOverdue:2,
    mentalCapacityAssessed:2, dolsInPlace:1, dolsExpiringSoon:0,
    goalsAchievedThisQuarter:1, goalsInProgress:5,
    openComplaints:0, complaintsResolvedOnTime:1,
    openSafeguarding:1, safeguardingResolvedThisMonth:2,
  };

  // Mock inspection
  const latestMock = INITIAL_MOCK_INSPECTIONS[0];
  const {domainScores: mockDomainScores, overall: mockOverall} = computeInspectionScores(latestMock.answers);
  const mockRating = getRating(mockOverall);

  // CQC readiness score — composite
  const cqcReadiness = Math.round([
    latestAudit.overall,
    medTrend[medTrend.length-1].score,
    mockOverall||0,
    staffCompliance.dbsValid/staffCompliance.total*100,
    staffCompliance.trainingCurrent/(staffCompliance.trainingCurrent+staffCompliance.trainingExpired)*100,
  ].reduce((a,b)=>a+b,0)/5);

  const REPORT_TABS = [
    {id:"overview",    label:"Compliance Overview",     icon:"dashboard"},
    {id:"audits",      label:"Audit Trends",            icon:"audits"},
    {id:"medication",  label:"Medication Trends",       icon:"medication"},
    {id:"staff",       label:"Staff Compliance",        icon:"staff"},
    {id:"serviceusers",label:"Service User Compliance", icon:"serviceusers"},
    {id:"safeguarding",label:"Safeguarding Summary",    icon:"shield"},
    {id:"mock",        label:"Mock Inspection Summary", icon:"mock"},
    {id:"cqcreadiness",label:"CQC Readiness Report",    icon:"shield"},
    ...(role==="director"||role==="superadmin"?[{id:"multisite",label:"Multi-Site Comparison",icon:"multisite"}]:[]),
  ];

  const domainColors = {Safe:"#FF5A6E",Effective:"#FF9A2F",Caring:"#16B5B8",Responsive:"#7A57D1","Well-led":"#7A57D1"};

  return(
    <div style={{display:"flex",height:"100%",fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif",overflow:"hidden"}}>
      {/* Left nav */}
      <div style={{width:220,background:"#fff",borderRight:"1px solid #E5E7EB",overflowY:"auto",flexShrink:0}}>
        <div style={{padding:"16px 14px 10px"}}>
          <div style={{fontSize:11,fontWeight:700,color:"#6B7280",letterSpacing:"1px",textTransform:"uppercase",marginBottom:10}}>Reports</div>
          {REPORT_TABS.map(t=>(
            <button key={t.id} onClick={()=>setActiveReport(t.id)} style={{
              display:"flex",alignItems:"center",gap:8,width:"100%",
              padding:"8px 10px",borderRadius:7,border:"none",
              background:activeReport===t.id?"rgba(43,191,178,0.1)":"transparent",
              color:activeReport===t.id?"#0E8F92":"#374151",
              fontWeight:activeReport===t.id?700:400,fontSize:13,
              cursor:"pointer",fontFamily:"inherit",marginBottom:1,
              borderLeft:activeReport===t.id?"2px solid #16B5B8":"2px solid transparent",
              textAlign:"left",
            }}>
              <Icon name={t.icon} size={13} color={activeReport===t.id?"#16B5B8":"#6B7280"} strokeWidth={activeReport===t.id?2:1.5}/>
              {t.label}
            </button>
          ))}
        </div>
      </div>

      {/* Report content */}
      <div style={{flex:1,overflowY:"auto",padding:"22px",background:"#F8FAFC"}}>
        <div style={{maxWidth:1000}}>

          {/* ── COMPLIANCE OVERVIEW ── */}
          {activeReport==="overview"&&(
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:4}}>Compliance Overview</div>
              <div style={{fontSize:13,color:"#6B7280",marginBottom:20}}>Real-time summary of compliance across all service areas · {new Date().toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"})}</div>

              {/* Top KPI row */}
              <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:14,marginBottom:20}}>
                {[
                  {label:"Overall Compliance",    value:`${latestAudit.overall}%`, color:latestAudit.overall>=85?"#16B5B8":latestAudit.overall>=70?"#FF9A2F":"#FF5A6E", sub:<TrendArrow current={latestAudit.overall} previous={previousAudit.overall}/>, icon:"shield"},
                  {label:"CQC Readiness Score",   value:`${cqcReadiness}%`,        color:cqcReadiness>=85?"#16B5B8":cqcReadiness>=70?"#FF9A2F":"#FF5A6E",              sub:<RAGChip rating={getRating(cqcReadiness)}/>,       icon:"mock"},
                  {label:"Open Action Items",      value:INITIAL_TASKS.filter(t=>t.done===false).length, color:"#FF9A2F", sub:"Across all modules", icon:"tasks"},
                  {label:"Staff Compliance Rate",  value:`${Math.round((staffCompliance.dbsValid/staffCompliance.total)*100)}%`, color:"#16B5B8", sub:`${staffCompliance.dbsExpired} DBS expired`, icon:"staff"},
                ].map((k,i)=>(
                  <div key={i} style={{background:"#fff",borderRadius:10,padding:"16px 18px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",borderLeft:`3px solid ${k.color}`}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
                      <span style={{fontSize:11,fontWeight:500,color:"#6B7280"}}>{k.label}</span>
                      <div style={{width:28,height:28,borderRadius:7,background:`${k.color}15`,display:"flex",alignItems:"center",justifyContent:"center"}}>
                        <Icon name={k.icon} size={13} color={k.color} strokeWidth={1.8}/>
                      </div>
                    </div>
                    <div style={{fontSize:26,fontWeight:800,color:k.color,lineHeight:1,marginBottom:5}}>{k.value}</div>
                    <div style={{fontSize:11}}>{k.sub}</div>
                  </div>
                ))}
              </div>

              {/* KLoE scores */}
              <ReportSection title="KLoE Domain Scores — Latest Audit" icon="audits" subtitle="May 2026 · Click Audit Trends for full history">
                <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10,marginBottom:16}}>
                  {Object.entries(domainColors).map(([domain,color])=>{
                    const score = latestAudit[domain.toLowerCase().replace("-","").replace(" ","").replace("well","wellLed").replace("led","")];
                    const s = latestAudit[{Safe:"safe",Effective:"effective",Caring:"caring",Responsive:"responsive","Well-led":"wellLed"}[domain]];
                    const rating = getRating(s);
                    return(
                      <div key={domain} style={{textAlign:"center",padding:"14px 8px",background:CQC_RATINGS[rating]?.bg||"#F1F3F8",borderRadius:8,border:`1px solid ${color}22`}}>
                        <div style={{fontSize:11,fontWeight:700,color:"#374151",marginBottom:4}}>{domain}</div>
                        <div style={{fontSize:24,fontWeight:800,color,lineHeight:1,marginBottom:5}}>{s}%</div>
                        <RAGChip rating={rating}/>
                      </div>
                    );
                  })}
                </div>
                <MiniBar
                  values={[latestAudit.safe,latestAudit.effective,latestAudit.caring,latestAudit.responsive,latestAudit.wellLed]}
                  labels={["Safe","Effective","Caring","Responsive","Well-led"]}
                  colors={Object.values(domainColors)}
                  height={80}/>
              </ReportSection>

              {/* Compliance snapshot grid */}
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:16}}>
                <ReportSection title="Staff Compliance Snapshot" icon="staff" subtitle="Current status across all staff records">
                  <StatRow label="DBS — Valid"              value={staffCompliance.dbsValid}      color="#16B5B8" sub="Certificates current"/>
                  <StatRow label="DBS — Expired"            value={staffCompliance.dbsExpired}     color={staffCompliance.dbsExpired>0?"#FF5A6E":"#16B5B8"} sub="Require immediate renewal"/>
                  <StatRow label="Training — All current"   ok={staffCompliance.trainingExpired===0} sub={`${staffCompliance.trainingExpired} expired, ${staffCompliance.trainingExpiring} expiring`}/>
                  <StatRow label="Supervisions on schedule" ok={staffCompliance.supervisionOverdue===0} sub={`${staffCompliance.supervisionOverdue} overdue`}/>
                  <StatRow label="Annual appraisals complete" ok={staffCompliance.appraisalOverdue===0} sub={`${staffCompliance.appraisalOverdue} overdue`}/>
                </ReportSection>

                <ReportSection title="Service User Compliance Snapshot" icon="serviceusers" subtitle="Current status across all service user records">
                  <StatRow label="Care plans — current"         ok={suCompliance.carePlansOverdue===0}  sub={`${suCompliance.carePlansCurrent} current · ${suCompliance.carePlansReviewDue} review due`}/>
                  <StatRow label="Risk assessments — current"   ok={suCompliance.riskAssessmentsOverdue===0} sub={`${suCompliance.riskAssessmentsOverdue} overdue`}/>
                  <StatRow label="Mental capacity assessed"      ok={true} sub={`${suCompliance.mentalCapacityAssessed} assessments on record`}/>
                  <StatRow label="DoLS in place (where needed)"  ok={true} sub={`${suCompliance.dolsInPlace} authorised`}/>
                  <StatRow label="Open complaints"               ok={suCompliance.openComplaints===0} value={suCompliance.openComplaints} color={suCompliance.openComplaints>0?"#FF5A6E":"#16B5B8"}/>
                </ReportSection>
              </div>

              {/* Alerts requiring action */}
              <ReportSection title="Items Requiring Immediate Attention" icon="alert" subtitle="Cross-module compliance alerts">
                {[
                  {msg:"DBS expired — Maria Johnson",              priority:"High",   module:"Staff Records",      reg:"Reg 19"},
                  {msg:"DBS expired — Rachel Davies",              priority:"High",   module:"Staff Records",      reg:"Reg 19"},
                  {msg:"Risk assessment overdue — SU02 (Nutrition)",priority:"Medium", module:"Service Users",      reg:"Reg 12"},
                  {msg:"Supervision overdue — Tom Patel",          priority:"Medium", module:"Staff Records",      reg:"Reg 18"},
                  {msg:"Open safeguarding concern — SU01",         priority:"Medium", module:"Safeguarding",       reg:"Reg 13"},
                  {msg:"Care plan review due — SU01 (Sept 2026)",  priority:"Low",    module:"Service Users",      reg:"Reg 9"},
                  {msg:"Prevent training expiring — Sarah Mitchell",priority:"Low",   module:"Staff Records",      reg:"Reg 13"},
                ].map((a,i)=>{
                  const pc=severityColor(a.priority);
                  return(
                    <div key={i} style={{display:"flex",gap:10,padding:"9px 0",borderBottom:"1px solid #E5E7EB",alignItems:"center"}}>
                      <span style={{background:pc.bg,color:pc.fg,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700,flexShrink:0}}>{a.priority}</span>
                      <span style={{flex:1,fontSize:12,color:"#062B7A"}}>{a.msg}</span>
                      <span style={{fontSize:11,color:"#6B7280"}}>{a.module}</span>
                      <RegTag reg={a.reg}/>
                    </div>
                  );
                })}
              </ReportSection>
            </div>
          )}

          {/* ── AUDIT TRENDS ── */}
          {activeReport==="audits"&&(
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:4}}>Audit Trends</div>
              <div style={{fontSize:13,color:"#6B7280",marginBottom:20}}>KLoE compliance scores over time — monthly audits</div>

              <ReportSection title="Overall Compliance Score — 4 Month Trend" icon="trending">
                <MiniBar values={auditTrend.map(a=>a.overall)} labels={auditTrend.map(a=>a.month)} colors={auditTrend.map(a=>a.overall>=85?"#16B5B8":a.overall>=75?"#7A57D1":a.overall>=50?"#FF9A2F":"#FF5A6E")} height={100}/>
                <div style={{display:"flex",gap:14,marginTop:12,flexWrap:"wrap"}}>
                  {auditTrend.map((a,i)=>(
                    <div key={i} style={{padding:"8px 12px",background:"#F8FAFC",borderRadius:8,textAlign:"center"}}>
                      <div style={{fontSize:14,fontWeight:800,color:a.overall>=85?"#16B5B8":a.overall>=75?"#7A57D1":"#FF9A2F"}}>{a.overall}%</div>
                      <div style={{fontSize:10,color:"#6B7280"}}>{a.month}</div>
                      <RAGChip rating={getRating(a.overall)}/>
                    </div>
                  ))}
                </div>
              </ReportSection>

              <ReportSection title="Domain Scores by Month" icon="audits">
                <table style={{width:"100%",borderCollapse:"collapse"}}>
                  <thead>
                    <tr style={{background:"#F8FAFC"}}>
                      {["Month","Safe","Effective","Caring","Responsive","Well-led","Overall"].map(h=>(
                        <th key={h} style={{padding:"9px 12px",fontSize:11,fontWeight:700,color:"#6B7280",textAlign:"center",textTransform:"uppercase",letterSpacing:"0.5px",borderBottom:"1px solid #E5E7EB"}}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {auditTrend.map((a,i)=>(
                      <tr key={i} style={{borderBottom:"1px solid #E5E7EB",background:i===auditTrend.length-1?"#F0FBFA":"#fff"}}>
                        <td style={{padding:"11px 12px",fontSize:13,fontWeight:i===auditTrend.length-1?700:500,color:"#062B7A",textAlign:"center"}}>{a.month}{i===auditTrend.length-1?" ★":""}</td>
                        {[a.safe,a.effective,a.caring,a.responsive,a.wellLed,a.overall].map((score,si)=>(
                          <td key={si} style={{padding:"11px 12px",textAlign:"center"}}>
                            <span style={{fontSize:13,fontWeight:700,color:[...Object.values(domainColors),"#062B7A"][si]}}>{score}%</span>
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
                <div style={{marginTop:12,fontSize:11,color:"#6B7280"}}>★ Latest audit · All scores are percentage compliance from monthly KLoE audits</div>
              </ReportSection>

              <ReportSection title="Trend Analysis & Commentary" icon="reports">
                {[
                  {domain:"Safe",     trend:"↑ Improving",  color:"#16B5B8", comment:"Safe score has improved from 68% to 81% over 4 months. Key drivers: medication audit improvements, DBS renewal process strengthened. Outstanding items: 2 expired DBS certificates require immediate action."},
                  {domain:"Effective",trend:"↑ Improving",  color:"#16B5B8", comment:"Effective score improving steadily. Care plan completion and mental capacity documentation are strong. Supervision frequency needs monitoring."},
                  {domain:"Caring",   trend:"→ Stable",     color:"#7A57D1", comment:"Caring domain remains the strongest area — consistently above 88%. Staff demonstrate genuine compassion and person-centred values. This is an area of outstanding practice."},
                  {domain:"Responsive",trend:"↑ Improving", color:"#16B5B8", comment:"Responsive score improving but still the lowest domain. Complaint handling is good. Service user feedback mechanisms need formalising. One unplanned review was missed after a hospital discharge."},
                  {domain:"Well-led", trend:"↑ Improving",  color:"#16B5B8", comment:"Well-led scores improving. Governance structure strengthening. Staff survey and residents/family meetings are outstanding actions. Leadership is visible and engaged."},
                ].map((item,i)=>(
                  <div key={i} style={{padding:"11px 0",borderBottom:i<4?"1px solid #E5E7EB":"none",display:"flex",gap:12,alignItems:"flex-start"}}>
                    <div style={{display:"flex",alignItems:"center",gap:6,minWidth:130}}>
                      <KloeTag domain={item.domain}/>
                      <span style={{fontSize:11,fontWeight:700,color:item.color}}>{item.trend}</span>
                    </div>
                    <div style={{fontSize:12,color:"#374151",lineHeight:1.6,flex:1}}>{item.comment}</div>
                  </div>
                ))}
              </ReportSection>
            </div>
          )}

          {/* ── MEDICATION TRENDS ── */}
          {activeReport==="medication"&&(
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:4}}>Medication Trends</div>
              <div style={{fontSize:13,color:"#6B7280",marginBottom:20}}>Monthly MAR audit scores and error tracking · Reg 12</div>

              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:14,marginBottom:16}}>
                {[
                  {label:"Latest MAR Score",value:`${medTrend[medTrend.length-1].score}%`, color:medTrend[medTrend.length-1].score>=90?"#16B5B8":"#FF9A2F", sub:<TrendArrow current={medTrend[medTrend.length-1].score} previous={medTrend[medTrend.length-2].score}/>},
                  {label:"Total Errors YTD", value:medTrend.reduce((s,m)=>s+m.errors,0),    color:"#FF9A2F", sub:"Across all months"},
                  {label:"High Severity",    value:medTrend.reduce((s,m)=>s+m.highSeverity,0),color:medTrend.reduce((s,m)=>s+m.highSeverity,0)>0?"#FF5A6E":"#16B5B8",sub:"Requiring GP/CQC notification"},
                ].map((k,i)=>(
                  <div key={i} style={{background:"#fff",borderRadius:10,padding:"16px 18px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",borderLeft:`3px solid ${k.color}`}}>
                    <div style={{fontSize:11,fontWeight:500,color:"#6B7280",marginBottom:6}}>{k.label}</div>
                    <div style={{fontSize:26,fontWeight:800,color:k.color,lineHeight:1,marginBottom:5}}>{k.value}</div>
                    <div style={{fontSize:11}}>{k.sub}</div>
                  </div>
                ))}
              </div>

              <ReportSection title="MAR Audit Score Trend" icon="medication">
                <MiniBar values={medTrend.map(m=>m.score)} labels={medTrend.map(m=>m.month)} colors={medTrend.map(m=>m.score>=90?"#16B5B8":m.score>=75?"#7A57D1":"#FF9A2F")} height={80}/>
              </ReportSection>

              <ReportSection title="Monthly Error Summary" icon="alert">
                <table style={{width:"100%",borderCollapse:"collapse"}}>
                  <thead>
                    <tr style={{background:"#F8FAFC"}}>
                      {["Month","MAR Score","Errors Recorded","High Severity","Trend"].map(h=>(
                        <th key={h} style={{padding:"9px 12px",fontSize:11,fontWeight:700,color:"#6B7280",textAlign:"left",textTransform:"uppercase",letterSpacing:"0.5px",borderBottom:"1px solid #E5E7EB"}}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {medTrend.map((m,i)=>(
                      <tr key={i} style={{borderBottom:"1px solid #E5E7EB",background:i===medTrend.length-1?"#F0FBFA":"#fff"}}>
                        <td style={{padding:"11px 12px",fontSize:13,fontWeight:500,color:"#062B7A"}}>{m.month}</td>
                        <td style={{padding:"11px 12px"}}><span style={{fontSize:13,fontWeight:700,color:m.score>=90?"#16B5B8":m.score>=75?"#7A57D1":"#FF9A2F"}}>{m.score}%</span></td>
                        <td style={{padding:"11px 12px",fontSize:13,color:m.errors>5?"#FF9A2F":"#062B7A"}}>{m.errors}</td>
                        <td style={{padding:"11px 12px"}}>{m.highSeverity>0?<span style={{background:"#FDF0F0",color:"#FF5A6E",padding:"2px 8px",borderRadius:20,fontSize:11,fontWeight:700}}>{m.highSeverity} High</span>:<span style={{background:"#F0FDF4",color:"#16B5B8",padding:"2px 8px",borderRadius:20,fontSize:11,fontWeight:600}}>None</span>}</td>
                        <td style={{padding:"11px 12px"}}>{i>0&&<TrendArrow current={m.score} previous={medTrend[i-1].score}/>}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </ReportSection>
            </div>
          )}

          {/* ── STAFF COMPLIANCE ── */}
          {activeReport==="staff"&&(
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:4}}>Staff Compliance Report</div>
              <div style={{fontSize:13,color:"#6B7280",marginBottom:20}}>DBS, training, supervision, appraisal and competency compliance · Reg 18, 19</div>

              <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:16}}>
                {[
                  {l:"Total Staff",     v:staffCompliance.total,          c:"#062B7A"},
                  {l:"DBS Valid",       v:`${staffCompliance.dbsValid}/${staffCompliance.total}`, c:staffCompliance.dbsExpired>0?"#FF5A6E":"#16B5B8"},
                  {l:"Training Current",v:`${staffCompliance.trainingCurrent}`,c:staffCompliance.trainingExpired>0?"#FF9A2F":"#16B5B8"},
                  {l:"Supervisions OK", v:`${staffCompliance.supervisionOnSchedule}/${staffCompliance.total}`, c:staffCompliance.supervisionOverdue>0?"#FF9A2F":"#16B5B8"},
                ].map((k,i)=>(
                  <div key={i} style={{background:"#fff",borderRadius:10,padding:"14px 16px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)"}}>
                    <div style={{fontSize:11,color:"#6B7280",marginBottom:4}}>{k.l}</div>
                    <div style={{fontSize:22,fontWeight:800,color:k.c,lineHeight:1}}>{k.v}</div>
                  </div>
                ))}
              </div>

              <ReportSection title="DBS Compliance" icon="safeguarding" subtitle="Reg 19 — All staff must hold a current DBS certificate">
                {INITIAL_STAFF.map((s,i)=>{
                  const dbs = s.dbs;
                  const exp = expiryLabel(dbs.expiryDate);
                  return(
                    <div key={s.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"9px 0",borderBottom:i<INITIAL_STAFF.length-1?"1px solid #E5E7EB":"none"}}>
                      <div style={{display:"flex",alignItems:"center",gap:10}}>
                        <div style={{width:28,height:28,borderRadius:"50%",background:"linear-gradient(135deg,#16B5B8,#062B7A)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700,color:"#fff"}}>{s.firstName[0]}{s.lastName[0]}</div>
                        <div><div style={{fontSize:13,fontWeight:500,color:"#062B7A"}}>{s.firstName} {s.lastName}</div><div style={{fontSize:11,color:"#6B7280"}}>{s.role}</div></div>
                      </div>
                      <div style={{display:"flex",gap:8,alignItems:"center"}}>
                        <span style={{fontSize:11,color:"#6B7280"}}>Expires: {dbs.expiryDate}</span>
                        <ExpiryTag date={dbs.expiryDate}/>
                        {dbs.updateService&&<span style={{background:"#EDF5FE",color:"#7A57D1",padding:"2px 7px",borderRadius:20,fontSize:10,fontWeight:600}}>Update Service</span>}
                      </div>
                    </div>
                  );
                })}
              </ReportSection>

              <ReportSection title="Training Compliance Summary" icon="audits" subtitle="Reg 18 — Mandatory training must be completed within required timeframes">
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:14}}>
                  {[["Current",staffCompliance.trainingCurrent,"#16B5B8"],["Expired",staffCompliance.trainingExpired,"#FF5A6E"],["Expiring Soon",staffCompliance.trainingExpiring,"#FF9A2F"]].map(([l,v,c])=>(
                    <div key={l} style={{textAlign:"center",padding:"12px",background:"#F8FAFC",borderRadius:8}}>
                      <div style={{fontSize:22,fontWeight:800,color:c,lineHeight:1}}>{v}</div>
                      <div style={{fontSize:11,color:"#6B7280",marginTop:3}}>{l}</div>
                    </div>
                  ))}
                </div>
                <StatRow label="Safeguarding training (all levels)" ok={true}  sub="All staff hold appropriate level" reg="Reg 13"/>
                <StatRow label="Medication competency"              ok={true}  sub="All administering staff assessed" reg="Reg 12"/>
                <StatRow label="Mental Capacity Act"                ok={true}  sub="Key staff trained"                reg="Reg 11"/>
                <StatRow label="Fire safety"                        ok={false} sub="2 staff — expiring within 3 months" reg="Reg 12"/>
                <StatRow label="Prevent awareness"                  ok={false} sub="Sarah Mitchell — expiring 9 Sept 2026" reg="Reg 13"/>
              </ReportSection>

              <ReportSection title="Supervision & Appraisal" icon="calendar" subtitle="Reg 18 — Supervision every 8 weeks minimum, annual appraisal required">
                <StatRow label="Supervision on schedule" ok={staffCompliance.supervisionOverdue===0} sub={`${staffCompliance.supervisionOverdue} overdue — Tom Patel supervision is 3 weeks late`} reg="Reg 18"/>
                <StatRow label="Annual appraisals complete" ok={staffCompliance.appraisalOverdue===0} sub={`${staffCompliance.appraisalOverdue} outstanding`} reg="Reg 18"/>
                <StatRow label="Probation reviews complete" ok={true} sub="All new starters within probation reviewed on schedule" reg="Reg 18"/>
              </ReportSection>
            </div>
          )}

          {/* ── SERVICE USER COMPLIANCE ── */}
          {activeReport==="serviceusers"&&(
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:4}}>Service User Compliance Report</div>
              <div style={{fontSize:13,color:"#6B7280",marginBottom:20}}>Care plan, risk assessment, mental capacity, goals and outcomes compliance · Reg 9, 11, 12</div>

              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:16}}>
                <ReportSection title="Care Plan Compliance" icon="tasks" subtitle="Reg 9 — Care plans must be reviewed at least 6-monthly">
                  <StatRow label="Care plans — current and signed"  ok={true}  sub="Both service users have current, signed care plans"/>
                  <StatRow label="Next review due within 30 days"   ok={false} sub="Arthur Mensah — review due September 2026"/>
                  <StatRow label="Personal history section complete" ok={true}  sub="Documented for all service users"/>
                  <StatRow label="Communication needs documented"   ok={true}  sub="Including specific communication tools for Dorothy"/>
                  <StatRow label="Service user involved in review"  ok={true}  sub="Evidenced in review records"/>
                  <StatRow label="Family/representative involved"   ok={true}  sub="Families present at all recent reviews"/>
                </ReportSection>

                <ReportSection title="Risk Assessment Compliance" icon="alert" subtitle="Reg 12 — All risks must be identified, assessed and mitigated">
                  <StatRow label="Risk assessments in place"        ok={true}  sub="7 risk assessments across 2 service users"/>
                  <StatRow label="High/critical risks documented"   ok={true}  sub="4 high/critical risk assessments with interventions"/>
                  <StatRow label="Reviews on schedule"              ok={false} sub="2 risk assessments are overdue for review"/>
                  <StatRow label="Interventions documented"        ok={true}  sub="All risk assessments include intervention plans"/>
                  <StatRow label="Post-incident risk review done"  ok={true}  sub="Reviews completed after AF episode and wound care incident"/>
                </ReportSection>
              </div>

              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:16}}>
                <ReportSection title="Mental Capacity & DoLS" icon="safeguarding" subtitle="Reg 11 — MCA assessments required for all significant decisions">
                  <StatRow label="MCA assessments completed"    ok={true}  sub="Both service users have documented assessments"/>
                  <StatRow label="Best interest decisions recorded" ok={true} sub="Documented for Dorothy — 2 formal BID on record"/>
                  <StatRow label="DoLS applications made"       ok={true}  sub="DoLS in place for Dorothy Okafor"/>
                  <StatRow label="DoLS expiry monitored"        ok={true}  sub="Expires January 2027 — renewal reminder set"/>
                  <StatRow label="LPA arrangements documented"  ok={true}  sub="Both service users have LPA arrangements on file"/>
                  <StatRow label="DNACPR documented"            ok={true}  sub="Both service users have documented CPR status"/>
                </ReportSection>

                <ReportSection title="Goals & Outcomes" icon="trending" subtitle="Reg 9 — Outcomes must be person-centred and evidenced">
                  <StatRow label="Goals in place for all SUs"   ok={true}  sub="6 goals across 2 service users"/>
                  <StatRow label="Goals achieved this quarter"  value={suCompliance.goalsAchievedThisQuarter} color="#16B5B8" sub="Arthur Mensah — church attendance goal"/>
                  <StatRow label="Goals in progress"           value={suCompliance.goalsInProgress}          color="#7A57D1" sub="Weight management, wound care, activities"/>
                  <StatRow label="Evidence of progress recorded" ok={true} sub="Progress notes on all active goals"/>
                  <StatRow label="Goals reviewed at care plan review" ok={true} sub="Evidenced in review records"/>
                </ReportSection>
              </div>

              <ReportSection title="Communication & Family Involvement" icon="bell" subtitle="Reg 9, 16 — Evidence of involvement and responsive communication">
                <StatRow label="Communication logs maintained"      ok={true}  sub="All professional contacts logged with follow-up actions"/>
                <StatRow label="Family visits/contacts recorded"    ok={true}  sub="Family contact evidenced for both service users"/>
                <StatRow label="Complaints resolved within 20 days" ok={true}  sub="1 complaint received and resolved on time"/>
                <StatRow label="Compliments recorded and shared"    ok={true}  sub="1 formal compliment — shared with staff team"/>
                <StatRow label="Hospital admissions documented"     ok={true}  sub="1 admission — family notified, care plan updated"/>
              </ReportSection>
            </div>
          )}

          {/* ── SAFEGUARDING SUMMARY ── */}
          {activeReport==="safeguarding"&&(
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:4}}>Safeguarding Summary Report</div>
              <div style={{fontSize:13,color:"#6B7280",marginBottom:20}}>Service-level safeguarding overview · Reg 13</div>

              <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:16}}>
                {[
                  {l:"Total Concerns YTD",    v:INITIAL_SG_CONCERNS.length,                                      c:"#062B7A"},
                  {l:"Currently Open",        v:INITIAL_SG_CONCERNS.filter(c=>c.status==="Open").length,         c:"#FF5A6E"},
                  {l:"Referred to LA",        v:INITIAL_SG_CONCERNS.filter(c=>c.referredExternally).length,      c:"#7A57D1"},
                  {l:"Closed with Learning",  v:INITIAL_SG_CONCERNS.filter(c=>c.status==="Closed"&&c.learningAndActions).length, c:"#16B5B8"},
                ].map((k,i)=>(
                  <div key={i} style={{background:"#fff",borderRadius:10,padding:"14px 16px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",borderLeft:`3px solid ${k.c}`}}>
                    <div style={{fontSize:11,color:"#6B7280",marginBottom:4}}>{k.l}</div>
                    <div style={{fontSize:24,fontWeight:800,color:k.c,lineHeight:1}}>{k.v}</div>
                  </div>
                ))}
              </div>

              <ReportSection title="Concern Type Analysis" icon="shield">
                {Object.entries(INITIAL_SG_CONCERNS.reduce((acc,c)=>{acc[c.concernType]=(acc[c.concernType]||0)+1;return acc;},{})).map(([type,count],i,arr)=>(
                  <div key={type} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 0",borderBottom:i<arr.length-1?"1px solid #E5E7EB":"none"}}>
                    <span style={{fontSize:12,color:"#062B7A"}}>{type}</span>
                    <div style={{display:"flex",alignItems:"center",gap:8}}>
                      <div style={{width:80,height:5,background:"#E5E7EB",borderRadius:3}}><div style={{height:"100%",width:`${(count/INITIAL_SG_CONCERNS.length)*100}%`,background:"#16B5B8",borderRadius:3}}/></div>
                      <span style={{fontSize:12,fontWeight:700,color:"#062B7A",minWidth:16}}>{count}</span>
                    </div>
                  </div>
                ))}
              </ReportSection>

              <ReportSection title="Safeguarding Compliance Checklist" icon="tasks" subtitle="Reg 13 — Evidence required for CQC inspection">
                <StatRow label="Named safeguarding lead in post"              ok={true}  sub="Sarah Mitchell — Level 3 trained" reg="Reg 13"/>
                <StatRow label="Safeguarding policy current and reviewed"    ok={true}  sub="Reviewed January 2026" reg="Reg 13"/>
                <StatRow label="All staff trained to appropriate level"       ok={true}  sub="All training records current" reg="Reg 13"/>
                <StatRow label="Referrals made to LA without delay"          ok={true}  sub="Both external referrals made on day of concern" reg="Reg 13"/>
                <StatRow label="Learning shared with staff from all cases"   ok={true}  sub="Learning documented on closed cases" reg="Reg 13"/>
                <StatRow label="Open concerns being actively managed"        ok={false} sub="SG/2026/003 open — low-level concern under investigation" reg="Reg 13"/>
                <StatRow label="CQC notified where required"                 ok={true}  sub="No cases required CQC notification" reg="Reg 18"/>
              </ReportSection>
            </div>
          )}

          {/* ── MOCK INSPECTION SUMMARY ── */}
          {activeReport==="mock"&&(
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:4}}>Mock Inspection Summary</div>
              <div style={{fontSize:13,color:"#6B7280",marginBottom:20}}>Latest mock inspection results and improvement progress</div>

              <div style={{background:"#fff",borderRadius:12,padding:"20px",marginBottom:16,boxShadow:"0 2px 8px rgba(0,0,0,0.06)",border:`2px solid ${CQC_RATINGS[mockRating]?.color+"33"}`}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
                  <div>
                    <div style={{fontSize:15,fontWeight:800,color:"#062B7A",marginBottom:2}}>{latestMock.name}</div>
                    <div style={{fontSize:12,color:"#6B7280"}}>{latestMock.conductedDate} · {latestMock.conductedBy}</div>
                  </div>
                  <div style={{textAlign:"center"}}>
                    <div style={{fontSize:36,fontWeight:900,color:CQC_RATINGS[mockRating]?.color,lineHeight:1,marginBottom:4}}>{mockOverall}%</div>
                    <RAGChip rating={mockRating} size="large"/>
                  </div>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:8}}>
                  {Object.keys(MOCK_QUESTIONS).map(domain=>{
                    const score=mockDomainScores[domain];
                    const rating=getRating(score);
                    const cfg=CQC_RATINGS[rating];
                    return(
                      <div key={domain} style={{textAlign:"center",padding:"10px 6px",background:cfg?.bg||"#F1F3F8",borderRadius:8,border:`1px solid ${cfg?.color+"33"||"#D1D5DB"}`}}>
                        <div style={{fontSize:10,fontWeight:700,color:"#374151",marginBottom:3}}>{domain}</div>
                        <div style={{fontSize:18,fontWeight:800,color:cfg?.color||"#D1D5DB",lineHeight:1,marginBottom:3}}>{score!=null?`${score}%`:"—"}</div>
                        {rating&&<RAGChip rating={rating}/>}
                      </div>
                    );
                  })}
                </div>
              </div>

              <ReportSection title="Generated Improvement Actions" icon="tasks" subtitle="Auto-generated from mock inspection responses">
                {generateActions(latestMock.answers).slice(0,10).map((action,i)=>{
                  const pc=severityColor(action.priority);
                  return(
                    <div key={i} style={{padding:"10px 0",borderBottom:i<9?"1px solid #E5E7EB":"none",display:"flex",gap:10,alignItems:"flex-start"}}>
                      <span style={{background:pc.bg,color:pc.fg,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700,flexShrink:0,marginTop:1}}>{action.priority}</span>
                      <div style={{flex:1}}>
                        <div style={{fontSize:12,fontWeight:500,color:"#062B7A",marginBottom:2}}>{action.question}</div>
                        <div style={{fontSize:11,color:"#0E8F92"}}>{action.improvement.slice(0,100)}…</div>
                      </div>
                      <div style={{display:"flex",gap:4,flexShrink:0}}><KloeTag domain={action.domain}/><RegTag reg={action.reg}/></div>
                    </div>
                  );
                })}
                <div style={{marginTop:10,fontSize:12,color:"#6B7280"}}>Showing top 10 of {generateActions(latestMock.answers).length} total actions. Go to Mock Inspection → Report to see the full action plan.</div>
              </ReportSection>
            </div>
          )}

          {/* ── CQC READINESS REPORT ── */}
          {activeReport==="cqcreadiness"&&(
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:4}}>CQC Readiness Report</div>
              <div style={{fontSize:13,color:"#6B7280",marginBottom:20}}>Comprehensive inspection readiness assessment — can be shared with directors and CQC</div>

              {/* Overall readiness */}
              <div style={{background:"#fff",borderRadius:12,padding:"24px",marginBottom:16,boxShadow:"0 2px 8px rgba(0,0,0,0.06)",border:`2px solid ${CQC_RATINGS[getRating(cqcReadiness)]?.color+"33"}`}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
                  <div>
                    <div style={{fontSize:11,fontWeight:700,color:"#6B7280",textTransform:"uppercase",letterSpacing:"1px",marginBottom:4}}>Overall CQC Readiness</div>
                    <div style={{fontSize:18,fontWeight:800,color:"#062B7A",marginBottom:2}}>Sunrise Support Living</div>
                    <div style={{fontSize:12,color:"#6B7280"}}>Supported Living · Assessment date: {TODAY}</div>
                  </div>
                  <div style={{textAlign:"center"}}>
                    <div style={{fontSize:44,fontWeight:900,color:CQC_RATINGS[getRating(cqcReadiness)]?.color,lineHeight:1,marginBottom:6}}>{cqcReadiness}%</div>
                    <RAGChip rating={getRating(cqcReadiness)} size="large"/>
                  </div>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10}}>
                  {[["KLoE Audit",latestAudit.overall],["Medication",medTrend[medTrend.length-1].score],["Mock Inspection",mockOverall],["Staff Compliance",Math.round(staffCompliance.dbsValid/staffCompliance.total*100)],["SU Compliance",88]].map(([l,v])=>(
                    <div key={l} style={{textAlign:"center",padding:"12px 8px",background:CQC_RATINGS[getRating(v)]?.bg||"#F1F3F8",borderRadius:8}}>
                      <div style={{fontSize:10,fontWeight:600,color:"#374151",marginBottom:4}}>{l}</div>
                      <div style={{fontSize:20,fontWeight:800,color:CQC_RATINGS[getRating(v)]?.color||"#D1D5DB"}}>{v!=null?`${v}%`:"—"}</div>
                      {v!=null&&<RAGChip rating={getRating(v)}/>}
                    </div>
                  ))}
                </div>
              </div>

              {/* Readiness checklist by regulation */}
              <ReportSection title="Fundamental Standards Compliance" icon="shield" subtitle="CQC checks compliance with all fundamental standards — Regulations 9-20">
                {[
                  {reg:"Reg 9",  title:"Person-centred care",    ok:true,  note:"Care plans current and signed. Service users involved. Goals documented."},
                  {reg:"Reg 10", title:"Dignity and respect",    ok:true,  note:"Staff demonstrate dignity. Privacy maintained. Spot checks evidenced."},
                  {reg:"Reg 11", title:"Need for consent",       ok:true,  note:"MCA assessments completed. DoLS in place. Best interest decisions recorded."},
                  {reg:"Reg 12", title:"Safe care and treatment",ok:false, note:"2 risk assessments overdue. Medication audit strong (94%). IPC up to date."},
                  {reg:"Reg 13", title:"Safeguarding",           ok:false, note:"1 open concern under investigation. Policies current. Training complete."},
                  {reg:"Reg 14", title:"Meeting nutritional needs",ok:true,note:"Dietary needs assessed. SALT involved for Dorothy. Weight monitoring in place."},
                  {reg:"Reg 15", title:"Premises and equipment", ok:true,  note:"No concerns raised in environmental audits."},
                  {reg:"Reg 16", title:"Receiving and acting on complaints",ok:true,note:"Complaints policy current. 1 complaint resolved within timeframe."},
                  {reg:"Reg 17", title:"Good governance",        ok:false, note:"Monthly audits in place. Staff survey and residents' meetings outstanding."},
                  {reg:"Reg 18", title:"Staffing",               ok:false, note:"2 DBS expired. Supervision overdue for 1 staff member. Competencies current."},
                  {reg:"Reg 19", title:"Fit and proper persons", ok:false, note:"2 DBS certificates expired — renewal in progress."},
                  {reg:"Reg 20", title:"Duty of candour",        ok:true,  note:"Duty of candour policy in place. Evidence of honest communication with families."},
                ].map((item,i)=>(
                  <div key={item.reg} style={{display:"flex",gap:10,padding:"9px 0",borderBottom:i<11?"1px solid #E5E7EB":"none",alignItems:"flex-start"}}>
                    <RegTag reg={item.reg}/>
                    <div style={{flex:1}}>
                      <div style={{fontSize:12,fontWeight:600,color:"#062B7A",marginBottom:2}}>{item.title}</div>
                      <div style={{fontSize:11,color:"#374151"}}>{item.note}</div>
                    </div>
                    <VerifiedBadge ok={item.ok} label={item.ok?"Met":"Requires action"}/>
                  </div>
                ))}
              </ReportSection>

              {/* Priority actions before inspection */}
              <ReportSection title="Priority Actions Before CQC Inspection" icon="alert" subtitle="Complete these to maximise your inspection rating">
                {[
                  {priority:"Critical",action:"Renew DBS certificates for Maria Johnson and Rachel Davies",timeframe:"Immediately",reg:"Reg 19"},
                  {priority:"High",    action:"Complete overdue risk assessment reviews (2 outstanding)",   timeframe:"Within 7 days",reg:"Reg 12"},
                  {priority:"High",    action:"Complete Tom Patel supervision (3 weeks overdue)",            timeframe:"Within 7 days",reg:"Reg 18"},
                  {priority:"High",    action:"Resolve open safeguarding concern SG/2026/003",              timeframe:"Within 14 days",reg:"Reg 13"},
                  {priority:"Medium",  action:"Implement quarterly residents' and families' meetings",       timeframe:"Within 30 days",reg:"Reg 17"},
                  {priority:"Medium",  action:"Complete annual staff survey",                               timeframe:"Within 30 days",reg:"Reg 17"},
                  {priority:"Medium",  action:"Update 3 policies not reviewed in last 12 months",           timeframe:"Within 30 days",reg:"Reg 17"},
                  {priority:"Low",     action:"Implement formal service user feedback/satisfaction surveys", timeframe:"Within 60 days",reg:"Reg 17"},
                  {priority:"Low",     action:"Renew Prevent training — Sarah Mitchell (expiring Sept 2026)",timeframe:"Within 60 days",reg:"Reg 13"},
                ].map((item,i)=>{
                  const pc=severityColor(item.priority);
                  return(
                    <div key={i} style={{display:"flex",gap:10,padding:"10px 0",borderBottom:i<8?"1px solid #E5E7EB":"none",alignItems:"center"}}>
                      <span style={{background:pc.bg,color:pc.fg,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700,flexShrink:0,minWidth:60,textAlign:"center"}}>{item.priority}</span>
                      <span style={{flex:1,fontSize:12,color:"#062B7A"}}>{item.action}</span>
                      <span style={{fontSize:11,color:"#6B7280",whiteSpace:"nowrap"}}>{item.timeframe}</span>
                      <RegTag reg={item.reg}/>
                    </div>
                  );
                })}
              </ReportSection>
            </div>
          )}

          {/* ── MULTI-SITE COMPARISON (Director/SuperAdmin) ── */}
          {activeReport==="multisite"&&(
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:4}}>Multi-Site Compliance Comparison</div>
              <div style={{fontSize:13,color:"#6B7280",marginBottom:20}}>Compliance overview across all services in your group · Director view</div>

              <ReportSection title="Compliance by Service" icon="multisite">
                <table style={{width:"100%",borderCollapse:"collapse"}}>
                  <thead>
                    <tr style={{background:"#F8FAFC"}}>
                      {["Service","Type","Overall","Safe","Effective","Caring","Responsive","Well-led","Alerts","Rating"].map(h=>(
                        <th key={h} style={{padding:"9px 12px",fontSize:11,fontWeight:700,color:"#6B7280",textAlign:"left",textTransform:"uppercase",letterSpacing:"0.5px",borderBottom:"1px solid #E5E7EB"}}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {DIR_SERVICES.map((svc,i)=>{
                      const rating=getRating(svc.score);
                      const cfg=CQC_RATINGS[rating];
                      const fakeScores={safe:svc.score-3,effective:svc.score+4,caring:svc.score+8,responsive:svc.score-5,wellLed:svc.score};
                      return(
                        <tr key={i} style={{borderBottom:"1px solid #E5E7EB",background:i%2===0?"#F8FAFC":"#fff"}}>
                          <td style={{padding:"11px 12px",fontSize:13,fontWeight:600,color:"#062B7A"}}>{svc.name}</td>
                          <td style={{padding:"11px 12px",fontSize:12,color:"#374151"}}>{svc.type}</td>
                          <td style={{padding:"11px 12px"}}><span style={{fontSize:14,fontWeight:800,color:cfg?.color}}>{svc.score}%</span></td>
                          {[fakeScores.safe,fakeScores.effective,fakeScores.caring,fakeScores.responsive,fakeScores.wellLed].map((s,si)=>(
                            <td key={si} style={{padding:"11px 12px"}}><span style={{fontSize:12,fontWeight:600,color:s>=85?"#16B5B8":s>=75?"#7A57D1":"#FF9A2F"}}>{s}%</span></td>
                          ))}
                          <td style={{padding:"11px 12px"}}><span style={{background:svc.alerts>3?"#FDF0F0":"#FDF8EE",color:svc.alerts>3?"#FF5A6E":"#FF9A2F",padding:"2px 8px",borderRadius:20,fontSize:11,fontWeight:700}}>{svc.alerts}</span></td>
                          <td style={{padding:"11px 12px"}}>{rating&&<RAGChip rating={rating}/>}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </ReportSection>

              <ReportSection title="Group Compliance Trend — Last 4 Months" icon="trending">
                <div style={{display:"flex",gap:20,alignItems:"flex-end",height:90}}>
                  {[{month:"Feb",scores:[74,82,85,77]},{month:"Mar",scores:[78,84,87,79]},{month:"Apr",scores:[81,87,90,75]},{month:"May",scores:[84,91,92,76]}].map((m,mi)=>(
                    <div key={mi} style={{flex:1}}>
                      <div style={{display:"flex",gap:3,alignItems:"flex-end",height:70,marginBottom:5}}>
                        {m.scores.map((sc,si)=>(
                          <div key={si} style={{flex:1,background:["#16B5B8","#16B5B8","#7A57D1","#FF9A2F"][si],borderRadius:"3px 3px 0 0",height:`${sc}%`,opacity:0.8}}/>
                        ))}
                      </div>
                      <div style={{fontSize:11,fontWeight:600,color:"#374151",textAlign:"center"}}>{m.month}</div>
                      <div style={{fontSize:9,color:"#6B7280",textAlign:"center"}}>avg {Math.round(m.scores.reduce((a,b)=>a+b,0)/m.scores.length)}%</div>
                    </div>
                  ))}
                </div>
                <div style={{display:"flex",gap:12,marginTop:10,flexWrap:"wrap"}}>
                  {DIR_SERVICES.map((s,i)=>(
                    <div key={i} style={{display:"flex",alignItems:"center",gap:5,fontSize:11,color:"#374151"}}>
                      <div style={{width:10,height:10,borderRadius:2,background:["#16B5B8","#16B5B8","#7A57D1","#FF9A2F"][i]}}/>
                      {s.name.split(" ").slice(0,2).join(" ")}
                    </div>
                  ))}
                </div>
              </ReportSection>

              <ReportSection title="Services Requiring Director Attention" icon="alert">
                {DIR_SERVICES.filter(s=>s.alerts>3||s.score<80).map((s,i)=>(
                  <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 0",borderBottom:"1px solid #E5E7EB"}}>
                    <div>
                      <div style={{fontSize:13,fontWeight:600,color:"#062B7A"}}>{s.name}</div>
                      <div style={{fontSize:11,color:"#6B7280"}}>{s.type} · Score: {s.score}% · {s.alerts} alerts</div>
                    </div>
                    <div style={{display:"flex",gap:8}}>
                      <span style={{background:s.score<80?"#FDF0F0":"#FDF8EE",color:s.score<80?"#FF5A6E":"#FF9A2F",padding:"3px 10px",borderRadius:20,fontSize:11,fontWeight:700}}>{s.score<80?"Below threshold":"Monitor"}</span>
                      <RAGChip rating={getRating(s.score)}/>
                    </div>
                  </div>
                ))}
                {DIR_SERVICES.filter(s=>s.alerts>3||s.score<80).length===0&&<div style={{fontSize:13,color:"#16B5B8",fontWeight:500}}>✓ All services are performing within acceptable thresholds.</div>}
              </ReportSection>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}

// ── APP SHELL ─────────────────────────────────────────────────

// ════════════════════════════════════════════════════════════════
// ONBOARDING MODULE — Super Admin only
// Add new care company, configure care setting, set up users,
// configure audit schedules, go-live checklist, company management
// ════════════════════════════════════════════════════════════════

const CARE_SETTING_TYPES = [
  "Supported Living","Care Home","Domiciliary Care","Nursing Home",
  "Residential Care","Respite Care","Extra Care Housing",
  "Learning Disability Service","Mental Health Service","Acquired Brain Injury",
];

