// ── Countdown timer component ─────────────────────────────────
function InspectionCountdown({ targetDate, targetTime }){
  const [timeLeft, setTimeLeft] = useState(null);

  useEffect(()=>{
    if(!targetDate) return;
    const target = new Date(`${targetDate}T${targetTime||"09:00"}:00`);
    const update = () => {
      const now  = new Date();
      const diff = target - now;
      if(diff <= 0){ setTimeLeft({days:0,hours:0,minutes:0,seconds:0,expired:true}); return; }
      const days    = Math.floor(diff/1000/60/60/24);
      const hours   = Math.floor((diff/1000/60/60)%24);
      const minutes = Math.floor((diff/1000/60)%60);
      const seconds = Math.floor((diff/1000)%60);
      setTimeLeft({days,hours,minutes,seconds,expired:false});
    };
    update();
    const interval = setInterval(update,1000);
    return ()=>clearInterval(interval);
  },[targetDate,targetTime]);

  if(!timeLeft) return null;

  const isUrgent = timeLeft.days===0;
  const color    = timeLeft.expired?"#6B7280":isUrgent?"#FF5A6E":"#FF9A2F";

  return(
    <div style={{display:"flex",gap:10,justifyContent:"center",marginTop:16}}>
      {timeLeft.expired
        ? <div style={{fontSize:18,fontWeight:800,color:"#FF5A6E"}}>⚠ Inspection time has passed</div>
        : [
            {v:timeLeft.days,   l:"Days"},
            {v:timeLeft.hours,  l:"Hours"},
            {v:timeLeft.minutes,l:"Minutes"},
            {v:timeLeft.seconds,l:"Seconds"},
          ].map((t,i)=>(
            <div key={i} style={{textAlign:"center",padding:"14px 18px",background:isUrgent?"#FDF0F0":"#FDF8EE",borderRadius:10,border:`2px solid ${color}33`,minWidth:72}}>
              <div style={{fontSize:32,fontWeight:900,color,lineHeight:1,fontVariantNumeric:"tabular-nums"}}>{String(t.v).padStart(2,"0")}</div>
              <div style={{fontSize:10,color:"#6B7280",marginTop:3,fontWeight:600,textTransform:"uppercase",letterSpacing:"0.8px"}}>{t.l}</div>
            </div>
          ))
      }
    </div>
  );
}

