// ── Score pill ────────────────────────────────────────────────
function DigestScore({score, size="normal"}){
  if(score==null) return <span style={{fontSize:size==="large"?28:18,fontWeight:800,color:"#D1D5DB"}}>—</span>;
  const color = score>=90?"#7A57D1":score>=85?"#16B5B8":score>=75?"#7A57D1":score>=50?"#FF9A2F":"#FF5A6E";
  const label = score>=90?"Outstanding":score>=85?"Good+":score>=75?"Good":score>=50?"Req. Improvement":"Inadequate";
  return(
    <div style={{display:"flex",alignItems:"baseline",gap:4}}>
      <span style={{fontSize:size==="large"?34:22,fontWeight:900,color,lineHeight:1}}>{score}%</span>
      {size==="large"&&<span style={{fontSize:12,fontWeight:700,color,marginBottom:2}}>{label}</span>}
    </div>
  );
}

// ── Trend arrow ───────────────────────────────────────────────
function DigestTrend({trend, direction}){
  if(!trend) return null;
  const up = direction==="up";
  return(
    <span style={{fontSize:11,fontWeight:700,color:up?"#16B5B8":"#FF5A6E",background:up?"#F0FDF4":"#FDF0F0",padding:"2px 8px",borderRadius:20,display:"inline-flex",alignItems:"center",gap:3}}>
      {up?"↑":"↓"} {trend}% this week
    </span>
  );
}

// ── Service card for digest ───────────────────────────────────
function DigestServiceCard({service, onExpand}){
  const w   = service.weeklyData;
  const rag = getRating(w.overallScore);
  const cfg = CQC_RATINGS[rag]||CQC_RATINGS["Requires Improvement"];
  const criticalAlerts = w.alerts.filter(a=>a.priority==="Critical"||a.priority==="High");
  const needsDirector  = w.requiringDirectorAction.length>0;

  return(
    <div style={{
      background:"#fff",borderRadius:12,overflow:"hidden",
      border:`1px solid ${needsDirector?"#FF9A2F33":"#E5E7EB"}`,
      boxShadow:needsDirector?"0 2px 12px rgba(201,112,32,0.1)":"0 1px 4px rgba(0,0,0,0.05)",
    }}>
      {/* Card header */}
      <div style={{padding:"16px 18px",borderBottom:"1px solid #E5E7EB",display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
        <div style={{flex:1}}>
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:3,flexWrap:"wrap"}}>
            <span style={{fontSize:14,fontWeight:800,color:"#062B7A"}}>{service.name}</span>
            <span style={{fontSize:10,background:"#F1F3F8",color:"#6B7280",padding:"1px 7px",borderRadius:20}}>{service.type}</span>
            {needsDirector&&<span style={{fontSize:10,background:"#FDF8EE",color:"#FF9A2F",padding:"1px 8px",borderRadius:20,fontWeight:700,border:"1px solid #FF9A2F33"}}>⚠ Director action needed</span>}
          </div>
          <div style={{fontSize:11,color:"#6B7280"}}>Manager: {service.manager} · {service.suCount} service users · {service.staffCount} staff</div>
          <div style={{fontSize:11,color:"#6B7280",marginTop:2}}>
            Last CQC: {service.lastInspectionDate} — <span style={{color:CQC_RATINGS[service.lastInspectionRating]?.color,fontWeight:600}}>{service.lastInspectionRating}</span>
          </div>
        </div>
        <div style={{textAlign:"center",padding:"10px 16px",background:cfg.bg,borderRadius:9,border:`1px solid ${cfg.color}33`,marginLeft:12}}>
          <DigestScore score={w.overallScore} size="normal"/>
          <div style={{marginTop:4}}><DigestTrend trend={w.trend} direction={w.trendDirection}/></div>
        </div>
      </div>

      {/* KLoE mini scores */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:0,borderBottom:"1px solid #E5E7EB"}}>
        {Object.entries(w.kloe).map(([domain,score])=>{
          const dr  = getRating(score);
          const dcfg= CQC_RATINGS[dr];
          return(
            <div key={domain} style={{padding:"9px 6px",textAlign:"center",borderRight:"1px solid #E5E7EB"}}>
              <div style={{fontSize:9,fontWeight:700,color:"#6B7280",marginBottom:3,textTransform:"uppercase",letterSpacing:"0.5px"}}>{domain}</div>
              <div style={{fontSize:14,fontWeight:800,color:dcfg?.color||"#D1D5DB"}}>{score}%</div>
            </div>
          );
        })}
      </div>

      {/* Quick stats row */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(6,1fr)",gap:0,borderBottom:"1px solid #E5E7EB"}}>
        {[
          {l:"Med Audit",  v:w.medAuditScore!=null?`${w.medAuditScore}%`:"Due",      alert:w.medAuditScore==null},
          {l:"DBS Expired",v:w.dbsExpired,      alert:w.dbsExpired>0},
          {l:"Supv Overdue",v:w.supervisionOverdue, alert:w.supervisionOverdue>0},
          {l:"Open Safeg.", v:w.openSafeguarding,   alert:w.openSafeguarding>0},
          {l:"Open Complaints",v:w.openComplaints,  alert:w.openComplaints>0},
          {l:"Audits Done", v:w.completedAuditsThisMonth, alert:w.completedAuditsThisMonth<2},
        ].map((s,i)=>(
          <div key={i} style={{padding:"8px 6px",textAlign:"center",borderRight:i<5?"1px solid #E5E7EB":"none",background:s.alert?"#FEFAF8":"#fff"}}>
            <div style={{fontSize:14,fontWeight:800,color:s.alert?"#FF5A6E":"#062B7A",lineHeight:1}}>{s.v}</div>
            <div style={{fontSize:9,color:"#6B7280",marginTop:2,lineHeight:1.3}}>{s.l}</div>
          </div>
        ))}
      </div>

      {/* Alerts */}
      {criticalAlerts.length>0&&(
        <div style={{padding:"10px 14px",borderBottom:"1px solid #E5E7EB"}}>
          {criticalAlerts.slice(0,3).map((a,i)=>{
            const pc=severityColor(a.priority);
            return(
              <div key={i} style={{display:"flex",gap:7,alignItems:"flex-start",marginBottom:i<criticalAlerts.slice(0,3).length-1?5:0}}>
                <span style={{background:pc.bg,color:pc.fg,padding:"1px 7px",borderRadius:20,fontSize:9,fontWeight:700,flexShrink:0,marginTop:1}}>{a.priority}</span>
                <span style={{fontSize:11,color:"#062B7A"}}>{a.text}</span>
              </div>
            );
          })}
          {criticalAlerts.length>3&&<div style={{fontSize:10,color:"#6B7280",marginTop:4}}>+{criticalAlerts.length-3} more alerts</div>}
        </div>
      )}

      {/* Highlights */}
      {w.weekHighlights.length>0&&(
        <div style={{padding:"10px 14px",borderBottom:"1px solid #E5E7EB"}}>
          {w.weekHighlights.map((h,i)=>(
            <div key={i} style={{display:"flex",gap:6,alignItems:"flex-start",marginBottom:i<w.weekHighlights.length-1?4:0}}>
              <span style={{color:"#16B5B8",fontWeight:700,fontSize:11,flexShrink:0}}>✓</span>
              <span style={{fontSize:11,color:"#374151"}}>{h}</span>
            </div>
          ))}
        </div>
      )}

      {/* Director actions */}
      {needsDirector&&(
        <div style={{padding:"10px 14px",background:"#FDF8EE"}}>
          <div style={{fontSize:10,fontWeight:700,color:"#FF9A2F",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.6px"}}>Requires your attention</div>
          {w.requiringDirectorAction.map((a,i)=>(
            <div key={i} style={{display:"flex",gap:6,alignItems:"flex-start",marginBottom:i<w.requiringDirectorAction.length-1?4:0}}>
              <span style={{color:"#FF9A2F",flexShrink:0,fontSize:11}}>→</span>
              <span style={{fontSize:11,color:"#FF9A2F",lineHeight:1.5}}>{a}</span>
            </div>
          ))}
        </div>
      )}

      <div style={{padding:"8px 14px",display:"flex",justifyContent:"flex-end"}}>
        <button onClick={()=>onExpand(service)} style={{padding:"5px 14px",borderRadius:7,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Full report →</button>
      </div>
    </div>
  );
}

// ── Full service drill-down ───────────────────────────────────
function DigestServiceDetail({service, onBack}){
  const w   = service.weeklyData;
  const rag = getRating(w.overallScore);
  const cfg = CQC_RATINGS[rag]||CQC_RATINGS["Requires Improvement"];

  return(
    <div style={{height:"100%",overflowY:"auto",background:"#F8FAFC",padding:"22px",fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif"}}>
      <button onClick={onBack} style={{display:"flex",alignItems:"center",gap:5,background:"none",border:"none",cursor:"pointer",color:"#6B7280",fontSize:12,fontWeight:600,fontFamily:"inherit",marginBottom:16,padding:0}}>
        ← Back to weekly digest
      </button>

      <div style={{maxWidth:900}}>
        {/* Service header */}
        <div style={{background:"#fff",borderRadius:12,padding:"22px",marginBottom:16,boxShadow:"0 2px 8px rgba(0,0,0,0.06)",border:`2px solid ${cfg.color}33`}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:3}}>{service.name}</div>
              <div style={{fontSize:13,color:"#6B7280"}}>{service.type} · Manager: {service.manager} · {service.suCount} service users · {service.staffCount} staff</div>
              <div style={{fontSize:13,color:"#6B7280",marginTop:2}}>Last CQC inspection: {service.lastInspectionDate} — <RAGChip rating={service.lastInspectionRating}/></div>
            </div>
            <div style={{textAlign:"center",padding:"18px 24px",background:cfg.bg,borderRadius:12,border:`2px solid ${cfg.color}33`}}>
              <div style={{fontSize:11,fontWeight:700,color:"#6B7280",marginBottom:4,textTransform:"uppercase",letterSpacing:"0.8px"}}>Weekly Score</div>
              <DigestScore score={w.overallScore} size="large"/>
              <div style={{marginTop:6}}><DigestTrend trend={w.trend} direction={w.trendDirection}/></div>
            </div>
          </div>

          {/* Full KLoE breakdown */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10}}>
            {Object.entries(w.kloe).map(([domain,score])=>{
              const dr  = getRating(score);
              const dcfg= CQC_RATINGS[dr];
              return(
                <div key={domain} style={{textAlign:"center",padding:"12px 8px",background:dcfg?.bg||"#F1F3F8",borderRadius:8,border:`1px solid ${dcfg?.color||"#D1D5DB"}33`}}>
                  <div style={{fontSize:10,fontWeight:700,color:"#374151",marginBottom:4}}>{domain}</div>
                  <div style={{fontSize:22,fontWeight:800,color:dcfg?.color||"#D1D5DB",lineHeight:1,marginBottom:4}}>{score}%</div>
                  <RAGChip rating={dr}/>
                </div>
              );
            })}
          </div>
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:14}}>
          {/* All alerts */}
          <div style={{background:"#fff",borderRadius:10,border:"1px solid #E5E7EB",overflow:"hidden"}}>
            <div style={{padding:"12px 16px",borderBottom:"1px solid #E5E7EB",fontSize:13,fontWeight:700,color:"#062B7A",display:"flex",alignItems:"center",gap:7}}>
              <Icon name="alert" size={13} color="#16B5B8" strokeWidth={2}/> All Alerts This Week
            </div>
            <div style={{padding:"12px 16px"}}>
              {w.alerts.length===0
                ?<div style={{fontSize:12,color:"#16B5B8",fontWeight:500}}>✓ No alerts this week</div>
                :w.alerts.map((a,i)=>{
                  const pc=severityColor(a.priority);
                  return(
                    <div key={i} style={{display:"flex",gap:8,padding:"8px 0",borderBottom:i<w.alerts.length-1?"1px solid #E5E7EB":"none",alignItems:"flex-start"}}>
                      <span style={{background:pc.bg,color:pc.fg,padding:"2px 7px",borderRadius:20,fontSize:10,fontWeight:700,flexShrink:0}}>{a.priority}</span>
                      <div>
                        <div style={{fontSize:12,color:"#062B7A"}}>{a.text}</div>
                        <div style={{display:"flex",gap:5,marginTop:3}}><span style={{fontSize:10,color:"#6B7280"}}>{a.module}</span><RegTag reg={a.reg}/></div>
                      </div>
                    </div>
                  );
                })
              }
            </div>
          </div>

          {/* Week metrics */}
          <div style={{background:"#fff",borderRadius:10,border:"1px solid #E5E7EB",overflow:"hidden"}}>
            <div style={{padding:"12px 16px",borderBottom:"1px solid #E5E7EB",fontSize:13,fontWeight:700,color:"#062B7A",display:"flex",alignItems:"center",gap:7}}>
              <Icon name="trending" size={13} color="#16B5B8" strokeWidth={2}/> Weekly Metrics
            </div>
            <div style={{padding:"12px 16px"}}>
              {[
                {l:"Medication audit score",v:w.medAuditScore!=null?`${w.medAuditScore}%`:"Not completed", alert:w.medAuditScore==null},
                {l:"Medication errors",      v:w.medErrors,    alert:w.medErrors>3},
                {l:"High severity errors",   v:w.medHighSeverity, alert:w.medHighSeverity>0},
                {l:"DBS expired",            v:w.dbsExpired,   alert:w.dbsExpired>0},
                {l:"Training expired",       v:w.trainingExpired, alert:w.trainingExpired>0},
                {l:"Supervisions overdue",   v:w.supervisionOverdue, alert:w.supervisionOverdue>0},
                {l:"Care plan reviews due",  v:w.carePlanReviewsDue, alert:w.carePlanReviewsDue>0},
                {l:"Open safeguarding",      v:w.openSafeguarding,   alert:w.openSafeguarding>0},
                {l:"Open complaints",        v:w.openComplaints,     alert:w.openComplaints>0},
                {l:"Goals achieved",         v:w.goalsAchievedThisWeek, alert:false},
                {l:"Audits completed",       v:w.completedAuditsThisMonth, alert:w.completedAuditsThisMonth<2},
                {l:"Mock inspection score",  v:w.mockinspectionScore!=null?`${w.mockinspectionScore}%`:"—", alert:w.mockinspectionScore!=null&&w.mockinspectionScore<75},
              ].map(([l,v,a],i,arr)=>typeof l==="string"?null:(
                <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:"1px solid #E5E7EB",fontSize:12}}>
                  <span style={{color:"#6B7280"}}>{l}</span>
                  <span style={{fontWeight:700,color:a?"#FF5A6E":"#062B7A"}}>{v}</span>
                </div>
              )).filter(Boolean)}
              {[
                {l:"Medication audit score",v:w.medAuditScore!=null?`${w.medAuditScore}%`:"Not completed",alert:w.medAuditScore==null},
                {l:"Medication errors",     v:w.medErrors,    alert:w.medErrors>3},
                {l:"DBS expired",           v:w.dbsExpired,   alert:w.dbsExpired>0},
                {l:"Training expired",      v:w.trainingExpired,alert:w.trainingExpired>0},
                {l:"Supervisions overdue",  v:w.supervisionOverdue,alert:w.supervisionOverdue>0},
                {l:"Open safeguarding",     v:w.openSafeguarding,alert:w.openSafeguarding>0},
                {l:"Open complaints",       v:w.openComplaints,alert:w.openComplaints>0},
                {l:"Audits completed",      v:w.completedAuditsThisMonth,alert:w.completedAuditsThisMonth<2},
                {l:"Mock inspection score", v:w.mockinspectionScore!=null?`${w.mockinspectionScore}%`:"—",alert:w.mockinspectionScore!=null&&w.mockinspectionScore<75},
                {l:"Goals achieved this week",v:w.goalsAchievedThisWeek,alert:false},
              ].map((s,i,arr)=>(
                <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:i<arr.length-1?"1px solid #E5E7EB":"none",fontSize:12}}>
                  <span style={{color:"#6B7280"}}>{s.l}</span>
                  <span style={{fontWeight:700,color:s.alert?"#FF5A6E":"#062B7A"}}>{s.v}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Week highlights */}
        <div style={{background:"#fff",borderRadius:10,border:"1px solid #E5E7EB",padding:"16px",marginBottom:14}}>
          <div style={{fontSize:13,fontWeight:700,color:"#062B7A",marginBottom:12,display:"flex",alignItems:"center",gap:7}}><Icon name="check" size={13} color="#16B5B8" strokeWidth={2}/> Week Highlights</div>
          {w.weekHighlights.length===0
            ?<div style={{fontSize:12,color:"#6B7280"}}>No highlights recorded this week.</div>
            :w.weekHighlights.map((h,i)=>(
              <div key={i} style={{display:"flex",gap:8,padding:"8px 0",borderBottom:i<w.weekHighlights.length-1?"1px solid #E5E7EB":"none",alignItems:"flex-start"}}>
                <span style={{background:"#F0FDF4",color:"#16B5B8",width:18,height:18,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,fontSize:10,fontWeight:700}}>✓</span>
                <span style={{fontSize:13,color:"#374151",lineHeight:1.5}}>{h}</span>
              </div>
            ))
          }
        </div>

        {/* Director actions */}
        {w.requiringDirectorAction.length>0&&(
          <div style={{background:"#FDF8EE",borderRadius:10,border:"1px solid #FF9A2F33",padding:"16px"}}>
            <div style={{fontSize:13,fontWeight:700,color:"#FF9A2F",marginBottom:12,display:"flex",alignItems:"center",gap:7}}><Icon name="alert" size={13} color="#FF9A2F" strokeWidth={2}/> Actions Requiring Your Attention as Director</div>
            {w.requiringDirectorAction.map((a,i)=>(
              <div key={i} style={{display:"flex",gap:8,padding:"10px 0",borderBottom:i<w.requiringDirectorAction.length-1?"1px solid #FF9A2F22":"none",alignItems:"flex-start"}}>
                <span style={{background:"#FF9A2F",color:"#fff",width:18,height:18,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,fontSize:10,fontWeight:700}}>{i+1}</span>
                <span style={{fontSize:13,color:"#FF9A2F",lineHeight:1.6}}>{a}</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Director Weekly Digest Page ───────────────────────────────
function DirectorDigestPage(){
  const [view,        setView]       = useState("digest"); // digest | service
  const [expanded,    setExpanded]   = useState(null);
  const [weekOffset,  setWeekOffset] = useState(0); // 0 = this week, -1 = last week etc.

  const today     = new Date();
  const monday    = new Date(today);
  monday.setDate(today.getDate() - today.getDay() + 1 + (weekOffset*7));
  const sunday    = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  const weekLabel = `${monday.toLocaleDateString("en-GB",{day:"numeric",month:"short"})} – ${sunday.toLocaleDateString("en-GB",{day:"numeric",month:"short",year:"numeric"})}`;

  if(view==="service"&&expanded){
    return <DigestServiceDetail service={expanded} onBack={()=>setView("digest")}/>;
  }

  // Group stats
  const totalServices  = DIGEST_SERVICES.length;
  const avgScore       = Math.round(DIGEST_SERVICES.reduce((s,sv)=>s+sv.weeklyData.overallScore,0)/totalServices);
  const totalAlerts    = DIGEST_SERVICES.reduce((n,sv)=>n+sv.weeklyData.alerts.length,0);
  const criticalServices= DIGEST_SERVICES.filter(sv=>sv.weeklyData.requiringDirectorAction.length>0);
  const totalSUs       = DIGEST_SERVICES.reduce((n,sv)=>n+sv.suCount,0);
  const totalStaff     = DIGEST_SERVICES.reduce((n,sv)=>n+sv.staffCount,0);
  const dbsExpired     = DIGEST_SERVICES.reduce((n,sv)=>n+sv.weeklyData.dbsExpired,0);
  const openSafeguarding=DIGEST_SERVICES.reduce((n,sv)=>n+sv.weeklyData.openSafeguarding,0);

  const groupRating = getRating(avgScore);
  const groupCfg    = CQC_RATINGS[groupRating]||CQC_RATINGS["Requires Improvement"];

  return(
    <div style={{height:"100%",overflowY:"auto",background:"#F8FAFC",fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif"}}>
      {/* Digest header banner */}
      <div style={{background:"linear-gradient(135deg,#062B7A,#2A4A7A)",padding:"22px 28px",position:"relative",overflow:"hidden"}}>
        <div style={{position:"absolute",right:-30,top:-30,width:220,height:220,borderRadius:"50%",background:"rgba(43,191,178,0.07)"}}/>
        <div style={{position:"absolute",right:80,bottom:-50,width:160,height:160,borderRadius:"50%",background:"rgba(43,191,178,0.04)"}}/>
        <div style={{position:"relative",zIndex:1}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
            <div>
              <div style={{fontSize:11,fontWeight:700,color:"rgba(255,255,255,0.5)",textTransform:"uppercase",letterSpacing:"1.5px",marginBottom:4}}>Director Weekly Digest</div>
              <div style={{fontSize:22,fontWeight:900,color:"#fff",marginBottom:3}}>Thornton Care Group</div>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <button onClick={()=>setWeekOffset(w=>w-1)} style={{background:"rgba(255,255,255,0.1)",border:"none",color:"rgba(255,255,255,0.6)",fontSize:14,cursor:"pointer",padding:"2px 8px",borderRadius:6}}>‹</button>
                <span style={{fontSize:13,color:"rgba(255,255,255,0.7)",fontWeight:500}}>Week of {weekLabel}</span>
                {weekOffset<0&&<button onClick={()=>setWeekOffset(w=>w+1)} style={{background:"rgba(255,255,255,0.1)",border:"none",color:"rgba(255,255,255,0.6)",fontSize:14,cursor:"pointer",padding:"2px 8px",borderRadius:6}}>›</button>}
              </div>
            </div>
            <div style={{textAlign:"center",padding:"16px 22px",background:"rgba(255,255,255,0.08)",borderRadius:12,border:"1px solid rgba(255,255,255,0.12)"}}>
              <div style={{fontSize:11,fontWeight:700,color:"rgba(255,255,255,0.5)",marginBottom:4,textTransform:"uppercase",letterSpacing:"0.8px"}}>Group Average</div>
              <div style={{fontSize:38,fontWeight:900,color:groupCfg.color,lineHeight:1,marginBottom:4}}>{avgScore}%</div>
              <RAGChip rating={groupRating} size="large"/>
            </div>
          </div>

          {/* Group KPIs */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(6,1fr)",gap:10,marginTop:18}}>
            {[
              {l:"Services",    v:totalServices,    c:"rgba(255,255,255,0.9)"},
              {l:"Service Users",v:totalSUs,        c:"rgba(255,255,255,0.9)"},
              {l:"Staff",       v:totalStaff,       c:"rgba(255,255,255,0.9)"},
              {l:"Total Alerts",v:totalAlerts,      c:totalAlerts>5?"#F87171":"#6EE7B7"},
              {l:"DBS Expired", v:dbsExpired,       c:dbsExpired>0?"#F87171":"#6EE7B7"},
              {l:"Open Safeguarding",v:openSafeguarding,c:openSafeguarding>0?"#F87171":"#6EE7B7"},
            ].map((k,i)=>(
              <div key={i} style={{textAlign:"center",padding:"10px 8px",background:"rgba(255,255,255,0.06)",borderRadius:8,border:"1px solid rgba(255,255,255,0.08)"}}>
                <div style={{fontSize:20,fontWeight:800,color:k.c,lineHeight:1}}>{k.v}</div>
                <div style={{fontSize:10,color:"rgba(255,255,255,0.4)",marginTop:3}}>{k.l}</div>
              </div>
            ))}
          </div>

          {/* Services needing director attention */}
          {criticalServices.length>0&&(
            <div style={{marginTop:14,padding:"10px 14px",background:"rgba(201,112,32,0.15)",borderRadius:9,border:"1px solid rgba(201,112,32,0.3)"}}>
              <div style={{fontSize:12,fontWeight:700,color:"#FCD34D",marginBottom:4}}>⚠ {criticalServices.length} service{criticalServices.length>1?"s":""} requiring your attention this week</div>
              <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                {criticalServices.map(sv=>(
                  <span key={sv.id} onClick={()=>{setExpanded(sv);setView("service");}} style={{background:"rgba(255,255,255,0.1)",color:"#FCD34D",padding:"3px 10px",borderRadius:20,fontSize:11,fontWeight:600,cursor:"pointer",border:"1px solid rgba(252,211,77,0.3)"}}>{sv.name} →</span>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Service cards grid */}
      <div style={{padding:"22px 24px"}}>

        {/* Group compliance bar */}
        <div style={{background:"#fff",borderRadius:10,padding:"16px 20px",marginBottom:20,boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)"}}>
          <div style={{fontSize:13,fontWeight:700,color:"#062B7A",marginBottom:12,display:"flex",alignItems:"center",gap:7}}>
            <Icon name="trending" size={14} color="#16B5B8" strokeWidth={2}/> Group Compliance Overview — All Services
          </div>
          <div style={{display:"flex",gap:12,alignItems:"flex-end",height:80}}>
            {DIGEST_SERVICES.map(sv=>{
              const rating = getRating(sv.weeklyData.overallScore);
              const cfg    = CQC_RATINGS[rating];
              return(
                <div key={sv.id} onClick={()=>{setExpanded(sv);setView("service");}} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"flex-end",gap:3,cursor:"pointer"}}
                  onMouseEnter={e=>e.currentTarget.style.opacity="0.8"}
                  onMouseLeave={e=>e.currentTarget.style.opacity="1"}>
                  <div style={{fontSize:11,fontWeight:700,color:cfg?.color}}>{sv.weeklyData.overallScore}%</div>
                  <div style={{width:"100%",background:cfg?.color||"#D1D5DB",borderRadius:"4px 4px 0 0",height:`${sv.weeklyData.overallScore}%`,opacity:0.85,minHeight:8,transition:"height 0.5s"}}/>
                  <div style={{fontSize:10,color:"#6B7280",textAlign:"center",maxWidth:"100%",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{sv.name.split(" ").slice(0,2).join(" ")}</div>
                  <RAGChip rating={rating}/>
                </div>
              );
            })}
          </div>

          {/* Group domain averages */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10,marginTop:16}}>
            {["Safe","Effective","Caring","Responsive","Well-led"].map(domain=>{
              const avg = Math.round(DIGEST_SERVICES.reduce((s,sv)=>s+(sv.weeklyData.kloe[domain]||0),0)/DIGEST_SERVICES.length);
              const color = {Safe:"#FF5A6E",Effective:"#FF9A2F",Caring:"#16B5B8",Responsive:"#7A57D1","Well-led":"#7A57D1"}[domain];
              return(
                <div key={domain} style={{textAlign:"center",padding:"10px",background:"#F8FAFC",borderRadius:8}}>
                  <div style={{fontSize:10,fontWeight:700,color:"#6B7280",marginBottom:3,textTransform:"uppercase",letterSpacing:"0.5px"}}>{domain}</div>
                  <div style={{fontSize:18,fontWeight:800,color}}>{avg}%</div>
                  <div style={{fontSize:9,color:"#6B7280",marginTop:2}}>Group avg</div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Individual service cards */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:20}}>
          {DIGEST_SERVICES.map(sv=>(
            <DigestServiceCard key={sv.id} service={sv} onExpand={s=>{setExpanded(s);setView("service");}}/>
          ))}
        </div>

        {/* Board-ready summary */}
        <div style={{background:"#fff",borderRadius:12,padding:"22px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",border:"1px solid #E5E7EB"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
            <div style={{fontSize:14,fontWeight:700,color:"#062B7A",display:"flex",alignItems:"center",gap:7}}>
              <Icon name="reports" size={14} color="#16B5B8" strokeWidth={2}/> Board Summary — Week of {weekLabel}
            </div>
            <button onClick={()=>window.print()} style={{display:"flex",alignItems:"center",gap:6,padding:"7px 14px",borderRadius:8,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>
              <Icon name="reports" size={12} color="#374151" strokeWidth={1.8}/> Export / Print
            </button>
          </div>

          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20}}>
            <div>
              <div style={{fontSize:12,fontWeight:700,color:"#062B7A",marginBottom:8}}>Overall position</div>
              <div style={{fontSize:13,color:"#374151",lineHeight:1.7}}>
                The group is performing at <strong style={{color:groupCfg.color}}>{avgScore}% ({groupRating})</strong> this week across {totalServices} services. {criticalServices.length>0?`${criticalServices.length} service${criticalServices.length>1?"s require":"requires"} director attention.`:"All services are within acceptable compliance thresholds."}
                {dbsExpired>0&&` ${dbsExpired} DBS certificate${dbsExpired>1?"s are":" is"} expired and require immediate renewal.`}
                {openSafeguarding>0&&` There ${openSafeguarding>1?"are":"is"} ${openSafeguarding} open safeguarding concern${openSafeguarding>1?"s":""} being actively managed.`}
              </div>
            </div>
            <div>
              <div style={{fontSize:12,fontWeight:700,color:"#062B7A",marginBottom:8}}>Services by rating this week</div>
              {["Outstanding","Good","Requires Improvement","Inadequate"].map(rating=>{
                const count = DIGEST_SERVICES.filter(sv=>getRating(sv.weeklyData.overallScore)===rating).length;
                if(count===0) return null;
                const cfg = CQC_RATINGS[rating];
                return(
                  <div key={rating} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"6px 0",borderBottom:"1px solid #E5E7EB"}}>
                    <RAGChip rating={rating}/>
                    <span style={{fontSize:12,fontWeight:700,color:cfg.color}}>{count} service{count>1?"s":""}</span>
                  </div>
                );
              }).filter(Boolean)}
            </div>
          </div>

          {criticalServices.length>0&&(
            <div style={{marginTop:16,padding:"12px 14px",background:"#FDF8EE",borderRadius:9,border:"1px solid #FF9A2F33"}}>
              <div style={{fontSize:12,fontWeight:700,color:"#FF9A2F",marginBottom:8}}>Director actions required this week</div>
              {criticalServices.flatMap(sv=>sv.weeklyData.requiringDirectorAction.map((a,i)=>({service:sv.name,action:a,key:`${sv.id}-${i}`}))).map((item,i)=>(
                <div key={item.key} style={{display:"flex",gap:8,padding:"7px 0",borderBottom:"1px solid #FF9A2F22",alignItems:"flex-start"}}>
                  <span style={{background:"rgba(201,112,32,0.15)",color:"#FF9A2F",padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:700,flexShrink:0}}>{item.service.split(" ").slice(0,2).join(" ")}</span>
                  <span style={{fontSize:12,color:"#FF9A2F",lineHeight:1.5}}>{item.action}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

