// ── Priority colour helper ────────────────────────────────────
function priorityStyle(p){
  return {
    Critical:{bg:"#FDF0F0",fg:"#FF5A6E",dot:"#FF5A6E"},
    High:    {bg:"#FDF8EE",fg:"#FF9A2F",dot:"#FF9A2F"},
    Medium:  {bg:"#EDF5FE",fg:"#7A57D1",dot:"#7A57D1"},
    Low:     {bg:"#F8FAFC",fg:"#374151",dot:"#6B7280"},
    info:    {bg:"#F8FAFC",fg:"#374151",dot:"#6B7280"},
    health:  {bg:"#EDF5FE",fg:"#7A57D1",dot:"#7A57D1"},
    care:    {bg:"#FDF8EE",fg:"#FF9A2F",dot:"#FF9A2F"},
    family:  {bg:"#F0FDF4",fg:"#16B5B8",dot:"#16B5B8"},
    medication:{bg:"#FDF8EE",fg:"#FF9A2F",dot:"#FF9A2F"},
  }[p]||{bg:"#F8FAFC",fg:"#374151",dot:"#6B7280"};
}

// ── Briefing section card ─────────────────────────────────────
function BriefSection({title, icon, color="#16B5B8", count, alert, children, defaultOpen=true}){
  const [open,setOpen]=useState(defaultOpen);
  return(
    <div style={{background:"#fff",borderRadius:11,marginBottom:12,overflow:"hidden",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",border:`1px solid ${alert?"#FF9A2F33":"#E5E7EB"}`}}>
      <div onClick={()=>setOpen(o=>!o)} style={{padding:"13px 16px",display:"flex",justifyContent:"space-between",alignItems:"center",cursor:"pointer",borderBottom:open?"1px solid #E5E7EB":"none",background:alert?"#FEFAF8":"#fff",userSelect:"none"}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <div style={{width:28,height:28,borderRadius:8,background:`${color}15`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
            <Icon name={icon} size={13} color={color} strokeWidth={2}/>
          </div>
          <span style={{fontSize:13,fontWeight:700,color:"#062B7A"}}>{title}</span>
          {count!=null&&count>0&&<span style={{background:alert?"#FDF8EE":"#F1F3F8",color:alert?"#FF9A2F":"#6B7280",padding:"1px 8px",borderRadius:20,fontSize:11,fontWeight:700}}>{count}</span>}
        </div>
        <div style={{transform:open?"rotate(180deg)":"none",transition:"transform 0.2s"}}>
          <Icon name="chevronDown" size={13} color="#6B7280" strokeWidth={2}/>
        </div>
      </div>
      {open&&<div style={{padding:"14px 16px"}}>{children}</div>}
    </div>
  );
}

// ── Daily Briefing Page ───────────────────────────────────────
function DailyBriefingPage({onNavigate}){
  const [tasksDone, setTasksDone]= useState({});
  const [dismissed,setDismissed]= useState({});
  const b = DAILY_BRIEFING_DATA;
  const {day,date} = getDayContext();
  const greeting   = getGreeting();

  const criticalCount = b.tasksDueToday.filter(t=>t.priority==="Critical"&&!tasksDone[t.id]).length
    + b.expiryAlerts.filter(a=>a.severity==="critical").length
    + b.serviceUserUpdates.filter(u=>u.priority==="high"&&!dismissed[u.name+u.update]).length;

  const pendingTasks = b.tasksDueToday.filter(t=>!tasksDone[t.id]);
  const overdueCount = pendingTasks.filter(t=>t.overdue).length;

  return(<DemoFeatureGate feature="briefing">
    <div style={{height:"100%",overflowY:"auto",background:"#F8FAFC",fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif"}}>

      {/* ── HERO HEADER ── */}
      <div style={{background:"linear-gradient(135deg,#062B7A 0%,#2A4A7A 60%,#1A7A72 100%)",padding:"24px 28px 20px",position:"relative",overflow:"hidden"}}>
        {/* Background circles */}
        <div style={{position:"absolute",right:-40,top:-40,width:250,height:250,borderRadius:"50%",background:"rgba(43,191,178,0.07)"}}/>
        <div style={{position:"absolute",right:100,bottom:-60,width:180,height:180,borderRadius:"50%",background:"rgba(43,191,178,0.05)"}}/>
        <div style={{position:"absolute",left:-20,bottom:-30,width:120,height:120,borderRadius:"50%",background:"rgba(255,255,255,0.03)"}}/>

        <div style={{position:"relative",zIndex:1}}>
          {/* Greeting */}
          <div style={{marginBottom:16}}>
            <div style={{fontSize:13,color:"rgba(255,255,255,0.5)",marginBottom:4,fontWeight:500}}>{day}, {date}</div>
            <div style={{fontSize:24,fontWeight:900,color:"#fff",marginBottom:2}}>{greeting}, {b.manager} 👋</div>
            <div style={{fontSize:13,color:"rgba(255,255,255,0.65)"}}>{b.service} · Briefing generated at {new Date(b.generatedAt).toLocaleTimeString("en-GB",{hour:"2-digit",minute:"2-digit"})}</div>
          </div>

          {/* Today's status pills */}
          <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:18}}>
            {criticalCount>0&&(
              <div style={{background:"rgba(217,64,64,0.2)",border:"1px solid rgba(217,64,64,0.4)",borderRadius:20,padding:"5px 12px",display:"flex",alignItems:"center",gap:6}}>
                <div style={{width:6,height:6,borderRadius:"50%",background:"#F87171",animation:"pulse 1s infinite"}}/>
                <span style={{fontSize:12,fontWeight:700,color:"#FCA5A5"}}>{criticalCount} critical item{criticalCount>1?"s":""} need your attention</span>
              </div>
            )}
            <div style={{background:"rgba(255,255,255,0.1)",border:"1px solid rgba(255,255,255,0.15)",borderRadius:20,padding:"5px 12px",display:"flex",alignItems:"center",gap:6}}>
              <Icon name="staff" size={12} color="rgba(255,255,255,0.7)" strokeWidth={2}/>
              <span style={{fontSize:12,color:"rgba(255,255,255,0.7)",fontWeight:500}}>{b.staffingLevel.actual}/{b.staffingLevel.required} staff on shift — {b.staffingLevel.status}</span>
            </div>
            <div style={{background:"rgba(255,255,255,0.1)",border:"1px solid rgba(255,255,255,0.15)",borderRadius:20,padding:"5px 12px",display:"flex",alignItems:"center",gap:6}}>
              <Icon name="shield" size={12} color="rgba(255,255,255,0.7)" strokeWidth={2}/>
              <span style={{fontSize:12,color:"rgba(255,255,255,0.7)",fontWeight:500}}>Compliance: {b.compliancePulse.overall}% · {b.compliancePulse.trend}</span>
            </div>
            {b.openItems.safeguarding>0&&(
              <div style={{background:"rgba(217,64,64,0.15)",border:"1px solid rgba(217,64,64,0.3)",borderRadius:20,padding:"5px 12px",display:"flex",alignItems:"center",gap:6}}>
                <Icon name="shield" size={12} color="#FCA5A5" strokeWidth={2}/>
                <span style={{fontSize:12,color:"#FCA5A5",fontWeight:600}}>{b.openItems.safeguarding} open safeguarding concern</span>
              </div>
            )}
          </div>

          {/* Quick compliance scores */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:8}}>
            {[["Safe",b.compliancePulse.safe,"#F87171"],["Effective",b.compliancePulse.effective,"#FCD34D"],["Caring",b.compliancePulse.caring,"#6EE7B7"],["Responsive",b.compliancePulse.responsive,"#93C5FD"],["Well-led",b.compliancePulse.wellLed,"#C4B5FD"]].map(([d,s,c])=>(
              <div key={d} style={{textAlign:"center",padding:"10px 6px",background:"rgba(255,255,255,0.07)",borderRadius:9,border:"1px solid rgba(255,255,255,0.1)"}}>
                <div style={{fontSize:9,fontWeight:600,color:"rgba(255,255,255,0.5)",textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:4}}>{d}</div>
                <div style={{fontSize:18,fontWeight:900,color:c,lineHeight:1}}>{s}%</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── MAIN CONTENT ── */}
      <div style={{padding:"18px 22px",maxWidth:1100,margin:"0 auto"}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 360px",gap:16,alignItems:"start"}}>

          {/* ── LEFT COLUMN ── */}
          <div>

            {/* TODAY'S PRIORITY TASKS */}
            <BriefSection title="Today's Priority Tasks" icon="tasks" color="#FF5A6E" count={pendingTasks.length} alert={overdueCount>0}>
              {overdueCount>0&&(
                <div style={{background:"#FDF0F0",border:"1px solid #FF5A6E33",borderRadius:8,padding:"9px 12px",marginBottom:12,fontSize:12,color:"#FF5A6E",fontWeight:600}}>
                  ⚠ {overdueCount} task{overdueCount>1?"s are":" is"} overdue — action required today
                </div>
              )}
              {pendingTasks.length===0&&(
                <div style={{textAlign:"center",padding:"20px",color:"#16B5B8",fontWeight:700,fontSize:13}}>✓ All tasks for today are complete</div>
              )}
              {pendingTasks.map((task,i)=>{
                const pc=priorityStyle(task.priority);
                return(
                  <div key={task.id} style={{display:"flex",gap:10,padding:"10px 0",borderBottom:i<pendingTasks.length-1?"1px solid #E5E7EB":"none",alignItems:"flex-start"}}>
                    <div onClick={()=>setTasksDone(p=>({...p,[task.id]:true}))} style={{width:20,height:20,borderRadius:5,border:`2px solid ${tasksDone[task.id]?"#16B5B8":"#D1D5DB"}`,background:tasksDone[task.id]?"#16B5B8":"#fff",display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",flexShrink:0,marginTop:2,transition:"all 0.15s"}}>
                      {tasksDone[task.id]&&<Icon name="check" size={10} color="white" strokeWidth={3}/>}
                    </div>
                    <div style={{flex:1}}>
                      <div style={{fontSize:13,fontWeight:500,color:"#062B7A",marginBottom:3,textDecoration:tasksDone[task.id]?"line-through":"none"}}>{task.title}</div>
                      <div style={{display:"flex",gap:6,flexWrap:"wrap",alignItems:"center"}}>
                        <span style={{background:pc.bg,color:pc.fg,padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:700}}>{task.priority}</span>
                        <span style={{fontSize:10,color:"#6B7280"}}>{task.module}</span>
                        {task.overdue&&<span style={{background:"#FDF0F0",color:"#FF5A6E",padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:700}}>{task.daysOverdue}d overdue</span>}
                        {task.dueToday&&!task.overdue&&<span style={{background:"#F0FDF4",color:"#16B5B8",padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:600}}>Due today</span>}
                      </div>
                    </div>
                    <button onClick={()=>onNavigate&&onNavigate(task.module==="Staff Records"?"staff":task.module==="Service Users"?"serviceusers":task.module==="Safeguarding"?"safeguarding":task.module==="Medication Audits"?"medication":"tasks")} style={{padding:"4px 10px",borderRadius:6,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:10,fontWeight:600,cursor:"pointer",fontFamily:"inherit",flexShrink:0}}>Go →</button>
                  </div>
                );
              })}
            </BriefSection>

            {/* SERVICE USER UPDATES */}
            <BriefSection title="Service User Updates" icon="serviceusers" color="#7A57D1" count={b.serviceUserUpdates.filter(u=>!dismissed[u.name+u.update]).length} alert={b.serviceUserUpdates.some(u=>u.priority==="high"&&!dismissed[u.name+u.update])}>
              {b.serviceUserUpdates.filter(u=>!dismissed[u.name+u.update]).map((upd,i,arr)=>{
                const pc=priorityStyle(upd.type);
                return(
                  <div key={i} style={{display:"flex",gap:10,padding:"10px 0",borderBottom:i<arr.length-1?"1px solid #E5E7EB":"none",alignItems:"flex-start"}}>
                    <div style={{width:8,height:8,borderRadius:"50%",background:pc.dot,flexShrink:0,marginTop:5}}/>
                    <div style={{flex:1}}>
                      <div style={{fontSize:12,fontWeight:700,color:"#062B7A",marginBottom:2}}>{upd.name}</div>
                      <div style={{fontSize:12,color:"#374151",lineHeight:1.5}}>{upd.update}</div>
                    </div>
                    <div style={{display:"flex",gap:5,flexShrink:0}}>
                      <span style={{background:pc.bg,color:pc.fg,padding:"2px 7px",borderRadius:20,fontSize:10,fontWeight:600}}>{upd.type}</span>
                      <button onClick={()=>setDismissed(p=>({...p,[upd.name+upd.update]:true}))} style={{background:"none",border:"none",cursor:"pointer",color:"#D1D5DB",fontSize:14,padding:"0 3px",lineHeight:1}}>×</button>
                    </div>
                  </div>
                );
              })}
              {b.serviceUserUpdates.every(u=>dismissed[u.name+u.update])&&(
                <div style={{fontSize:12,color:"#16B5B8",fontWeight:500,textAlign:"center",padding:"16px 0"}}>✓ All service user updates reviewed</div>
              )}
            </BriefSection>

            {/* EXPIRY ALERTS */}
            <BriefSection title="Expiry & Review Alerts" icon="alert" color="#FF9A2F" count={b.expiryAlerts.filter(a=>a.severity==="critical"||a.severity==="high").length} alert={b.expiryAlerts.some(a=>a.severity==="critical")}>
              {b.expiryAlerts.map((alert,i)=>{
                const cfg={critical:{bg:"#FDF0F0",fg:"#FF5A6E"},high:{bg:"#FDF0F0",fg:"#FF5A6E"},medium:{bg:"#FDF8EE",fg:"#FF9A2F"},low:{bg:"#F8FAFC",fg:"#6B7280"}}[alert.severity];
                return(
                  <div key={i} style={{display:"flex",gap:10,padding:"9px 0",borderBottom:i<b.expiryAlerts.length-1?"1px solid #E5E7EB":"none",alignItems:"center"}}>
                    <div style={{flex:1}}>
                      <div style={{display:"flex",gap:6,alignItems:"center",marginBottom:2,flexWrap:"wrap"}}>
                        <span style={{fontSize:12,fontWeight:700,color:"#062B7A"}}>{alert.person}</span>
                        <span style={{background:"#F1F3F8",color:"#374151",padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:600}}>{alert.type}</span>
                      </div>
                      <div style={{fontSize:11,color:"#374151"}}>{alert.note}</div>
                    </div>
                    <div style={{textAlign:"right",flexShrink:0}}>
                      {alert.daysOverdue
                        ?<span style={{background:"#FDF0F0",color:"#FF5A6E",padding:"2px 9px",borderRadius:20,fontSize:11,fontWeight:700}}>{alert.daysOverdue}d expired</span>
                        :<span style={{background:cfg.bg,color:cfg.fg,padding:"2px 9px",borderRadius:20,fontSize:11,fontWeight:700}}>{alert.daysRemaining}d remaining</span>
                      }
                    </div>
                  </div>
                );
              })}
            </BriefSection>

            {/* RECENT ACTIVITY FLAGS */}
            <BriefSection title="Recent Activity" icon="activity" color="#374151" defaultOpen={false}>
              {b.recentActivity.map((act,i)=>(
                <div key={i} style={{display:"flex",gap:10,padding:"8px 0",borderBottom:i<b.recentActivity.length-1?"1px solid #E5E7EB":"none",alignItems:"flex-start"}}>
                  <span style={{fontSize:11,color:"#6B7280",flexShrink:0,minWidth:90,marginTop:1}}>{act.time}</span>
                  <div style={{flex:1}}>
                    <div style={{fontSize:12,color:"#062B7A"}}><strong>{act.user}</strong> — {act.action}</div>
                    {act.flag&&<div style={{fontSize:11,color:"#FF9A2F",marginTop:3,padding:"4px 8px",background:"#FDF8EE",borderRadius:6}}>⚠ {act.flagNote}</div>}
                  </div>
                </div>
              ))}
            </BriefSection>

          </div>

          {/* ── RIGHT COLUMN ── */}
          <div>

            {/* STAFF ON SHIFT */}
            <BriefSection title="Staff Today" icon="staff" color="#16B5B8" alert={b.staffOnShift.some(s=>s.alert)}>
              {b.staffOnShift.map((staff,i)=>(
                <div key={i} style={{padding:"8px 0",borderBottom:i<b.staffOnShift.length-1?"1px solid #E5E7EB":"none"}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:staff.alert?4:0}}>
                    <div>
                      <div style={{fontSize:12,fontWeight:600,color:"#062B7A"}}>{staff.name}</div>
                      <div style={{fontSize:11,color:"#6B7280"}}>{staff.role} · {staff.start}–{staff.end}</div>
                    </div>
                    <span style={{
                      background:staff.status==="On shift"?"#F0FDF4":staff.status==="Later today"?"#EDF5FE":"#F8FAFC",
                      color:staff.status==="On shift"?"#16B5B8":staff.status==="Later today"?"#7A57D1":"#6B7280",
                      padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:600,whiteSpace:"nowrap",
                    }}>{staff.status}</span>
                  </div>
                  {staff.alert&&<div style={{fontSize:11,color:"#FF5A6E",background:"#FDF0F0",padding:"4px 8px",borderRadius:6}}>⚠ {staff.alert}</div>}
                </div>
              ))}
            </BriefSection>

            {/* CQC READINESS PULSE */}
            <BriefSection title="CQC Readiness" icon="mock" color="#7A57D1">
              <div style={{textAlign:"center",padding:"10px 0 16px"}}>
                <div style={{fontSize:42,fontWeight:900,color:CQC_RATINGS[b.cqcReadiness.rating]?.color||"#7A57D1",lineHeight:1,marginBottom:6}}>{b.cqcReadiness.score}%</div>
                <RAGChip rating={b.cqcReadiness.rating} size="large"/>
                <div style={{fontSize:11,color:"#6B7280",marginTop:10}}>Last mock: {b.cqcReadiness.lastMockDate}</div>
                <div style={{fontSize:11,color:"#6B7280"}}>Next due: {b.cqcReadiness.nextMockDue}</div>
              </div>
              <div style={{height:6,background:"#E5E7EB",borderRadius:3,overflow:"hidden"}}>
                <div style={{height:"100%",width:`${b.cqcReadiness.score}%`,background:`linear-gradient(90deg,${CQC_RATINGS[b.cqcReadiness.rating]?.color||"#7A57D1"},${CQC_RATINGS[b.cqcReadiness.rating]?.color||"#7A57D1"}aa)`,borderRadius:3}}/>
              </div>
              <button onClick={()=>onNavigate&&onNavigate("inspection")} style={{width:"100%",marginTop:12,padding:"8px",borderRadius:8,border:"none",background:"linear-gradient(135deg,#062B7A,#2A4A7A)",color:"#fff",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>
                Open Inspection Mode →
              </button>
            </BriefSection>

            {/* THIS WEEK */}
            <BriefSection title="Upcoming This Week" icon="calendar" color="#7A57D1" defaultOpen={true}>
              {b.upcomingThisWeek.map((item,i)=>(
                <div key={i} style={{display:"flex",gap:8,padding:"8px 0",borderBottom:i<b.upcomingThisWeek.length-1?"1px solid #E5E7EB":"none",alignItems:"flex-start"}}>
                  <span style={{fontSize:10,fontWeight:700,color:item.day==="Today"?"#FF5A6E":"#7A57D1",background:item.day==="Today"?"#FDF0F0":"#EDF5FE",padding:"2px 7px",borderRadius:20,flexShrink:0,marginTop:1,minWidth:55,textAlign:"center"}}>{item.day}</span>
                  <div>
                    <div style={{fontSize:12,color:"#062B7A",fontWeight:500}}>{item.item}</div>
                    <div style={{fontSize:10,color:"#6B7280"}}>{item.module}</div>
                  </div>
                </div>
              ))}
            </BriefSection>

            {/* THIS WEEK'S WINS */}
            <BriefSection title="This Week's Highlights" icon="check" color="#16B5B8" defaultOpen={true}>
              {b.weekHighlights.map((h,i)=>(
                <div key={i} style={{display:"flex",gap:8,padding:"7px 0",borderBottom:i<b.weekHighlights.length-1?"1px solid #E5E7EB":"none",alignItems:"flex-start"}}>
                  <div style={{width:18,height:18,borderRadius:"50%",background:"#F0FDF4",border:"1.5px solid #16B5B844",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,marginTop:1}}>
                    <Icon name="check" size={9} color="#16B5B8" strokeWidth={3}/>
                  </div>
                  <span style={{fontSize:12,color:"#374151",lineHeight:1.5}}>{h}</span>
                </div>
              ))}
            </BriefSection>

            {/* OPEN ITEMS SUMMARY */}
            <BriefSection title="Open Items Summary" icon="dashboard" color="#062B7A" defaultOpen={false}>
              {[
                {label:"Open safeguarding concerns",  value:b.openItems.safeguarding,  alert:b.openItems.safeguarding>0, nav:"safeguarding"},
                {label:"Unresolved complaints",        value:b.openItems.complaints,     alert:b.openItems.complaints>0,   nav:"serviceusers"},
                {label:"Incomplete tasks",             value:b.openItems.tasks,          alert:b.openItems.tasks>5,         nav:"tasks"},
                {label:"Active escalations",           value:b.openItems.escalations,    alert:b.openItems.escalations>0,  nav:"accountability"},
                {label:"Overdue audits",               value:b.openItems.overdueAudits,  alert:b.openItems.overdueAudits>0,nav:"audits"},
              ].map((item,i,arr)=>(
                <div key={i} onClick={()=>onNavigate&&onNavigate(item.nav)} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 0",borderBottom:i<arr.length-1?"1px solid #E5E7EB":"none",cursor:"pointer"}}
                  onMouseEnter={e=>e.currentTarget.style.background="#F8FAFC"}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <span style={{fontSize:12,color:"#374151"}}>{item.label}</span>
                  <span style={{fontSize:13,fontWeight:800,color:item.alert?"#FF5A6E":"#16B5B8"}}>{item.value}</span>
                </div>
              ))}
            </BriefSection>

          </div>
        </div>
      </div>
    </div>
  </DemoFeatureGate>);
}

