// ── Credit usage bar ──────────────────────────────────────────
function CreditBar({ used, total, color="#16B5B8" }){
  if(total===0) return null;
  const pct   = Math.min((used/total)*100,100);
  const warn  = pct>=80;
  const c     = pct>=90?"#FF5A6E":pct>=80?"#FF9A2F":color;
  return(
    <div>
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:4,fontSize:11}}>
        <span style={{color:"#6B7280"}}>{used} of {total===999?"Unlimited":total} analyses used</span>
        <span style={{color:c,fontWeight:700}}>{total===999?"Unlimited":`${total-used} remaining`}</span>
      </div>
      {total!==999&&(
        <div style={{height:6,background:"#E5E7EB",borderRadius:3,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${pct}%`,background:c,borderRadius:3,transition:"width 0.5s"}}/>
        </div>
      )}
      {warn&&total!==999&&<div style={{fontSize:10,color:"#FF9A2F",marginTop:3}}>⚠ Running low — client may need to upgrade</div>}
    </div>
  );
}

