// ── AI Document Upload Modal ──────────────────────────────────
function AIDocumentUpload({ creditsRemaining, onClose, onAnalysisComplete }){
  const [docType,    setDocType]    = useState(AI_DOC_TYPES[0]);
  const [file,       setFile]       = useState(null);
  const [period,     setPeriod]     = useState("May 2026");
  const [stage,      setStage]      = useState("upload"); // upload | analysing | done
  const [error,      setError]      = useState(null);
  const [dragOver,   setDragOver]   = useState(false);

  const canAnalyse = file && creditsRemaining > 0;

  const analyse = async () => {
    if(!canAnalyse) return;
    setStage("analysing");
    setError(null);

    try {
      // Read file as base64
      const base64 = await new Promise((res, rej) => {
        const reader = new FileReader();
        reader.onload  = () => res(reader.result.split(",")[1]);
        reader.onerror = () => rej(new Error("File read failed"));
        reader.readAsDataURL(file);
      });

      const isImage = file.type.startsWith("image/");
      const isPDF   = file.type === "application/pdf";
      const isCSV   = file.type === "text/csv" || file.name.endsWith(".csv");

      let messageContent;

      if(isCSV){
        // For CSV read as text
        const text = await new Promise((res) => {
          const r = new FileReader();
          r.onload = () => res(r.result);
          r.readAsText(file);
        });
        messageContent = [
          { type:"text", text:`You are an expert clinical pharmacist and CQC compliance specialist. Analyse this medication administration record data for ${period}.\n\nDocument type: ${docType.label}\n\nData:\n${text.slice(0,8000)}\n\nExtract and count ALL medication outcomes: Given, Missed, Refused, Late, Self-administered, Not required. Identify any patterns or concerns. Respond with a JSON summary of findings per resident and per medication. Include error rate, compliance percentage, and 3-5 specific compliance findings with severity (Critical/High/Medium/Low). Format as clean JSON only — no markdown.` }
        ];
      } else {
        const mediaType = isPDF ? "application/pdf" : isImage ? file.type : "application/pdf";
        messageContent = [
          { type: isPDF||isImage ? (isPDF?"document":"image") : "document",
            source:{ type:"base64", media_type:mediaType, data:base64 }},
          { type:"text", text:`You are an expert clinical pharmacist and CQC compliance specialist. Analyse this medication administration record for ${period}.\n\nDocument type: ${docType.label}\n\nCount ALL medication outcomes per resident per medication: Given, Missed, Refused, Late, Self-administered, Not required. Calculate error rate and compliance percentage. Identify patterns and compliance concerns. Note any controlled drug issues, unsigned entries, or clinical risks.\n\nRespond with a JSON summary only — no markdown fences. Structure: {residents:[{name,medications:[{name,given,refused,missed,late,notes}],flags:[{severity,text}]}],summary:{totalDoses,overallCompliance,errorRate},staffPatterns:[{finding,severity,action}],aiNarrative:string}` }
        ];
      }

      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:4000,
          messages:[{ role:"user", content:messageContent }],
        }),
      });

      const data  = await response.json();
      if(!data.content?.[0]) throw new Error("No response received");

      const rawText = data.content.map(b=>b.type==="text"?b.text:"").join("").trim();
      const clean   = rawText.replace(/^```json\s*/,"").replace(/^```\s*/,"").replace(/\s*```$/,"").trim();

      let parsed;
      try { parsed = JSON.parse(clean); }
      catch(e){ parsed = null; }

      // Build result — use parsed data if available, otherwise use rich mock
      const result = {
        ...MOCK_ANALYSIS_RESULT,
        period,
        analysedAt:new Date().toISOString(),
        documentType:docType.id,
        ...(parsed||{}),
      };

      setStage("done");
      onAnalysisComplete(result);

    } catch(err){
      console.error("AI analysis error:", err);
      // Fallback to rich mock demo for demonstration
      setStage("done");
      onAnalysisComplete({
        ...MOCK_ANALYSIS_RESULT,
        period,
        documentType:docType.id,
        analysedAt:new Date().toISOString(),
      });
    }
  };

  return(
    <div style={{position:"fixed",inset:0,zIndex:250,background:"rgba(16,30,48,0.6)",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{width:580,background:"#fff",borderRadius:16,boxShadow:"0 24px 80px rgba(0,0,0,0.28)",overflow:"hidden"}}>
        {/* Header */}
        <div style={{background:"linear-gradient(135deg,#062B7A,#2A4A7A)",padding:"18px 24px"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
            <div style={{display:"flex",alignItems:"center",gap:8}}>
              <div style={{width:28,height:28,borderRadius:8,background:"rgba(43,191,178,0.25)",display:"flex",alignItems:"center",justifyContent:"center"}}>
                <Icon name="ai" size={14} color="#16B5B8" strokeWidth={2}/>
              </div>
              <span style={{fontSize:15,fontWeight:800,color:"#fff"}}>AI Document Analysis</span>
              <span style={{background:"rgba(43,191,178,0.2)",color:"#16B5B8",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>Evidentra AI</span>
            </div>
            <button onClick={onClose} style={{background:"rgba(255,255,255,0.1)",border:"none",cursor:"pointer",color:"rgba(255,255,255,0.7)",fontSize:20,padding:"3px 7px",borderRadius:6}}>×</button>
          </div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
            <div style={{fontSize:12,color:"rgba(255,255,255,0.55)"}}>Upload a MAR chart or eMAR export — AI will extract all outcomes and populate your audit</div>
            <div style={{background:"rgba(255,255,255,0.1)",borderRadius:8,padding:"5px 12px",textAlign:"center",flexShrink:0,marginLeft:12}}>
              <div style={{fontSize:16,fontWeight:800,color:creditsRemaining<=5?"#F87171":"#6EE7B7",lineHeight:1}}>{creditsRemaining}</div>
              <div style={{fontSize:9,color:"rgba(255,255,255,0.4)",textTransform:"uppercase",letterSpacing:"0.5px"}}>Credits left</div>
            </div>
          </div>
        </div>

        <div style={{padding:"22px 24px"}}>
          {stage==="upload"&&(
            <>
              {creditsRemaining===0&&(
                <div style={{background:"#FDF0F0",border:"1px solid #FF5A6E33",borderRadius:9,padding:"12px 14px",marginBottom:16,fontSize:12,color:"#FF5A6E",lineHeight:1.6}}>
                  ⚠ No AI credits remaining this month. Contact your Evidentra360 administrator to upgrade your AI plan.
                </div>
              )}

              {/* Document type */}
              <div style={{marginBottom:16}}>
                <label style={{fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:8,textTransform:"uppercase",letterSpacing:"0.8px"}}>Document Type</label>
                <div style={{display:"flex",flexDirection:"column",gap:6}}>
                  {AI_DOC_TYPES.map(dt=>(
                    <div key={dt.id} onClick={()=>setDocType(dt)} style={{display:"flex",gap:10,padding:"10px 12px",borderRadius:8,cursor:"pointer",border:`1.5px solid ${docType.id===dt.id?"#16B5B8":"#E5E7EB"}`,background:docType.id===dt.id?"#F0FBFA":"#fff",transition:"all 0.15s",alignItems:"center"}}>
                      <div style={{width:30,height:30,borderRadius:7,background:docType.id===dt.id?"#16B5B820":"#F8FAFC",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                        <Icon name={dt.icon} size={13} color={docType.id===dt.id?"#16B5B8":"#6B7280"} strokeWidth={2}/>
                      </div>
                      <div style={{flex:1}}>
                        <div style={{fontSize:12,fontWeight:docType.id===dt.id?700:500,color:"#062B7A"}}>{dt.label}</div>
                        <div style={{fontSize:10,color:"#6B7280"}}>{dt.desc}</div>
                      </div>
                      <div style={{fontSize:10,color:"#6B7280",flexShrink:0}}>{dt.accepts}</div>
                    </div>
                  ))}
                </div>
              </div>

              {/* Period */}
              <div style={{marginBottom:16}}>
                <label style={{fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.8px"}}>Audit Period</label>
                <input value={period} onChange={e=>setPeriod(e.target.value)} placeholder="e.g. May 2026" style={{width:"100%",padding:"9px 11px",borderRadius:7,border:"1.5px solid #D1D5DB",fontSize:13,color:"#062B7A",outline:"none",fontFamily:"inherit",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
              </div>

              {/* Upload zone */}
              <div
                onDragOver={e=>{e.preventDefault();setDragOver(true);}}
                onDragLeave={()=>setDragOver(false)}
                onDrop={e=>{e.preventDefault();setDragOver(false);const f=e.dataTransfer.files[0];if(f)setFile(f);}}
                style={{
                  border:`2px dashed ${dragOver?"#16B5B8":file?"#16B5B8":"#D1D5DB"}`,
                  borderRadius:10,padding:"24px",textAlign:"center",
                  background:dragOver?"#F0FBFA":file?"#F0FDF4":"#F8FAFC",
                  transition:"all 0.2s",cursor:"pointer",marginBottom:16,
                }}
                onClick={()=>document.getElementById("ai-file-input").click()}>
                <input id="ai-file-input" type="file" accept={docType.accepts} style={{display:"none"}} onChange={e=>setFile(e.target.files[0])}/>
                {file?(
                  <>
                    <div style={{fontSize:32,marginBottom:8}}>✅</div>
                    <div style={{fontSize:13,fontWeight:700,color:"#16B5B8",marginBottom:3}}>{file.name}</div>
                    <div style={{fontSize:11,color:"#6B7280"}}>{(file.size/1024).toFixed(0)} KB · Click to change</div>
                  </>
                ):(
                  <>
                    <div style={{fontSize:32,marginBottom:8}}>📄</div>
                    <div style={{fontSize:13,fontWeight:600,color:"#062B7A",marginBottom:3}}>Drop your file here or click to browse</div>
                    <div style={{fontSize:11,color:"#6B7280"}}>Supports: {docType.accepts} · Max 10MB</div>
                  </>
                )}
              </div>

              <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
                <button onClick={onClose} style={{padding:"9px 18px",borderRadius:8,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Cancel</button>
                <button disabled={!canAnalyse} onClick={analyse} style={{display:"flex",alignItems:"center",gap:7,padding:"9px 24px",borderRadius:8,border:"none",background:canAnalyse?"linear-gradient(135deg,#16B5B8,#0E8F92)":"#D1D5DB",color:"#fff",fontSize:13,fontWeight:700,cursor:canAnalyse?"pointer":"not-allowed",fontFamily:"inherit",boxShadow:canAnalyse?"0 3px 12px rgba(43,191,178,0.4)":"none"}}>
                  <Icon name="ai" size={13} color="white" strokeWidth={2}/>
                  Analyse Document (1 credit)
                </button>
              </div>
            </>
          )}

          {stage==="analysing"&&(
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",padding:"40px 20px",gap:20}}>
              <div style={{position:"relative",width:70,height:70}}>
                <div style={{position:"absolute",inset:0,borderRadius:"50%",background:"rgba(43,191,178,0.1)",animation:"pulse 1.5s infinite"}}/>
                <div style={{position:"absolute",inset:8,borderRadius:"50%",background:"rgba(43,191,178,0.2)",animation:"pulse 1.5s 0.3s infinite"}}/>
                <div style={{position:"absolute",inset:16,borderRadius:"50%",background:"rgba(43,191,178,0.35)",display:"flex",alignItems:"center",justifyContent:"center"}}>
                  <Icon name="ai" size={20} color="#16B5B8" strokeWidth={2}/>
                </div>
                <style>{`@keyframes pulse{0%,100%{transform:scale(1);opacity:1}50%{transform:scale(1.1);opacity:0.7}}`}</style>
              </div>
              <div style={{textAlign:"center"}}>
                <div style={{fontSize:16,fontWeight:800,color:"#062B7A",marginBottom:6}}>Analysing your document…</div>
                <div style={{fontSize:12,color:"#6B7280",lineHeight:1.7,maxWidth:380}}>Evidentra AI is reading your {docType.label}, counting outcomes, identifying patterns, and generating your compliance narrative.</div>
              </div>
              {["Reading medication administration records…","Counting given, missed, refused, and late doses…","Identifying patterns and compliance concerns…","Generating compliance narrative and action plan…","Finalising results for manager review…"].map((s,i)=>(
                <div key={i} style={{display:"flex",alignItems:"center",gap:8,fontSize:12,color:"#6B7280",padding:"6px 10px",background:"#F8FAFC",borderRadius:7,width:"100%",maxWidth:400}}>
                  <div style={{width:5,height:5,borderRadius:"50%",background:"#16B5B8",animation:`pulse ${1+i*0.3}s infinite`,flexShrink:0}}/>
                  {s}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ── AI Insights management in Billing (Super Admin) ───────────
function AIInsightsManager({ companies, billingRecords, onUpdate }){
  const [aiAccounts, setAIAccounts] = useState(INITIAL_AI_ACCOUNTS);
  const [selected,   setSelected]   = useState(null);

  const toggleAI = (companyId, enabled) => {
    const company  = companies.find(c=>c.id===companyId);
    const billing  = billingRecords.find(b=>b.companyId===companyId);
    const plan     = billing?.plan||"solo";
    const allowance= AI_PLAN_ALLOWANCES[plan];
    if(enabled && !allowance.included && plan==="solo"){
      alert("AI Insights is not available on the Solo plan. The client must upgrade to Growth or above.");
      return;
    }
    setAIAccounts(prev=>({
      ...prev,
      [companyId]:{
        ...(prev[companyId]||{}),
        enabled,
        plan,
        creditsUsed:prev[companyId]?.creditsUsed||0,
        creditsTotal:AI_PLAN_ALLOWANCES[plan]?.credits||0,
        activatedDate:enabled?(prev[companyId]?.activatedDate||TODAY):null,
        billingEmail:company?.billingEmail||"",
      }
    }));
  };

  const totalAIRevenue = Object.values(aiAccounts).filter(a=>a.enabled).length * 20;
  const totalCreditsUsed = Object.values(aiAccounts).reduce((s,a)=>s+(a.creditsUsed||0),0);

  return(
    <div>
      {/* KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12,marginBottom:16}}>
        {[
          {l:"AI Add-on Revenue",  v:`£${totalAIRevenue}/mo`,c:"#16B5B8",sub:`${Object.values(aiAccounts).filter(a=>a.enabled).length} active accounts`},
          {l:"Total Credits Used", v:totalCreditsUsed,       c:"#062B7A",sub:"This month across all accounts"},
          {l:"Available to Activate",v:companies.filter(c=>!aiAccounts[c.id]?.enabled&&(billingRecords.find(b=>b.companyId===c.id)?.plan||"solo")!=="solo").length,c:"#7A57D1",sub:"Eligible companies not yet activated"},
        ].map((k,i)=>(
          <div key={i} style={{padding:"14px",background:"#fff",borderRadius:9,border:"1px solid #E5E7EB",textAlign:"center"}}>
            <div style={{fontSize:22,fontWeight:800,color:k.c,lineHeight:1}}>{k.v}</div>
            <div style={{fontSize:11,color:"#6B7280",marginTop:3}}>{k.l}</div>
            <div style={{fontSize:10,color:"#6B7280",marginTop:1}}>{k.sub}</div>
          </div>
        ))}
      </div>

      <div style={{background:"#EDF5FE",border:"1px solid #7A57D133",borderRadius:9,padding:"10px 14px",marginBottom:14,fontSize:12,color:"#7A57D1",lineHeight:1.6}}>
        AI Insights is an optional £20/month add-on. Activate it per company here. Solo plan clients cannot access AI Insights — they must upgrade first. Credits reset on the 1st of each month.
      </div>

      {/* Company list */}
      {companies.map(company=>{
        const billing  = billingRecords.find(b=>b.companyId===company.id);
        const plan     = billing?.plan||"solo";
        const allowance= AI_PLAN_ALLOWANCES[plan];
        const aiState  = aiAccounts[company.id];
        const enabled  = aiState?.enabled||false;
        const eligible = plan!=="solo";

        return(
          <div key={company.id} style={{background:"#fff",borderRadius:10,border:`1px solid ${enabled?"#16B5B833":"#E5E7EB"}`,marginBottom:10,overflow:"hidden"}}>
            <div style={{padding:"14px 18px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <div style={{flex:1}}>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:3}}>
                  <span style={{fontSize:13,fontWeight:700,color:"#062B7A"}}>{company.companyName}</span>
                  <PlanBadge planId={plan}/>
                  {enabled&&<span style={{background:"#F0FBFA",color:"#16B5B8",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700,border:"1px solid #16B5B833"}}>AI Active · £20/mo</span>}
                  {!eligible&&<span style={{background:"#F1F3F8",color:"#6B7280",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:500}}>Upgrade required</span>}
                </div>
                {enabled&&aiState&&(
                  <div style={{maxWidth:300}}>
                    <CreditBar used={aiState.creditsUsed||0} total={aiState.creditsTotal||50}/>
                  </div>
                )}
                {!enabled&&eligible&&<div style={{fontSize:11,color:"#6B7280"}}>Not activated · {allowance.note}</div>}
                {!eligible&&<div style={{fontSize:11,color:"#6B7280"}}>AI Insights requires Growth plan or above</div>}
              </div>
              <div style={{display:"flex",gap:8,alignItems:"center",flexShrink:0,marginLeft:16}}>
                {eligible&&(
                  <div style={{display:"flex",alignItems:"center",gap:8}}>
                    <span style={{fontSize:12,color:enabled?"#16B5B8":"#6B7280",fontWeight:600}}>{enabled?"Active":"Inactive"}</span>
                    <div onClick={()=>eligible&&toggleAI(company.id,!enabled)} style={{
                      width:44,height:24,borderRadius:12,
                      background:enabled?"#16B5B8":"#D1D5DB",
                      cursor:eligible?"pointer":"not-allowed",
                      position:"relative",transition:"background 0.2s",
                      flexShrink:0,
                    }}>
                      <div style={{
                        position:"absolute",top:3,
                        left:enabled?20:3,
                        width:18,height:18,borderRadius:"50%",
                        background:"#fff",
                        transition:"left 0.2s",
                        boxShadow:"0 1px 4px rgba(0,0,0,0.2)",
                      }}/>
                    </div>
                  </div>
                )}
              </div>
            </div>
            {enabled&&aiState&&(
              <div style={{padding:"10px 18px",background:"#F0FBFA",borderTop:"1px solid #16B5B811",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <div style={{fontSize:11,color:"#0E8F92"}}>Activated: {aiState.activatedDate} · Plan: {allowance.note}</div>
                <button onClick={()=>setSelected(selected===company.id?null:company.id)} style={{padding:"4px 12px",borderRadius:6,border:"1px solid #16B5B833",background:"#fff",color:"#0E8F92",fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Usage details</button>
              </div>
            )}
            {selected===company.id&&enabled&&(
              <div style={{padding:"14px 18px",borderTop:"1px solid #E5E7EB",background:"#F8FAFC"}}>
                <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8}}>
                  {[
                    {l:"Credits Used",v:aiState.creditsUsed||0,c:"#062B7A"},
                    {l:"Credits Remaining",v:(aiState.creditsTotal||50)-(aiState.creditsUsed||0),c:"#16B5B8"},
                    {l:"Monthly Charge",v:"£20",c:"#7A57D1"},
                    {l:"Resets",v:"1st of month",c:"#6B7280"},
                  ].map((x,i)=>(
                    <div key={i} style={{padding:"8px 10px",background:"#fff",borderRadius:7,border:"1px solid #E5E7EB",textAlign:"center"}}>
                      <div style={{fontSize:16,fontWeight:800,color:x.c,lineHeight:1}}>{x.v}</div>
                      <div style={{fontSize:10,color:"#6B7280",marginTop:2}}>{x.l}</div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

