// ── Delegation detail drawer ──────────────────────────────────
function DelegationDrawer({ item, role, onClose, onUpdate }){
  const [d,         setD]         = useState({...item});
  const [response,  setResponse]  = useState("");
  const [showAudit, setShowAudit] = useState(false);
  const typeCfg = DELEGATION_TYPES[d.type]||DELEGATION_TYPES.note;
  const sc      = severityColor(d.priority==="Urgent"?"Critical":d.priority);
  const isRecipient = role==="manager"||role==="staff";
  const isSender    = role==="director"||role==="superadmin";
  const canRespond  = isRecipient && !d.completedAt;
  const canComplete = isSender    && d.response && !d.completedAt;

  const statusColors = {
    Open:         {bg:"#FDF8EE",fg:"#FF9A2F"},
    Acknowledged: {bg:"#EDF5FE",fg:"#7A57D1"},
    "In Progress":{bg:"#EDF5FE",fg:"#7A57D1"},
    Completed:    {bg:"#F0FDF4",fg:"#16B5B8"},
    Overdue:      {bg:"#FDF0F0",fg:"#FF5A6E"},
    Escalated:    {bg:"#FDF0F0",fg:"#FF5A6E"},
  };
  const stc = statusColors[d.status]||statusColors.Open;

  const acknowledge = () => {
    const now = new Date().toISOString();
    const updated = {...d,
      acknowledgedAt:now,
      readAt:d.readAt||now,
      status:"Acknowledged",
      auditTrail:[...d.auditTrail,{action:"Acknowledged",by:"Sarah Mitchell",at:now}],
    };
    setD(updated); onUpdate(updated);
  };

  const sendResponse = () => {
    if(!response.trim()) return;
    const now = new Date().toISOString();
    const updated = {...d,
      response:response.trim(),
      status:"In Progress",
      auditTrail:[...d.auditTrail,{action:"Response sent",by:"Sarah Mitchell",at:now}],
    };
    setD(updated); onUpdate(updated); setResponse("");
  };

  const markComplete = () => {
    const now = new Date().toISOString();
    const updated = {...d,
      completedAt:now,
      status:"Completed",
      auditTrail:[...d.auditTrail,{action:"Marked complete",by:role==="director"?"James Thornton":"Sarah Mitchell",at:now}],
    };
    setD(updated); onUpdate(updated);
  };

  return(
    <div style={{position:"fixed",inset:0,zIndex:100,display:"flex"}}>
      <div onClick={onClose} style={{flex:1,background:"rgba(16,30,48,0.4)"}}/>
      <div style={{width:580,background:"#fff",height:"100vh",display:"flex",flexDirection:"column",boxShadow:"-8px 0 40px rgba(0,0,0,0.15)"}}>
        {/* Header */}
        <div style={{padding:"16px 20px",borderBottom:"1px solid #E5E7EB",flexShrink:0,background:`${typeCfg.bg}`}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
            <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
              <div style={{width:30,height:30,borderRadius:8,background:typeCfg.color+"22",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                <Icon name={typeCfg.icon} size={14} color={typeCfg.color} strokeWidth={2}/>
              </div>
              <span style={{fontSize:11,fontWeight:700,color:typeCfg.color,textTransform:"uppercase",letterSpacing:"0.8px"}}>{typeCfg.label}</span>
              <span style={{background:sc.bg,color:sc.fg,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{d.priority}</span>
              <span style={{background:stc.bg,color:stc.fg,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{d.status}</span>
              {d.requiresAcknowledgement&&!d.acknowledgedAt&&<span style={{background:"#FDF0F0",color:"#FF5A6E",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>Acknowledgement required</span>}
            </div>
            <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:"#6B7280",fontSize:20,padding:"2px 6px",lineHeight:1}}>×</button>
          </div>
          <div style={{fontSize:15,fontWeight:700,color:"#062B7A",marginBottom:6,lineHeight:1.4}}>{d.title}</div>
          <div style={{display:"flex",gap:12,flexWrap:"wrap",fontSize:11,color:"#374151"}}>
            <span>From: <strong>{d.from.name}</strong></span>
            <span>To: <strong>{d.to.map(t=>t.name).join(", ")}</strong></span>
            <span>{formatTimestamp(d.createdAt)}</span>
            {d.dueDate&&<span style={{color:new Date(d.dueDate)<new Date()&&d.status!=="Completed"?"#FF5A6E":"#374151",fontWeight:new Date(d.dueDate)<new Date()&&d.status!=="Completed"?700:400}}>Due: {d.dueDate}</span>}
          </div>
          {(d.linkedModule||d.reg)&&(
            <div style={{display:"flex",gap:6,marginTop:8,flexWrap:"wrap"}}>
              {d.linkedModule&&<span style={{background:"rgba(255,255,255,0.7)",color:"#374151",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:600}}>📎 {d.linkedModule}{d.linkedRecord?` — ${d.linkedRecord}`:""}</span>}
              {d.reg&&<RegTag reg={d.reg}/>}
            </div>
          )}
        </div>

        {/* Body */}
        <div style={{flex:1,overflowY:"auto",padding:"18px 20px"}}>
          {/* Message body */}
          <div style={{fontSize:13,color:"#062B7A",lineHeight:1.8,marginBottom:20,padding:"14px",background:"#F8FAFC",borderRadius:10,border:"1px solid #E5E7EB",whiteSpace:"pre-wrap"}}>{d.body}</div>

          {/* Response */}
          {d.response&&(
            <div style={{marginBottom:16}}>
              <div style={{fontSize:11,fontWeight:700,color:"#6B7280",marginBottom:6,textTransform:"uppercase",letterSpacing:"0.8px"}}>Response from {d.to[0]?.name}</div>
              <div style={{padding:"12px 14px",background:"#F0FBFA",border:"1px solid #16B5B833",borderRadius:10,fontSize:13,color:"#062B7A",lineHeight:1.7}}>{d.response}</div>
              <div style={{fontSize:10,color:"#6B7280",marginTop:4}}>{formatTimestamp(d.auditTrail.find(a=>a.action==="Response sent")?.at||"")}</div>
            </div>
          )}

          {/* Completion */}
          {d.completedAt&&(
            <div style={{padding:"10px 14px",background:"#F0FDF4",border:"1px solid #16B5B833",borderRadius:9,display:"flex",alignItems:"center",gap:8,marginBottom:16}}>
              <Icon name="check" size={14} color="#16B5B8" strokeWidth={2.5}/>
              <span style={{fontSize:12,fontWeight:600,color:"#16B5B8"}}>Marked complete {formatTimestamp(d.completedAt)}</span>
            </div>
          )}

          {/* Actions for recipient */}
          {canRespond&&(
            <div style={{marginBottom:16}}>
              {!d.acknowledgedAt&&d.requiresAcknowledgement&&(
                <button onClick={acknowledge} style={{width:"100%",marginBottom:10,padding:"10px",borderRadius:8,border:"none",background:"linear-gradient(135deg,#7A57D1,#1C5C9E)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:7}}>
                  <Icon name="check" size={13} color="white" strokeWidth={2.5}/>
                  Acknowledge — I have received and read this
                </button>
              )}
              {!d.response&&(
                <div>
                  <label style={{fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.8px"}}>Your Response</label>
                  <textarea value={response} onChange={e=>setResponse(e.target.value)} rows={4} placeholder="Type your response — this will be logged and visible to the sender…" style={{width:"100%",padding:"10px 12px",borderRadius:8,border:"1.5px solid #D1D5DB",fontSize:13,color:"#062B7A",outline:"none",fontFamily:"inherit",resize:"vertical",lineHeight:1.6,boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
                  <button disabled={!response.trim()} onClick={sendResponse} style={{marginTop:8,padding:"9px 22px",borderRadius:8,border:"none",background:response.trim()?"linear-gradient(135deg,#16B5B8,#0E8F92)":"#D1D5DB",color:"#fff",fontSize:13,fontWeight:700,cursor:response.trim()?"pointer":"not-allowed",fontFamily:"inherit"}}>
                    Send Response
                  </button>
                </div>
              )}
            </div>
          )}

          {/* Actions for sender */}
          {canComplete&&(
            <button onClick={markComplete} style={{width:"100%",marginBottom:16,padding:"10px",borderRadius:8,border:"none",background:"linear-gradient(135deg,#16B5B8,#1E7A48)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:7}}>
              <Icon name="check" size={13} color="white" strokeWidth={2.5}/>
              Mark as Complete — Action Confirmed
            </button>
          )}

          {/* Audit trail */}
          <div>
            <button onClick={()=>setShowAudit(a=>!a)} style={{display:"flex",alignItems:"center",gap:5,background:"none",border:"none",cursor:"pointer",fontSize:11,fontWeight:600,color:"#6B7280",fontFamily:"inherit",padding:0,marginBottom:showAudit?8:0}}>
              <Icon name="shield" size={11} color="#6B7280" strokeWidth={2}/>{showAudit?"Hide":"Show"} audit trail ({d.auditTrail.length} events)
            </button>
            {showAudit&&(
              <div style={{background:"#F8FAFC",borderRadius:8,padding:"10px 12px"}}>
                {d.auditTrail.map((event,i)=>(
                  <div key={i} style={{display:"flex",gap:10,padding:"5px 0",borderBottom:i<d.auditTrail.length-1?"1px solid #E5E7EB":"none",alignItems:"center"}}>
                    <div style={{width:6,height:6,borderRadius:"50%",background:"#16B5B8",flexShrink:0}}/>
                    <span style={{fontSize:11,color:"#062B7A",flex:1}}>{event.action} — {event.by}</span>
                    <span style={{fontSize:10,color:"#6B7280",flexShrink:0}}>{formatTimestamp(event.at)}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── New delegation/note composer ──────────────────────────────
function NewDelegationModal({ role, onClose, onSave }){
  const [type,       setType]      = useState("task");
  const [priority,   setPriority]  = useState("High");
  const [title,      setTitle]     = useState("");
  const [body,       setBody]      = useState("");
  const [linkedMod,  setLinkedMod] = useState("General");
  const [linkedRec,  setLinkedRec] = useState("");
  const [reg,        setReg]       = useState("");
  const [dueDate,    setDueDate]   = useState("");
  const [toRole,     setToRole]    = useState("manager");
  const [requireAck, setRequireAck]= useState(true);

  const typeCfg = DELEGATION_TYPES[type];
  const valid   = title.trim() && body.trim();

  const RECIPIENTS = {
    superadmin:["director","manager"],
    director:  ["manager"],
    manager:   ["director","staff"],
  };
  const availableRecipients = RECIPIENTS[role]||["manager"];

  const fs={width:"100%",padding:"9px 11px",borderRadius:7,border:"1.5px solid #D1D5DB",fontSize:13,color:"#062B7A",outline:"none",fontFamily:"inherit",background:"#fff",boxSizing:"border-box"};
  const lb={fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.8px"};

  // Smart title suggestions per type
  const titleSuggestions = {
    task:"e.g. Complete overdue supervision — Tom Patel",
    note:"e.g. Positive feedback — MAR audit result",
    escalation:"e.g. DBS expired — immediate action required",
    director:"e.g. Governance concern — Well-led domain score",
    docrequest:"e.g. Request: Updated safeguarding policy",
    progresscheck:"e.g. Progress check — open safeguarding concern",
  };

  return(
    <div style={{position:"fixed",inset:0,zIndex:200,background:"rgba(16,30,48,0.6)",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{width:640,maxHeight:"92vh",overflowY:"auto",background:"#fff",borderRadius:14,boxShadow:"0 20px 60px rgba(0,0,0,0.25)"}}>
        <div style={{padding:"18px 22px",borderBottom:"1px solid #E5E7EB",position:"sticky",top:0,background:"#fff",zIndex:1,borderRadius:"14px 14px 0 0"}}>
          <div style={{fontSize:15,fontWeight:700,color:"#062B7A",marginBottom:2}}>New Delegation / Note</div>
          <div style={{fontSize:11,color:"#6B7280"}}>Every item is logged with full audit trail. Nothing gets lost.</div>
        </div>
        <div style={{padding:"20px 22px"}}>

          {/* Type selector */}
          <div style={{marginBottom:16}}>
            <label style={lb}>Type</label>
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:7}}>
              {Object.entries(DELEGATION_TYPES).map(([key,cfg])=>(
                <div key={key} onClick={()=>setType(key)} style={{
                  padding:"10px",borderRadius:8,cursor:"pointer",textAlign:"center",
                  border:`1.5px solid ${type===key?cfg.color:"#E5E7EB"}`,
                  background:type===key?cfg.bg:"#fff",transition:"all 0.15s",
                }}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:5,marginBottom:3}}>
                    <Icon name={cfg.icon} size={12} color={type===key?cfg.color:"#6B7280"} strokeWidth={2}/>
                    <span style={{fontSize:11,fontWeight:type===key?700:400,color:type===key?cfg.color:"#374151"}}>{cfg.label}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:14}}>
            <div>
              <label style={lb}>Priority</label>
              <div style={{display:"flex",gap:5}}>
                {DELEGATION_PRIORITIES.map(p=>{
                  const c=severityColor(p==="Urgent"?"Critical":p==="High"?"High":p==="Normal"?"Medium":"Low");
                  return(
                    <button key={p} onClick={()=>setPriority(p)} style={{flex:1,padding:"7px 4px",borderRadius:7,border:`1.5px solid ${priority===p?c.fg:"#E5E7EB"}`,background:priority===p?c.bg:"#fff",color:priority===p?c.fg:"#6B7280",fontSize:11,fontWeight:priority===p?700:400,cursor:"pointer",fontFamily:"inherit"}}>{p}</button>
                  );
                })}
              </div>
            </div>
            <div>
              <label style={lb}>Send To</label>
              <select value={toRole} onChange={e=>setToRole(e.target.value)} style={{...fs,cursor:"pointer"}}>
                {availableRecipients.map(r=><option key={r} value={r}>{ROLE_LABELS[r]}</option>)}
              </select>
            </div>
          </div>

          <div style={{marginBottom:12}}>
            <label style={lb}>Title *</label>
            <input value={title} onChange={e=>setTitle(e.target.value)} placeholder={titleSuggestions[type]} style={fs} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
          </div>

          <div style={{marginBottom:12}}>
            <label style={lb}>Message / Instructions *</label>
            <textarea value={body} onChange={e=>setBody(e.target.value)} rows={5} placeholder="Be specific. Include what action is required, by when, and what confirmation you need…" style={{...fs,resize:"vertical",lineHeight:1.7}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
          </div>

          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
            <div>
              <label style={lb}>Linked Module</label>
              <select value={linkedMod} onChange={e=>setLinkedMod(e.target.value)} style={{...fs,cursor:"pointer"}}>
                {LINKED_MODULES.map(m=><option key={m}>{m}</option>)}
              </select>
            </div>
            <div>
              <label style={lb}>Linked Record</label>
              <input value={linkedRec} onChange={e=>setLinkedRec(e.target.value)} placeholder="e.g. Maria Johnson, SG/2026/003" style={fs} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
            </div>
            <div>
              <label style={lb}>Regulation Reference</label>
              <input value={reg} onChange={e=>setReg(e.target.value)} placeholder="e.g. Reg 18, Reg 12" style={fs} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
            </div>
            <div>
              <label style={lb}>Due Date</label>
              <input type="date" value={dueDate} onChange={e=>setDueDate(e.target.value)} style={fs} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
            </div>
          </div>

          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,padding:"10px 12px",background:"#F8FAFC",borderRadius:8}}>
            <span style={{fontSize:12,color:"#062B7A"}}>Require acknowledgement from recipient</span>
            <div onClick={()=>setRequireAck(a=>!a)} style={{width:40,height:22,borderRadius:11,background:requireAck?"#16B5B8":"#D1D5DB",cursor:"pointer",position:"relative",transition:"background 0.2s"}}>
              <div style={{position:"absolute",top:2,left:requireAck?18:2,width:18,height:18,borderRadius:"50%",background:"#fff",transition:"left 0.2s",boxShadow:"0 1px 4px rgba(0,0,0,0.2)"}}/>
            </div>
          </div>

          <div style={{display:"flex",gap:8,justifyContent:"flex-end",paddingTop:14,borderTop:"1px solid #E5E7EB"}}>
            <button onClick={onClose} style={{padding:"9px 20px",borderRadius:8,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Cancel</button>
            <button disabled={!valid} onClick={()=>{
              const now=new Date().toISOString();
              const senderName=role==="director"?"James Thornton":role==="superadmin"?"Admin Portal":"Sarah Mitchell";
              onSave({
                id:`DL${Date.now()}`,type,priority,
                status:"Open",title:title.trim(),body:body.trim(),
                from:{name:senderName,role,initials:senderName.split(" ").map(n=>n[0]).join("")},
                to:[{name:toRole==="manager"?"Sarah Mitchell":toRole==="director"?"James Thornton":"Tom Patel",role:toRole,initials:toRole==="manager"?"SM":toRole==="director"?"JT":"TP"}],
                linkedModule:linkedMod,linkedRecord:linkedRec,reg:reg||null,
                createdAt:now,dueDate:dueDate||null,
                readAt:null,acknowledgedAt:null,response:null,completedAt:null,
                requiresAcknowledgement:requireAck,
                auditTrail:[{action:"Created",by:senderName,at:now},{action:"Delivered",by:"System",at:now}],
              });
              onClose();
            }} style={{padding:"9px 24px",borderRadius:8,border:"none",background:valid?"linear-gradient(135deg,#16B5B8,#0E8F92)":"#D1D5DB",color:"#fff",fontSize:13,fontWeight:700,cursor:valid?"pointer":"not-allowed",fontFamily:"inherit"}}>
              Send →
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Delegation item card ──────────────────────────────────────
function DelegationCard({ item, role, onClick }){
  const typeCfg  = DELEGATION_TYPES[item.type]||DELEGATION_TYPES.note;
  const sc       = severityColor(item.priority==="Urgent"?"Critical":item.priority);
  const isUnread = !item.readAt;
  const isOverdue= item.dueDate && new Date(item.dueDate)<new Date() && item.status!=="Completed";
  const needsAck = item.requiresAcknowledgement && !item.acknowledgedAt && (role==="manager"||role==="staff");
  const statusColors={
    Open:{bg:"#FDF8EE",fg:"#FF9A2F"},Acknowledged:{bg:"#EDF5FE",fg:"#7A57D1"},
    "In Progress":{bg:"#EDF5FE",fg:"#7A57D1"},Completed:{bg:"#F0FDF4",fg:"#16B5B8"},
    Overdue:{bg:"#FDF0F0",fg:"#FF5A6E"},Escalated:{bg:"#FDF0F0",fg:"#FF5A6E"},
  };
  const stc=statusColors[item.status]||statusColors.Open;

  return(
    <div onClick={onClick} style={{
      background:"#fff",borderRadius:10,border:`1px solid ${needsAck||isOverdue?"#FF5A6E33":isUnread?"#7A57D133":"#E5E7EB"}`,
      padding:"14px 16px",cursor:"pointer",transition:"all 0.15s",
      borderLeft:`4px solid ${typeCfg.color}`,
      boxShadow:needsAck?"0 2px 8px rgba(217,64,64,0.1)":isUnread?"0 2px 8px rgba(42,126,200,0.1)":"0 1px 3px rgba(0,0,0,0.04)",
    }}
      onMouseEnter={e=>{e.currentTarget.style.transform="translateY(-1px)";e.currentTarget.style.boxShadow="0 4px 14px rgba(0,0,0,0.08)";}}
      onMouseLeave={e=>{e.currentTarget.style.transform="none";e.currentTarget.style.boxShadow=needsAck?"0 2px 8px rgba(217,64,64,0.1)":isUnread?"0 2px 8px rgba(42,126,200,0.1)":"0 1px 3px rgba(0,0,0,0.04)";}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:6}}>
        <div style={{display:"flex",gap:6,alignItems:"center",flexWrap:"wrap",flex:1,marginRight:8}}>
          <span style={{background:typeCfg.bg,color:typeCfg.color,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700,display:"flex",alignItems:"center",gap:4}}>
            <Icon name={typeCfg.icon} size={9} color={typeCfg.color} strokeWidth={2}/>{typeCfg.label}
          </span>
          <span style={{background:sc.bg,color:sc.fg,padding:"2px 7px",borderRadius:20,fontSize:10,fontWeight:700}}>{item.priority}</span>
          <span style={{background:stc.bg,color:stc.fg,padding:"2px 7px",borderRadius:20,fontSize:10,fontWeight:600}}>{item.status}</span>
          {isUnread&&<span style={{background:"#EDF5FE",color:"#7A57D1",padding:"2px 7px",borderRadius:20,fontSize:10,fontWeight:700}}>● Unread</span>}
          {needsAck&&<span style={{background:"#FDF0F0",color:"#FF5A6E",padding:"2px 7px",borderRadius:20,fontSize:10,fontWeight:700}}>⚡ Acknowledgement required</span>}
          {isOverdue&&<span style={{background:"#FDF0F0",color:"#FF5A6E",padding:"2px 7px",borderRadius:20,fontSize:10,fontWeight:700}}>Overdue</span>}
        </div>
        <div style={{fontSize:10,color:"#6B7280",flexShrink:0,marginTop:2}}>{formatTimestamp(item.createdAt)}</div>
      </div>
      <div style={{fontSize:13,fontWeight:isUnread?700:600,color:"#062B7A",marginBottom:5,lineHeight:1.4}}>{item.title}</div>
      <div style={{fontSize:12,color:"#374151",lineHeight:1.5,marginBottom:8,display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical",overflow:"hidden"}}>{item.body}</div>
      <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>
        <span style={{fontSize:11,color:"#6B7280"}}>From: <strong style={{color:"#062B7A"}}>{item.from.name}</strong></span>
        {item.linkedModule&&item.linkedModule!=="General"&&<span style={{background:"#F1F3F8",color:"#374151",padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:500}}>📎 {item.linkedModule}{item.linkedRecord?` — ${item.linkedRecord}`:""}</span>}
        {item.reg&&<RegTag reg={item.reg}/>}
        {item.dueDate&&<span style={{fontSize:10,color:isOverdue?"#FF5A6E":"#6B7280",fontWeight:isOverdue?700:400}}>Due: {item.dueDate}</span>}
        {item.response&&<span style={{background:"#F0FDF4",color:"#16B5B8",padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:600}}>✓ Response received</span>}
      </div>
    </div>
  );
}

// ── Delegation Centre main page ───────────────────────────────
function DelegationCentrePage({ role }){
  const [items,       setItems]       = useState(INITIAL_DELEGATIONS);
  const [selected,    setSelected]    = useState(null);
  const [showNew,     setShowNew]     = useState(false);
  const [filter,      setFilter]      = useState("all");
  const [typeFilter,  setTypeFilter]  = useState("all");
  const [search,      setSearch]      = useState("");

  const updateItem = updated => setItems(is=>is.map(i=>i.id===updated.id?updated:i));

  // Role-based view — managers see items sent to them + items they sent
  // Directors see everything they sent + responses
  const visibleItems = items.filter(item=>{
    if(role==="superadmin"||role==="director") return true;
    return item.to.some(t=>t.role===role)||item.from.role===role;
  });

  const filtered = visibleItems
    .filter(i=>typeFilter==="all"||i.type===typeFilter)
    .filter(i=>{
      if(filter==="unread")     return !i.readAt && i.to.some(t=>t.role===role);
      if(filter==="needsaction")return (!i.acknowledgedAt||!i.response)&&i.status!=="Completed"&&i.to.some(t=>t.role===role);
      if(filter==="open")       return i.status!=="Completed";
      if(filter==="completed")  return i.status==="Completed";
      if(filter==="sent")       return i.from.role===role;
      return true;
    })
    .filter(i=>{
      const q=search.toLowerCase();
      return !q||i.title.toLowerCase().includes(q)||i.body.toLowerCase().includes(q)||i.linkedRecord?.toLowerCase().includes(q);
    })
    .sort((a,b)=>{
      const urgency={Urgent:0,High:1,Normal:2,Low:3};
      if(a.status!=="Completed"&&b.status==="Completed") return -1;
      if(a.status==="Completed"&&b.status!=="Completed") return 1;
      return (urgency[a.priority]||2)-(urgency[b.priority]||2)||new Date(b.createdAt)-new Date(a.createdAt);
    });

  const needsActionCount = visibleItems.filter(i=>i.to.some(t=>t.role===role)&&(!i.acknowledgedAt||!i.response)&&i.status!=="Completed").length;
  const unreadCount      = visibleItems.filter(i=>i.to.some(t=>t.role===role)&&!i.readAt).length;
  const urgentCount      = visibleItems.filter(i=>i.priority==="Urgent"&&i.status!=="Completed").length;
  const openCount        = visibleItems.filter(i=>i.status!=="Completed").length;

  const filterTabs=[
    {id:"all",         label:"All",          count:visibleItems.length},
    {id:"needsaction", label:"Needs Action", count:needsActionCount, alert:needsActionCount>0},
    {id:"unread",      label:"Unread",       count:unreadCount,      alert:unreadCount>0},
    {id:"open",        label:"Open",         count:openCount},
    {id:"sent",        label:"Sent",         count:visibleItems.filter(i=>i.from.role===role).length},
    {id:"completed",   label:"Completed",    count:visibleItems.filter(i=>i.status==="Completed").length},
  ];

  return(<DemoFeatureGate feature="delegation">
    <div style={{padding:24,fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif",maxWidth:1200,height:"100%",overflowY:"auto"}}>
      {/* Header */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:20}}>
        <div>
          <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:3}}>Delegation Centre</div>
          <div style={{fontSize:13,color:"#6B7280"}}>Compliance-linked delegations, notes, and escalation responses · Full audit trail on every item</div>
        </div>
        <button onClick={()=>setShowNew(true)} style={{display:"flex",alignItems:"center",gap:8,padding:"10px 20px",borderRadius:9,border:"none",background:"linear-gradient(135deg,#16B5B8,#0E8F92)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",boxShadow:"0 3px 12px rgba(43,191,178,0.4)"}}>
          <Icon name="onboarding" size={14} color="white" strokeWidth={2.5}/> New Delegation / Note
        </button>
      </div>

      {/* KPI row */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:14,marginBottom:20}}>
        {[
          {l:"Needs Your Action",   v:needsActionCount, c:needsActionCount>0?"#FF5A6E":"#16B5B8", icon:"alert",   sub:"Acknowledgements or responses due"},
          {l:"Unread",             v:unreadCount,       c:unreadCount>0?"#7A57D1":"#16B5B8",       icon:"bell",    sub:"Not yet opened"},
          {l:"Urgent Open",        v:urgentCount,       c:urgentCount>0?"#FF5A6E":"#16B5B8",       icon:"shield",  sub:"Marked urgent"},
          {l:"Open Items",         v:openCount,         c:openCount>5?"#FF9A2F":"#062B7A",         icon:"tasks",   sub:"Awaiting completion"},
        ].map((k,i)=>(
          <div key={i} style={{background:"#fff",borderRadius:10,padding:"16px 18px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",borderLeft:`3px solid ${k.c}`}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
              <span style={{fontSize:11,fontWeight:500,color:"#6B7280"}}>{k.l}</span>
              <div style={{width:30,height:30,borderRadius:8,background:`${k.c}15`,display:"flex",alignItems:"center",justifyContent:"center"}}>
                <Icon name={k.icon} size={14} color={k.c} strokeWidth={1.8}/>
              </div>
            </div>
            <div style={{fontSize:26,fontWeight:800,color:k.c,lineHeight:1}}>{k.v}</div>
            <div style={{fontSize:11,color:"#6B7280",marginTop:5}}>{k.sub}</div>
          </div>
        ))}
      </div>

      {/* Urgent alert banner */}
      {urgentCount>0&&(
        <div style={{background:"#FDF0F0",border:"1px solid #FF5A6E33",borderRadius:9,padding:"10px 16px",marginBottom:14,display:"flex",alignItems:"center",gap:10}}>
          <div style={{width:8,height:8,borderRadius:"50%",background:"#FF5A6E",animation:"pulse 1s infinite",flexShrink:0}}/>
          <span style={{fontSize:12,fontWeight:700,color:"#FF5A6E"}}>{urgentCount} urgent item{urgentCount!==1?"s require":"requires"} immediate attention</span>
        </div>
      )}

      {/* Filters */}
      <div style={{background:"#fff",borderRadius:10,padding:"12px 14px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",marginBottom:14,display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
        <div style={{position:"relative",flex:1,minWidth:200}}>
          <div style={{position:"absolute",left:9,top:"50%",transform:"translateY(-50%)"}}><Icon name="mock" size={13} color="#6B7280" strokeWidth={1.8}/></div>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search title, body, or linked record…"
            style={{width:"100%",padding:"8px 10px 8px 28px",borderRadius:8,border:"1.5px solid #D1D5DB",fontSize:13,color:"#062B7A",outline:"none",fontFamily:"inherit",boxSizing:"border-box"}}
            onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
        </div>
        <select value={typeFilter} onChange={e=>setTypeFilter(e.target.value)} style={{padding:"8px 10px",borderRadius:8,border:"1.5px solid #D1D5DB",fontSize:12,color:"#374151",outline:"none",fontFamily:"inherit",cursor:"pointer",background:"#fff"}}>
          <option value="all">All Types</option>
          {Object.entries(DELEGATION_TYPES).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
        </select>
      </div>

      {/* Status filter tabs */}
      <div style={{display:"flex",gap:6,marginBottom:16,flexWrap:"wrap"}}>
        {filterTabs.map(t=>(
          <button key={t.id} onClick={()=>setFilter(t.id)} style={{
            display:"flex",alignItems:"center",gap:5,
            padding:"6px 14px",borderRadius:20,
            border:`1px solid ${filter===t.id?"#062B7A":"#D1D5DB"}`,
            background:filter===t.id?"#062B7A":"#fff",
            color:filter===t.id?"#fff":"#374151",
            fontSize:12,fontWeight:filter===t.id?700:400,
            cursor:"pointer",fontFamily:"inherit",
          }}>
            {t.label}
            {t.count>0&&<span style={{background:t.alert?(filter===t.id?"rgba(255,255,255,0.25)":"#FDF0F0"):"#F1F3F8",color:t.alert?(filter===t.id?"#fff":"#FF5A6E"):"#6B7280",padding:"0 6px",borderRadius:20,fontSize:11,fontWeight:700}}>{t.count}</span>}
          </button>
        ))}
      </div>

      {/* Item list */}
      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        {filtered.length===0&&(
          <div style={{background:"#F8FAFC",borderRadius:10,padding:"32px",textAlign:"center",color:"#6B7280",fontSize:13}}>
            No items match your filters.
          </div>
        )}
        {filtered.map(item=>(
          <DelegationCard
            key={item.id}
            item={item}
            role={role}
            onClick={()=>{
              // Mark as read when opened
              if(!item.readAt){
                const updated={...item,readAt:new Date().toISOString(),auditTrail:[...item.auditTrail,{action:"Read",by:role==="manager"?"Sarah Mitchell":"James Thornton",at:new Date().toISOString()}]};
                updateItem(updated);
                setSelected(updated);
              } else {
                setSelected(item);
              }
            }}
          />
        ))}
      </div>

      {/* Drawer */}
      {selected&&(
        <DelegationDrawer
          item={selected}
          role={role}
          onClose={()=>setSelected(null)}
          onUpdate={updated=>{updateItem(updated);setSelected(updated);}}
        />
      )}

      {/* New item modal */}
      {showNew&&(
        <NewDelegationModal
          role={role}
          onClose={()=>setShowNew(false)}
          onSave={item=>{setItems(is=>[item,...is]);setShowNew(false);}}
        />
      )}
    </div>
  </DemoFeatureGate>);
}

