// ── Completion records seed ───────────────────────────────────
const INITIAL_COMPLIANCE_COMPLETIONS = [
  { id:"CC001", obligationId:"OB001", completedDate:"2026-05-07", completedBy:"Sarah Mitchell", notes:"Submitted on time. Capacity 4/4. Staffing adequate.", evidence:"NECS_May2026.pdf" },
  { id:"CC002", obligationId:"OB003", completedDate:"2026-05-10", completedBy:"Sarah Mitchell", notes:"1 safeguarding referral submitted to LA — SG/2026/001.", evidence:"" },
  { id:"CC003", obligationId:"OB001", completedDate:"2026-04-07", completedBy:"Sarah Mitchell", notes:"Submitted on time.", evidence:"" },
  { id:"CC004", obligationId:"OB005", completedDate:"2026-03-31", completedBy:"Sarah Mitchell", notes:"Q1 IPC audit completed. Minor issues with PPE storage resolved.", evidence:"IPC_Q1_2026.pdf" },
];

// ── Calendar Page ─────────────────────────────────────────────
function ComplianceCalendarPage({ onNavigateToPIR }){
  const [completions,  setCompletions]  = useState(INITIAL_COMPLIANCE_COMPLETIONS);
  const [selected,     setSelected]     = useState(null);
  const [showComplete, setShowComplete] = useState(null);
  const [filterCat,    setFilterCat]    = useState("All");
  const [compNotes,    setCompNotes]    = useState("");
  const cfg = APP_CONFIG;
  const settingId = cfg?.settingId||"supported_living";

  const relevantObs = COMPLIANCE_OBLIGATIONS.filter(o=>o.settingTypes.includes(settingId));
  const categories  = ["All",...new Set(relevantObs.map(o=>o.category))];

  const filtered = relevantObs.filter(o=>filterCat==="All"||o.category===filterCat);

  const getLastCompletion = (oblId) => completions.filter(c=>c.obligationId===oblId).sort((a,b)=>new Date(b.completedDate)-new Date(a.completedDate))[0];

  const isDue = (obl) => {
    const last = getLastCompletion(obl.id);
    if(!last) return true;
    if(obl.frequency==="Monthly"){
      const lastDate = new Date(last.completedDate);
      const now = new Date();
      return lastDate.getMonth()!==now.getMonth()||lastDate.getFullYear()!==now.getFullYear();
    }
    if(obl.frequency==="Quarterly"){
      const lastDate = new Date(last.completedDate);
      const now = new Date();
      const quartersDiff = (now.getFullYear()-lastDate.getFullYear())*4+Math.floor(now.getMonth()/3)-Math.floor(lastDate.getMonth()/3);
      return quartersDiff>=1;
    }
    if(obl.frequency==="Annual"){
      const lastDate = new Date(last.completedDate);
      const now = new Date();
      return (now.getFullYear()-lastDate.getFullYear())>=1;
    }
    return false;
  };

  const dueCount      = filtered.filter(o=>isDue(o)&&!o.isOngoing).length;
  const completedThisMonth = completions.filter(c=>{const d=new Date(c.completedDate);const n=new Date();return d.getMonth()===n.getMonth()&&d.getFullYear()===n.getFullYear();}).length;

  return(
    <div style={{padding:24,fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif",maxWidth:1200,height:"100%",overflowY:"auto"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:20}}>
        <div>
          <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:3}}>Compliance Calendar</div>
          <div style={{fontSize:13,color:"#6B7280"}}>All recurring regulatory obligations · Monthly, quarterly, and annual submissions · Never miss a deadline</div>
        </div>
      </div>

      {/* KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:14,marginBottom:20}}>
        {[
          {l:"Due This Month",        v:dueCount,            c:dueCount>0?"#FF5A6E":"#16B5B8",    icon:"alert",   sub:"Submissions required"},
          {l:"Completed This Month",  v:completedThisMonth,  c:"#16B5B8",                          icon:"check",   sub:"Recorded completions"},
          {l:"Total Obligations",     v:relevantObs.length,  c:"#062B7A",                          icon:"tasks",   sub:"For your care setting"},
          {l:"Ongoing Monitoring",    v:relevantObs.filter(o=>o.isOngoing).length, c:"#FF9A2F",   icon:"shield",  sub:"No fixed deadline"},
        ].map((k,i)=>(
          <div key={i} style={{background:"#fff",borderRadius:10,padding:"16px 18px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",borderLeft:`3px solid ${k.c}`}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
              <span style={{fontSize:11,fontWeight:500,color:"#6B7280"}}>{k.l}</span>
              <div style={{width:30,height:30,borderRadius:8,background:`${k.c}15`,display:"flex",alignItems:"center",justifyContent:"center"}}>
                <Icon name={k.icon} size={14} color={k.c} strokeWidth={1.8}/>
              </div>
            </div>
            <div style={{fontSize:26,fontWeight:800,color:k.c,lineHeight:1}}>{k.v}</div>
            <div style={{fontSize:11,color:"#6B7280",marginTop:5}}>{k.sub}</div>
          </div>
        ))}
      </div>

      {/* Category filter */}
      <div style={{display:"flex",gap:6,marginBottom:16,flexWrap:"wrap"}}>
        {categories.map(cat=>(
          <button key={cat} onClick={()=>setFilterCat(cat)} style={{padding:"6px 14px",borderRadius:20,border:`1px solid ${filterCat===cat?"#062B7A":"#D1D5DB"}`,background:filterCat===cat?"#062B7A":"#fff",color:filterCat===cat?"#fff":"#374151",fontSize:12,fontWeight:filterCat===cat?700:400,cursor:"pointer",fontFamily:"inherit"}}>{cat}</button>
        ))}
      </div>

      {/* Obligations list */}
      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        {filtered.map(obl=>{
          const last   = getLastCompletion(obl.id);
          const due    = isDue(obl) && !obl.isOngoing;
          const ongoing= obl.isOngoing;
          return(
            <div key={obl.id} style={{
              background:"#fff",borderRadius:11,border:`1px solid ${due?"#FF5A6E33":ongoing?"#FF9A2F22":"#E5E7EB"}`,
              overflow:"hidden",boxShadow:"0 1px 4px rgba(0,0,0,0.04)",
              borderLeft:`4px solid ${obl.color}`,
            }}>
              <div style={{padding:"14px 18px",display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                <div style={{flex:1}}>
                  <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:5,flexWrap:"wrap"}}>
                    <Icon name={obl.icon} size={14} color={obl.color} strokeWidth={2}/>
                    <span style={{fontSize:14,fontWeight:700,color:"#062B7A"}}>{obl.title}</span>
                    <span style={{background:`${obl.color}12`,color:obl.color,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{obl.frequency}</span>
                    <span style={{background:"#F1F3F8",color:"#6B7280",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:500}}>{obl.category}</span>
                    <RegTag reg={obl.reg}/>
                    {due&&<span style={{background:"#FDF0F0",color:"#FF5A6E",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>⚠ Due now</span>}
                    {ongoing&&<span style={{background:"#FDF8EE",color:"#FF9A2F",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:600}}>Ongoing — check monthly</span>}
                  </div>
                  <div style={{fontSize:12,color:"#374151",lineHeight:1.6,marginBottom:6,maxWidth:700}}>{obl.description}</div>
                  <div style={{display:"flex",gap:14,flexWrap:"wrap",fontSize:11,color:"#6B7280"}}>
                    <span>📍 Submit to: <strong style={{color:"#374151"}}>{obl.whereToSubmit}</strong></span>
                    <span>⏱ Time: <strong style={{color:"#374151"}}>{obl.estimatedTime}</strong></span>
                    {last&&<span>✓ Last done: <strong style={{color:"#16B5B8"}}>{last.completedDate} by {last.completedBy}</strong></span>}
                    {!last&&<span style={{color:"#FF5A6E",fontWeight:600}}>⚠ No record of completion</span>}
                  </div>
                  {obl.evidentraData.length>0&&(
                    <div style={{marginTop:8,padding:"7px 10px",background:"#F0FBFA",borderRadius:7,border:"1px solid #16B5B822"}}>
                      <span style={{fontSize:10,fontWeight:700,color:"#0E8F92",textTransform:"uppercase",letterSpacing:"0.5px"}}>Evidentra data available: </span>
                      <span style={{fontSize:11,color:"#0E8F92"}}>{obl.evidentraData.join(" · ")}</span>
                    </div>
                  )}
                </div>
                <div style={{display:"flex",gap:7,flexShrink:0,marginLeft:16,flexDirection:"column",alignItems:"flex-end"}}>
                  {obl.hasPIRSupport&&(
                    <button onClick={onNavigateToPIR} style={{padding:"6px 12px",borderRadius:7,border:"none",background:"linear-gradient(135deg,#062B7A,#2A4A7A)",color:"#fff",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>
                      Open PIR Support →
                    </button>
                  )}
                  <button onClick={()=>{setShowComplete(obl);setCompNotes("");}} style={{padding:"6px 14px",borderRadius:7,border:"none",background:`linear-gradient(135deg,${obl.color},${obl.color}cc)`,color:"#fff",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>
                    ✓ Record Completion
                  </button>
                  <button onClick={()=>setSelected(selected?.id===obl.id?null:obl)} style={{padding:"5px 12px",borderRadius:7,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>
                    {selected?.id===obl.id?"Hide":"Details"}
                  </button>
                </div>
              </div>

              {/* Expanded detail */}
              {selected?.id===obl.id&&(
                <div style={{padding:"14px 18px",borderTop:"1px solid #E5E7EB",background:"#F8FAFC"}}>
                  {/* History */}
                  {completions.filter(c=>c.obligationId===obl.id).length>0&&(
                    <div>
                      <div style={{fontSize:11,fontWeight:700,color:"#6B7280",marginBottom:8,textTransform:"uppercase",letterSpacing:"0.5px"}}>Completion History</div>
                      {completions.filter(c=>c.obligationId===obl.id).sort((a,b)=>new Date(b.completedDate)-new Date(a.completedDate)).map((comp,i)=>(
                        <div key={i} style={{display:"flex",gap:10,padding:"7px 0",borderBottom:"1px solid #E5E7EB",fontSize:12,alignItems:"center"}}>
                          <Icon name="check" size={12} color="#16B5B8" strokeWidth={2.5}/>
                          <span style={{color:"#062B7A",fontWeight:500}}>{comp.completedDate}</span>
                          <span style={{color:"#6B7280"}}>by {comp.completedBy}</span>
                          {comp.notes&&<span style={{color:"#374151",flex:1}}>— {comp.notes}</span>}
                          {comp.evidence&&<span style={{background:"#EDF5FE",color:"#7A57D1",padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:600}}>📎 {comp.evidence}</span>}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Record completion modal */}
      {showComplete&&(
        <div style={{position:"fixed",inset:0,zIndex:200,background:"rgba(16,30,48,0.6)",display:"flex",alignItems:"center",justifyContent:"center"}}>
          <div style={{width:480,background:"#fff",borderRadius:13,boxShadow:"0 20px 60px rgba(0,0,0,0.25)",overflow:"hidden"}}>
            <div style={{padding:"18px 22px",borderBottom:"1px solid #E5E7EB",background:`${showComplete.color}08`}}>
              <div style={{fontSize:14,fontWeight:700,color:"#062B7A",marginBottom:2}}>Record Completion</div>
              <div style={{fontSize:12,color:"#6B7280"}}>{showComplete.title}</div>
            </div>
            <div style={{padding:"20px 22px"}}>
              <div style={{marginBottom:12}}>
                <label style={{fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.8px"}}>Completion Date</label>
                <input type="date" defaultValue={TODAY} id="comp-date" style={{width:"100%",padding:"9px 11px",borderRadius:7,border:"1.5px solid #D1D5DB",fontSize:13,outline:"none",fontFamily:"inherit",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
              </div>
              <div style={{marginBottom:12}}>
                <label style={{fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.8px"}}>Notes (optional)</label>
                <textarea value={compNotes} onChange={e=>setCompNotes(e.target.value)} rows={3} placeholder="Any notes about this submission — reference numbers, outcomes, actions taken…" style={{width:"100%",padding:"9px 11px",borderRadius:7,border:"1.5px solid #D1D5DB",fontSize:13,outline:"none",fontFamily:"inherit",resize:"vertical",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
              </div>
              <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
                <button onClick={()=>setShowComplete(null)} style={{padding:"9px 18px",borderRadius:8,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Cancel</button>
                <button onClick={()=>{
                  const date=document.getElementById("comp-date")?.value||TODAY;
                  setCompletions(cs=>[{id:`CC${Date.now()}`,obligationId:showComplete.id,completedDate:date,completedBy:"Sarah Mitchell",notes:compNotes,evidence:""},...cs]);
                  setShowComplete(null);
                }} style={{padding:"9px 22px",borderRadius:8,border:"none",background:`linear-gradient(135deg,${showComplete.color},${showComplete.color}cc)`,color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>
                  ✓ Save Record
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════
// MODULE 2: PIR SUPPORT TOOL
// Auto-populates the CQC Provider Information Return
// from data already in Evidentra360
// ════════════════════════════════════════════════════════════════

const PIR_SECTIONS = [
  {
    id:"PIR_S1", title:"About Your Service",
    questions:[
      {id:"Q1_1", text:"What is the total number of people currently using your service?", evidentraSource:"Service Users module — current active count", autoValue:"2 (demo — will reflect actual count in production)", editable:true},
      {id:"Q1_2", text:"What is your registered capacity?", evidentraSource:"Service setup — registered capacity", autoValue:"4 (registered capacity from setup)", editable:true},
      {id:"Q1_3", text:"What is your current occupancy rate?", evidentraSource:"Calculated from above", autoValue:"50% (2 of 4 places occupied)", editable:false},
      {id:"Q1_4", text:"Has your registered manager changed in the last 12 months?", evidentraSource:"Staff Records — registered manager history", autoValue:"No — Sarah Mitchell has been RM since March 2022", editable:true},
    ],
  },
  {
    id:"PIR_S2", title:"Staffing",
    questions:[
      {id:"Q2_1", text:"What is your total number of directly employed staff (WTE)?", evidentraSource:"Workforce Intelligence — staff count", autoValue:"5 staff (approx 4.2 WTE)", editable:true},
      {id:"Q2_2", text:"What was your staff turnover rate in the last 12 months?", evidentraSource:"Workforce Intelligence — Turnover Tracking", autoValue:"2 leavers in 12 months = 40% turnover rate", editable:true},
      {id:"Q2_3", text:"What percentage of your workforce are on zero-hours contracts?", evidentraSource:"Staff Records — contract types", autoValue:"0% (no zero-hours contracts in demo data)", editable:true},
      {id:"Q2_4", text:"How many agency or bank staff shifts were used in the last 12 months?", evidentraSource:"Workforce Intelligence — agency shift records", autoValue:"Approx 52 agency shifts (from rota records)", editable:true},
      {id:"Q2_5", text:"What is your current vacancy rate?", evidentraSource:"Workforce Intelligence — Turnover Tracking — vacancy days", autoValue:"1 vacancy (Care Worker — 32 day vacancy)", editable:true},
    ],
  },
  {
    id:"PIR_S3", title:"Training & Development",
    questions:[
      {id:"Q3_1", text:"What percentage of your staff have completed mandatory training?", evidentraSource:"Staff Records — training compliance", autoValue:"18 of 20 mandatory training certificates current = 90% compliance", editable:false},
      {id:"Q3_2", text:"Do you use the Care Certificate for new starters?", evidentraSource:"Staff Records — induction records", autoValue:"Yes — Care Certificate is part of induction for all new care staff", editable:true},
      {id:"Q3_3", text:"What percentage of your staff hold a relevant qualification at Level 2 or above?", evidentraSource:"Staff Records — qualifications", autoValue:"", editable:true, placeholder:"Enter percentage of staff with Level 2+ qualification"},
      {id:"Q3_4", text:"Has the registered manager completed a relevant management qualification?", evidentraSource:"Staff Records — RM qualifications", autoValue:"", editable:true, placeholder:"e.g. Yes — Level 5 Diploma in Leadership for Health and Social Care"},
    ],
  },
  {
    id:"PIR_S4", title:"Safeguarding",
    questions:[
      {id:"Q4_1", text:"How many safeguarding referrals were made to the local authority in the last 12 months?", evidentraSource:"Safeguarding module — external referrals", autoValue:"2 referrals made (SG/2026/001 and SG/2026/002)", editable:false},
      {id:"Q4_2", text:"How many of these referrals were substantiated?", evidentraSource:"Safeguarding module — outcomes", autoValue:"0 substantiated — both cases closed without further action", editable:true},
      {id:"Q4_3", text:"Do you have a named safeguarding lead?", evidentraSource:"Staff Records — safeguarding lead designation", autoValue:"Yes — Sarah Mitchell (Registered Manager), Level 3 trained", editable:true},
      {id:"Q4_4", text:"When was your safeguarding policy last reviewed?", evidentraSource:"Evidence Vault — Safeguarding Policy review date", autoValue:"May 2026 (reviewed and updated)", editable:true},
    ],
  },
  {
    id:"PIR_S5", title:"Quality & Governance",
    questions:[
      {id:"Q5_1", text:"What is your current overall compliance score from your most recent internal audit?", evidentraSource:"KLoE Audit module — latest audit score", autoValue:"84% — Good (May 2026 audit)", editable:false},
      {id:"Q5_2", text:"How many complaints were received in the last 12 months?", evidentraSource:"Service Users — Complaints tab", autoValue:"1 formal complaint received — resolved within 20 days", editable:false},
      {id:"Q5_3", text:"How many compliments were received in the last 12 months?", evidentraSource:"Service Users — Complaints tab", autoValue:"1 formal compliment received from Joseph Mensah", editable:false},
      {id:"Q5_4", text:"Do you carry out regular audits of your service?", evidentraSource:"KLoE Audit and Medication Audit modules", autoValue:"Yes — monthly KLoE audits and monthly medication audits. Mock CQC inspection completed May 2026.", editable:true},
      {id:"Q5_5", text:"How do you involve service users and their families in the running of the service?", evidentraSource:"Service Users — Reviews tab, Communication Log", autoValue:"", editable:true, placeholder:"Describe how you involve service users — meetings, surveys, care plan involvement, complaints process etc."},
      {id:"Q5_6", text:"What improvements have you made in the last 12 months?", evidentraSource:"KLoE Audit — action plans, completed tasks", autoValue:"", editable:true, placeholder:"Describe the main improvements made to your service in the last 12 months"},
    ],
  },
  {
    id:"PIR_S6", title:"Person-Centred Care",
    questions:[
      {id:"Q6_1", text:"How do you ensure care is person-centred and outcome-focused?", evidentraSource:"Service Users — Care Plans, Goals tabs", autoValue:"", editable:true, placeholder:"Describe your approach to person-centred care — how are care plans developed, reviewed, and how are people involved"},
      {id:"Q6_2", text:"How do you support people to maintain relationships with family and friends?", evidentraSource:"Service Users — Communication Log, family involvement records", autoValue:"", editable:true, placeholder:"Describe your approach to supporting relationships and social connections"},
      {id:"Q6_3", text:"How do you support people to be as independent as possible?", evidentraSource:"Service Users — Goals tab, outcomes data", autoValue:"Goals module shows 1 goal achieved this quarter — Arthur Mensah: church attendance. 5 goals currently in progress.", editable:true},
    ],
  },
];

function PIRSupportPage(){
  const [answers,   setAnswers]   = useState({});
  const [tab,       setTab]       = useState(PIR_SECTIONS[0].id);
  const [saved,     setSaved]     = useState(false);
  const [showExport,setShowExport]= useState(false);

  const setAnswer = (qId, val) => setAnswers(p=>({...p,[qId]:val}));
  const getAnswer = (q) => answers[q.id] !== undefined ? answers[q.id] : q.autoValue||"";

  const totalQ        = PIR_SECTIONS.reduce((n,s)=>n+s.questions.length,0);
  const answeredQ     = PIR_SECTIONS.reduce((n,s)=>n+s.questions.filter(q=>getAnswer(q).trim()).length,0);
  const completionPct = Math.round((answeredQ/totalQ)*100);

  const currentSection = PIR_SECTIONS.find(s=>s.id===tab);

  return(<DemoFeatureGate feature="pir">
    <div style={{height:"100%",display:"flex",flexDirection:"column",overflow:"hidden",fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif"}}>
      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#062B7A,#2A4A7A)",padding:"16px 24px",flexShrink:0}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
          <div>
            <div style={{fontSize:16,fontWeight:800,color:"#fff",marginBottom:2}}>CQC Provider Information Return (PIR) — Support Tool</div>
            <div style={{fontSize:12,color:"rgba(255,255,255,0.55)"}}>Annual CQC survey · Auto-populated from your Evidentra360 data · Review and complete before submitting to CQC</div>
          </div>
          <div style={{display:"flex",gap:8}}>
            <button onClick={()=>{setSaved(true);setTimeout(()=>setSaved(false),2000);}} style={{padding:"7px 16px",borderRadius:8,border:"none",background:"rgba(43,191,178,0.2)",color:"#16B5B8",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>{saved?"✓ Saved":"Save Draft"}</button>
            <button onClick={()=>setShowExport(true)} style={{padding:"7px 16px",borderRadius:8,border:"none",background:"linear-gradient(135deg,#16B5B8,#0E8F92)",color:"#fff",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>Export Responses →</button>
          </div>
        </div>
        {/* Progress */}
        <div style={{display:"flex",justifyContent:"space-between",marginBottom:5,fontSize:11}}>
          <span style={{color:"rgba(255,255,255,0.6)"}}>{answeredQ} of {totalQ} questions answered</span>
          <span style={{color:completionPct>=80?"#6EE7B7":completionPct>=50?"#FCD34D":"#F87171",fontWeight:700}}>{completionPct}% complete</span>
        </div>
        <div style={{height:6,background:"rgba(255,255,255,0.1)",borderRadius:3,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${completionPct}%`,background:completionPct>=80?"#16B5B8":completionPct>=50?"#FCD34D":"#F87171",borderRadius:3,transition:"width 0.5s"}}/>
        </div>
      </div>

      {/* Section tabs */}
      <div style={{background:"#fff",borderBottom:"1px solid #E5E7EB",padding:"0 20px",display:"flex",gap:2,overflowX:"auto",flexShrink:0}}>
        {PIR_SECTIONS.map(section=>{
          const answered = section.questions.filter(q=>getAnswer(q).trim()).length;
          const total    = section.questions.length;
          const complete = answered===total;
          return(
            <button key={section.id} onClick={()=>setTab(section.id)} style={{
              padding:"10px 14px",whiteSpace:"nowrap",
              borderRadius:"6px 6px 0 0",border:"none",
              background:tab===section.id?"#F8FAFC":"transparent",
              color:tab===section.id?"#062B7A":"#6B7280",
              fontSize:12,fontWeight:tab===section.id?700:400,
              cursor:"pointer",fontFamily:"inherit",
              borderBottom:tab===section.id?"2px solid #16B5B8":"2px solid transparent",
              display:"flex",alignItems:"center",gap:6,
            }}>
              {section.title}
              <span style={{background:complete?"#F0FDF4":answered>0?"#EDF5FE":"#F1F3F8",color:complete?"#16B5B8":answered>0?"#7A57D1":"#6B7280",padding:"0 6px",borderRadius:20,fontSize:10,fontWeight:700}}>
                {answered}/{total}
              </span>
            </button>
          );
        })}
      </div>

      {/* Questions */}
      <div style={{flex:1,overflowY:"auto",padding:"20px 24px",background:"#F8FAFC"}}>
        {currentSection&&(
          <div style={{maxWidth:800}}>
            <div style={{background:"#EDF5FE",border:"1px solid #7A57D133",borderRadius:9,padding:"11px 14px",marginBottom:16,fontSize:12,color:"#7A57D1",lineHeight:1.6}}>
              <strong>How this works:</strong> Fields marked with a teal source label have been pre-populated from your Evidentra360 data. Review each answer, edit if needed, and complete the blank fields. Once complete, export your responses to use when filling in the actual CQC PIR online.
            </div>

            {currentSection.questions.map((q,i)=>{
              const answer    = getAnswer(q);
              const hasSource = q.evidentraSource;
              const isAuto    = q.autoValue && !answers[q.id];
              const isEmpty   = !answer.trim();

              return(
                <div key={q.id} style={{background:"#fff",borderRadius:10,border:`1px solid ${isEmpty?"#FDF0F0":"#E5E7EB"}`,marginBottom:12,overflow:"hidden",borderLeft:`3px solid ${isAuto?"#16B5B8":isEmpty?"#D1D5DB":"#16B5B8"}`}}>
                  <div style={{padding:"13px 16px"}}>
                    <div style={{display:"flex",gap:8,alignItems:"flex-start",marginBottom:8}}>
                      <span style={{background:"#F8FAFC",color:"#6B7280",padding:"2px 7px",borderRadius:20,fontSize:10,fontWeight:700,flexShrink:0}}>Q{i+1}</span>
                      <span style={{fontSize:13,fontWeight:600,color:"#062B7A",lineHeight:1.5}}>{q.text}</span>
                    </div>
                    {hasSource&&(
                      <div style={{display:"flex",alignItems:"center",gap:5,marginBottom:8,padding:"5px 9px",background:"#F0FBFA",borderRadius:6,width:"fit-content"}}>
                        <Icon name="ai" size={10} color="#16B5B8" strokeWidth={2}/>
                        <span style={{fontSize:10,fontWeight:600,color:"#0E8F92"}}>Evidentra source: {q.evidentraSource}</span>
                        {isAuto&&<span style={{background:"#16B5B8",color:"#fff",padding:"1px 6px",borderRadius:20,fontSize:9,fontWeight:700,marginLeft:4}}>Auto-populated</span>}
                      </div>
                    )}
                    {q.editable?(
                      <textarea
                        value={answer}
                        onChange={e=>setAnswer(q.id,e.target.value)}
                        rows={answer.length>100?4:2}
                        placeholder={q.placeholder||"Enter your response…"}
                        style={{width:"100%",padding:"9px 11px",borderRadius:7,border:`1.5px solid ${isEmpty?"#D1D5DB":"#16B5B833"}`,fontSize:13,color:"#062B7A",outline:"none",fontFamily:"inherit",resize:"vertical",lineHeight:1.6,boxSizing:"border-box",background:isEmpty?"#fff":"#F0FDF4"}}
                        onFocus={e=>e.target.style.borderColor="#16B5B8"}
                        onBlur={e=>e.target.style.borderColor=isEmpty?"#D1D5DB":"#16B5B833"}
                      />
                    ):(
                      <div style={{padding:"9px 11px",background:"#F0FDF4",borderRadius:7,fontSize:13,color:"#062B7A",lineHeight:1.6,border:"1px solid #16B5B822"}}>
                        {answer||<span style={{color:"#D1D5DB"}}>No data available</span>}
                        <div style={{fontSize:10,color:"#6B7280",marginTop:3}}>Auto-calculated — not editable</div>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Export modal */}
      {showExport&&(
        <div style={{position:"fixed",inset:0,zIndex:200,background:"rgba(16,30,48,0.6)",display:"flex",alignItems:"center",justifyContent:"center"}}>
          <div style={{width:500,background:"#fff",borderRadius:13,boxShadow:"0 20px 60px rgba(0,0,0,0.28)",overflow:"hidden"}}>
            <div style={{padding:"18px 22px",borderBottom:"1px solid #E5E7EB"}}>
              <div style={{fontSize:14,fontWeight:700,color:"#062B7A",marginBottom:2}}>Export PIR Responses</div>
              <div style={{fontSize:12,color:"#6B7280"}}>Your responses are ready to copy into the CQC online PIR form</div>
            </div>
            <div style={{padding:"20px 22px",maxHeight:"60vh",overflowY:"auto"}}>
              {PIR_SECTIONS.map(section=>(
                <div key={section.id} style={{marginBottom:16}}>
                  <div style={{fontSize:13,fontWeight:700,color:"#062B7A",marginBottom:8,paddingBottom:4,borderBottom:"2px solid #16B5B822"}}>{section.title}</div>
                  {section.questions.map((q,i)=>{
                    const answer=getAnswer(q);
                    return(
                      <div key={q.id} style={{marginBottom:10}}>
                        <div style={{fontSize:11,fontWeight:600,color:"#6B7280",marginBottom:3}}>Q{i+1}. {q.text}</div>
                        <div style={{padding:"8px 10px",background:"#F8FAFC",borderRadius:6,fontSize:12,color:answer?"#062B7A":"#D1D5DB",lineHeight:1.5}}>{answer||"Not answered"}</div>
                      </div>
                    );
                  })}
                </div>
              ))}
            </div>
            <div style={{padding:"14px 22px",borderTop:"1px solid #E5E7EB",display:"flex",justifyContent:"flex-end",gap:8}}>
              <button onClick={()=>setShowExport(false)} style={{padding:"9px 18px",borderRadius:8,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Close</button>
              <button onClick={()=>{window.print();setShowExport(false);}} style={{padding:"9px 22px",borderRadius:8,border:"none",background:"linear-gradient(135deg,#062B7A,#2A4A7A)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>Print / Save as PDF</button>
            </div>
          </div>
        </div>
      )}
    </div>
  </DemoFeatureGate>);
}

// ════════════════════════════════════════════════════════════════
// MODULE 3: PROFESSIONAL DEVELOPMENT HUB
// Sector updates, Skills for Care, CPD tracker,
// regulation library, webinars, and support resources.
// The professional home for care managers.
// ════════════════════════════════════════════════════════════════

const CPD_CATEGORIES = ["Leadership & Management","Safeguarding","Clinical Practice","Medication","CQC & Compliance","Mental Capacity","Equality & Diversity","Communication","Health & Safety","Personal Development"];

const REGULATION_LIBRARY = [
  {reg:"Reg 9",  title:"Person-centred care",       summary:"Care must be tailored to individual needs and preferences. Service users must be involved in decisions about their care. Care plans must reflect personal goals and aspirations.", cqcFocus:"Inspector will speak to service users directly and read care plans. Looks for evidence of genuine involvement, not token consultation.", commonFindings:["Generic care plans not tailored to individual","Service users unable to describe their care","No evidence of involvement in reviews"]},
  {reg:"Reg 10", title:"Dignity and respect",       summary:"Service users must be treated with dignity and respect at all times, including during personal care. Privacy must be maintained. Staff must use preferred names and communication styles.", cqcFocus:"Inspector will observe staff interactions and ask service users how they are treated. Will look for evidence of dignity in daily practice.", commonFindings:["Staff discussing service users within earshot","Personal care not conducted privately","Use of inappropriate language or overfamiliarity"]},
  {reg:"Reg 11", title:"Need for consent",          summary:"Service users must give informed consent before care is provided. Where capacity is lacking, care must be in the person's best interests following MCA 2005 principles.", cqcFocus:"Will check MCA assessments, best interest decisions, and DoLS where applicable. Will ask staff about their understanding of consent.", commonFindings:["No MCA assessments for people who lack capacity","DoLS not applied for where required","Best interest decisions not documented"]},
  {reg:"Reg 12", title:"Safe care and treatment",   summary:"Care must be provided in a way that prevents abuse and avoidable harm. Risk assessments must be in place. Medication must be managed safely. Infection control must be maintained.", cqcFocus:"Looks at medication management, risk assessments, incident records, and infection control. Often the most closely scrutinised regulation.", commonFindings:["Gaps or errors in MAR charts","Risk assessments not reviewed after incidents","Poor infection prevention practices"]},
  {reg:"Reg 13", title:"Safeguarding from abuse",  summary:"Providers must protect service users from all forms of abuse and improper treatment. Safeguarding policies must be in place. All staff must be trained. Referrals must be made promptly.", cqcFocus:"Will check safeguarding policies, training records, referral history, and ask staff what they would do if they had a concern.", commonFindings:["Delayed referrals to local authority","Safeguarding training not current for all staff","No evidence of learning from safeguarding incidents"]},
  {reg:"Reg 14", title:"Meeting nutritional needs",  summary:"Service users must receive sufficient food and drink to meet their nutritional needs. MUST assessments required. Dietary needs and preferences must be met.", cqcFocus:"Will observe mealtimes, check MUST assessments, and ask about dietary provision for service users with specific needs.", commonFindings:["No MUST assessments on admission","Weight loss not investigated or escalated","Special dietary needs not consistently met"]},
  {reg:"Reg 17", title:"Good governance",           summary:"Providers must have effective governance systems in place. Regular audits must be completed. The registered manager must have oversight of quality. Staff must be supported.", cqcFocus:"Will ask for evidence of audit programme, action plans, staff meetings, and board/director oversight. Often key to Outstanding or Requires Improvement.", commonFindings:["No evidence of audit programme","Action plans not progressed","Staff survey not completed","Lack of director oversight"]},
  {reg:"Reg 18", title:"Staffing",                 summary:"Sufficient numbers of suitably qualified, skilled, and experienced staff must be deployed at all times. Staff must receive appropriate supervision and appraisal.", cqcFocus:"Will check rotas, training records, supervision records, and ask staff when they last had supervision and appraisal.", commonFindings:["Supervision overdue for multiple staff","Over-reliance on agency staff","DBS certificates expired","Training not kept current"]},
  {reg:"Reg 19", title:"Fit and proper persons",   summary:"All persons employed must be of good character, have the necessary qualifications, and be physically and mentally fit. Safe recruitment processes must be followed.", cqcFocus:"Will check DBS certificates, reference records, and recruitment files. May ask to see full safer recruitment evidence for a sample of staff.", commonFindings:["DBS certificates expired","References not obtained before start date","Gaps in employment history not explored"]},
];

const INITIAL_CPD = [
  {id:"CPD001",title:"CQC Insight Session — Medicines Management",type:"Webinar",provider:"CQC",date:"2026-04-15",hours:1.5,notes:"Key learning: MAR chart gaps are the most common medication finding. CD reconciliation must be done with two staff.",certificate:true,category:"Medication"},
  {id:"CPD002",title:"Skills for Care — Moving Into Management",type:"Online course",provider:"Skills for Care",date:"2026-03-10",hours:4,notes:"Completed all 5 modules. Key focus on governance and quality monitoring.",certificate:true,category:"Leadership & Management"},
  {id:"CPD003",title:"Local Authority Safeguarding Briefing — Prevent",type:"Training",provider:"Local Authority",date:"2026-02-20",hours:2,notes:"Prevent awareness refresher. Updated on local referral pathways.",certificate:true,category:"Safeguarding"},
];

const SECTOR_RESOURCES = [
  {
    category:"Skills for Care",
    color:"#16B5B8",
    resources:[
      {title:"Manager Induction Standards",              url:"skillsforcare.org.uk/managers",    desc:"The framework for new managers — what competencies are expected and how to demonstrate them"},
      {title:"Workforce Development Fund",               url:"skillsforcare.org.uk/wdf",         desc:"Funding available for staff training and qualifications — check what your organisation is entitled to"},
      {title:"Well-led Podcast",                         url:"skillsforcare.org.uk/podcast",     desc:"Regular podcast for registered managers — practical leadership guidance"},
      {title:"NMDS-SC Workforce Data",                  url:"skillsforcare.org.uk/nmds",         desc:"Submit your workforce data and access sector-wide benchmarking"},
      {title:"Workforce Planning Guide",                 url:"skillsforcare.org.uk/workforce",   desc:"Tools for forecasting your staffing needs and building a sustainable workforce"},
    ],
  },
  {
    category:"CQC Guidance",
    color:"#062B7A",
    resources:[
      {title:"Fundamentals of Care Guidance",            url:"cqc.org.uk/guidance",              desc:"CQC's guidance on meeting the fundamental standards — essential reading for registered managers"},
      {title:"Key Lines of Enquiry (KLoE)",              url:"cqc.org.uk/kloe",                  desc:"The five KLoE domains explained — what inspectors look for under each domain"},
      {title:"Inspection Insight Reports",               url:"cqc.org.uk/insight",               desc:"CQC's analysis of common themes from recent inspections across care settings"},
      {title:"Provider Portal",                          url:"cqc.org.uk/portal",                desc:"Submit notifications, update your Statement of Purpose, access your inspection history"},
      {title:"State of Care Annual Report",              url:"cqc.org.uk/state-of-care",         desc:"CQC's annual overview of quality in health and care — useful context for PIR responses"},
    ],
  },
  {
    category:"Sector News & Updates",
    color:"#7A57D1",
    resources:[
      {title:"Care England",                             url:"careengland.org.uk",               desc:"Membership body for independent care providers — policy updates, guidance, and advocacy"},
      {title:"Community Care",                           url:"communitycare.co.uk",              desc:"News, practice guidance, and analysis for social care professionals"},
      {title:"NCAS — National Care Association",        url:"nationalcareassociation.org.uk",    desc:"Sector news, events, and support for independent care providers"},
      {title:"Social Care Institute for Excellence",     url:"scie.org.uk",                      desc:"Research, guidance, and resources to improve social care practice"},
      {title:"Hft — Learning Disability Support",        url:"hft.org.uk",                       desc:"Resources for services supporting people with learning disabilities"},
    ],
  },
  {
    category:"Legal & Regulatory",
    color:"#7A57D1",
    resources:[
      {title:"Mental Capacity Act 2005 — Code of Practice", url:"gov.uk/mca-code",             desc:"The statutory code of practice — every registered manager must be familiar with this"},
      {title:"Care Act 2014 Guidance",                   url:"gov.uk/care-act",                 desc:"Local authority duties under the Care Act — relevant to safeguarding and assessments"},
      {title:"Health & Social Care Act 2008",            url:"legislation.gov.uk/hsc",          desc:"The primary legislation underpinning CQC regulation and the fundamental standards"},
      {title:"Disclosure & Barring Service",             url:"gov.uk/dbs",                      desc:"DBS check process, Update Service, and guidance on when checks are required"},
    ],
  },
  {
    category:"Wellbeing & Support",
    color:"#16B5B8",
    resources:[
      {title:"Registered Managers Network — Skills for Care", url:"skillsforcare.org.uk/network", desc:"Peer support network for registered managers — local meetings and online forums"},
      {title:"Social Care Workforce Retention Fund",     url:"gov.uk/scwrf",                     desc:"Government funding to support staff retention and wellbeing initiatives"},
      {title:"Mental Health at Work",                   url:"mentalhealthatwork.org.uk",          desc:"Resources for managers supporting staff mental health and their own wellbeing"},
      {title:"The Managers' Forum",                      url:"themanagersforum.co.uk",            desc:"Peer support and CPD for registered managers in adult social care"},
    ],
  },
];

function ProfDevHubPage(){
  const [tab,       setTab]       = useState("cpd");
  const [cpdLog,    setCpdLog]    = useState(INITIAL_CPD);
  const [showNewCPD,setShowNewCPD]= useState(false);
  const [newCPD,    setNewCPD]    = useState({title:"",type:"Training",provider:"",date:TODAY,hours:1,notes:"",certificate:false,category:CPD_CATEGORIES[0]});
  const [regSearch, setRegSearch] = useState("");
  const [expandedReg,setExpandedReg]=useState(null);

  const totalCPDHours = cpdLog.reduce((s,c)=>s+c.hours,0);
  const thisYear      = cpdLog.filter(c=>c.date.startsWith("2026")).length;
  const withCert      = cpdLog.filter(c=>c.certificate).length;

  const filteredRegs  = REGULATION_LIBRARY.filter(r=>!regSearch||r.reg.toLowerCase().includes(regSearch.toLowerCase())||r.title.toLowerCase().includes(regSearch.toLowerCase())||r.summary.toLowerCase().includes(regSearch.toLowerCase()));

  const inp=(k,v)=>setNewCPD(p=>({...p,[k]:v}));
  const fs={width:"100%",padding:"9px 11px",borderRadius:7,border:"1.5px solid #D1D5DB",fontSize:13,color:"#062B7A",outline:"none",fontFamily:"inherit",background:"#fff",boxSizing:"border-box"};
  const lb={fontSize:11,fontWeight:700,color:"#6B7280",display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.8px"};

  const pageTabs=[
    {id:"cpd",        label:"CPD Tracker"},
    {id:"regulations",label:"Regulation Library"},
    {id:"resources",  label:"Sector Resources"},
  ];

  return(
    <div style={{padding:24,fontFamily:"'Inter','Manrope','Plus Jakarta Sans','Segoe UI',sans-serif",maxWidth:1200,height:"100%",overflowY:"auto"}}>
      {/* Header */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:20}}>
        <div>
          <div style={{fontSize:20,fontWeight:800,color:"#062B7A",marginBottom:3}}>Professional Development Hub</div>
          <div style={{fontSize:13,color:"#6B7280"}}>CPD tracker · Regulation library · Sector resources · Skills for Care · Your professional home</div>
        </div>
      </div>

      {/* Tab nav */}
      <div style={{display:"flex",gap:6,marginBottom:20,background:"#fff",borderRadius:10,padding:"10px 14px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)"}}>
        {pageTabs.map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)} style={{padding:"7px 20px",borderRadius:8,border:"none",background:tab===t.id?"#062B7A":"transparent",color:tab===t.id?"#fff":"#374151",fontSize:13,fontWeight:tab===t.id?700:500,cursor:"pointer",fontFamily:"inherit"}}>
            {t.label}
          </button>
        ))}
      </div>

      {/* ── CPD TRACKER ── */}
      {tab==="cpd"&&(
        <div>
          {/* KPIs */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:14,marginBottom:20}}>
            {[
              {l:"Total CPD Hours",     v:`${totalCPDHours}h`, c:"#16B5B8", sub:"All recorded learning"},
              {l:"CPD Activities 2026", v:thisYear,            c:"#7A57D1", sub:"This year"},
              {l:"Certificates Held",  v:withCert,            c:"#16B5B8", sub:"Evidenced CPD"},
              {l:"Categories Covered", v:new Set(cpdLog.map(c=>c.category)).size, c:"#7A57D1", sub:"Breadth of learning"},
            ].map((k,i)=>(
              <div key={i} style={{background:"#fff",borderRadius:10,padding:"16px 18px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",borderLeft:`3px solid ${k.c}`}}>
                <div style={{fontSize:11,fontWeight:500,color:"#6B7280",marginBottom:6}}>{k.l}</div>
                <div style={{fontSize:26,fontWeight:800,color:k.c,lineHeight:1}}>{k.v}</div>
                <div style={{fontSize:11,color:"#6B7280",marginTop:5}}>{k.sub}</div>
              </div>
            ))}
          </div>

          <div style={{display:"flex",justifyContent:"flex-end",marginBottom:12}}>
            <button onClick={()=>setShowNewCPD(true)} style={{display:"flex",alignItems:"center",gap:7,padding:"9px 18px",borderRadius:8,border:"none",background:"linear-gradient(135deg,#16B5B8,#0E8F92)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",boxShadow:"0 3px 12px rgba(43,191,178,0.4)"}}>
              <Icon name="onboarding" size={13} color="white" strokeWidth={2.5}/> Log CPD Activity
            </button>
          </div>

          {/* CPD log */}
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {cpdLog.map(cpd=>(
              <div key={cpd.id} style={{background:"#fff",borderRadius:10,border:"1px solid #E5E7EB",padding:"14px 18px",display:"flex",gap:14,alignItems:"flex-start",boxShadow:"0 1px 3px rgba(0,0,0,0.04)"}}>
                <div style={{width:44,height:44,borderRadius:10,background:"linear-gradient(135deg,#16B5B8,#0E8F92)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                  <span style={{fontSize:16,fontWeight:800,color:"#fff"}}>{cpd.hours}h</span>
                </div>
                <div style={{flex:1}}>
                  <div style={{fontSize:13,fontWeight:700,color:"#062B7A",marginBottom:3}}>{cpd.title}</div>
                  <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:5}}>
                    <span style={{background:"#F1F3F8",color:"#374151",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:600}}>{cpd.type}</span>
                    <span style={{background:"#EDF5FE",color:"#7A57D1",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:600}}>{cpd.provider}</span>
                    <span style={{background:"#F8FAFC",color:"#6B7280",padding:"2px 8px",borderRadius:20,fontSize:10}}>{cpd.date}</span>
                    <span style={{background:cpd.certificate?"#F0FDF4":"#F8FAFC",color:cpd.certificate?"#16B5B8":"#6B7280",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:600}}>{cpd.certificate?"✓ Certificate":"No certificate"}</span>
                    <span style={{background:"#F3F0FD",color:"#7A57D1",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:600}}>{cpd.category}</span>
                  </div>
                  {cpd.notes&&<div style={{fontSize:12,color:"#374151",lineHeight:1.5}}>{cpd.notes}</div>}
                </div>
              </div>
            ))}
            {cpdLog.length===0&&<div style={{background:"#F8FAFC",borderRadius:10,padding:"32px",textAlign:"center",color:"#6B7280",fontSize:13}}>No CPD activities logged yet. Click "Log CPD Activity" to start recording your professional development.</div>}
          </div>

          {/* New CPD modal */}
          {showNewCPD&&(
            <div style={{position:"fixed",inset:0,zIndex:200,background:"rgba(16,30,48,0.6)",display:"flex",alignItems:"center",justifyContent:"center"}}>
              <div style={{width:540,maxHeight:"90vh",overflowY:"auto",background:"#fff",borderRadius:13,boxShadow:"0 20px 60px rgba(0,0,0,0.28)"}}>
                <div style={{padding:"18px 22px",borderBottom:"1px solid #E5E7EB",position:"sticky",top:0,background:"#fff",borderRadius:"13px 13px 0 0",zIndex:1}}>
                  <div style={{fontSize:14,fontWeight:700,color:"#062B7A"}}>Log CPD Activity</div>
                </div>
                <div style={{padding:"20px 22px"}}>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:14}}>
                    <div style={{gridColumn:"1/-1"}}><label style={lb}>Activity Title *</label><input value={newCPD.title} onChange={e=>inp("title",e.target.value)} placeholder="e.g. CQC Insight Session — Medication Management" style={fs} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/></div>
                    <div><label style={lb}>Type</label><select value={newCPD.type} onChange={e=>inp("type",e.target.value)} style={{...fs,cursor:"pointer"}}>{["Training","Webinar","Online course","Conference","Peer supervision","Reading/self-study","Coaching/mentoring","Other"].map(t=><option key={t}>{t}</option>)}</select></div>
                    <div><label style={lb}>Provider / Organisation</label><input value={newCPD.provider} onChange={e=>inp("provider",e.target.value)} placeholder="e.g. Skills for Care, CQC, Local Authority" style={fs} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/></div>
                    <div><label style={lb}>Date</label><input type="date" value={newCPD.date} onChange={e=>inp("date",e.target.value)} style={fs}/></div>
                    <div><label style={lb}>Hours</label><input type="number" min="0.5" step="0.5" value={newCPD.hours} onChange={e=>inp("hours",parseFloat(e.target.value)||1)} style={fs}/></div>
                    <div><label style={lb}>Category</label><select value={newCPD.category} onChange={e=>inp("category",e.target.value)} style={{...fs,cursor:"pointer"}}>{CPD_CATEGORIES.map(c=><option key={c}>{c}</option>)}</select></div>
                    <div style={{display:"flex",alignItems:"center",gap:8}}><input type="checkbox" checked={newCPD.certificate} onChange={e=>inp("certificate",e.target.checked)} style={{accentColor:"#16B5B8",cursor:"pointer"}}/><label style={{fontSize:12,color:"#062B7A",cursor:"pointer"}}>Certificate / evidence obtained</label></div>
                    <div style={{gridColumn:"1/-1"}}><label style={lb}>Key Learning / Notes</label><textarea value={newCPD.notes} onChange={e=>inp("notes",e.target.value)} rows={3} placeholder="What did you learn? How will you apply it?" style={{...fs,resize:"vertical",lineHeight:1.6}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/></div>
                  </div>
                  <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
                    <button onClick={()=>setShowNewCPD(false)} style={{padding:"9px 18px",borderRadius:8,border:"1px solid #D1D5DB",background:"#fff",color:"#374151",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Cancel</button>
                    <button disabled={!newCPD.title} onClick={()=>{setCpdLog(l=>[{...newCPD,id:`CPD${Date.now()}`},...l]);setShowNewCPD(false);setNewCPD({title:"",type:"Training",provider:"",date:TODAY,hours:1,notes:"",certificate:false,category:CPD_CATEGORIES[0]});}} style={{padding:"9px 22px",borderRadius:8,border:"none",background:newCPD.title?"linear-gradient(135deg,#16B5B8,#0E8F92)":"#D1D5DB",color:"#fff",fontSize:13,fontWeight:700,cursor:newCPD.title?"pointer":"not-allowed",fontFamily:"inherit"}}>Save CPD Record</button>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ── REGULATION LIBRARY ── */}
      {tab==="regulations"&&(
        <div>
          <div style={{background:"#EDF5FE",border:"1px solid #7A57D133",borderRadius:9,padding:"11px 14px",marginBottom:16,fontSize:12,color:"#7A57D1",lineHeight:1.6}}>
            Plain English summaries of every fundamental standard. What each regulation means, what CQC specifically looks for, and the most common inspection findings. Use this to prepare for inspections and brief your team.
          </div>
          <div style={{position:"relative",marginBottom:14}}>
            <div style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)"}}><Icon name="mock" size={14} color="#6B7280" strokeWidth={1.8}/></div>
            <input value={regSearch} onChange={e=>setRegSearch(e.target.value)} placeholder="Search regulations — e.g. medication, DoLS, staffing, dignity…" style={{width:"100%",padding:"10px 12px 10px 34px",borderRadius:9,border:"1.5px solid #D1D5DB",fontSize:13,color:"#062B7A",outline:"none",fontFamily:"inherit",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor="#16B5B8"} onBlur={e=>e.target.style.borderColor="#D1D5DB"}/>
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {filteredRegs.map(reg=>(
              <div key={reg.reg} style={{background:"#fff",borderRadius:10,border:"1px solid #E5E7EB",overflow:"hidden",boxShadow:"0 1px 3px rgba(0,0,0,0.04)"}}>
                <div onClick={()=>setExpandedReg(expandedReg===reg.reg?null:reg.reg)} style={{padding:"14px 18px",display:"flex",justifyContent:"space-between",alignItems:"center",cursor:"pointer",borderBottom:expandedReg===reg.reg?"1px solid #E5E7EB":"none"}}>
                  <div style={{display:"flex",gap:10,alignItems:"center"}}>
                    <RegTag reg={reg.reg}/>
                    <span style={{fontSize:14,fontWeight:700,color:"#062B7A"}}>{reg.title}</span>
                  </div>
                  <div style={{transform:expandedReg===reg.reg?"rotate(180deg)":"none",transition:"transform 0.2s"}}><Icon name="chevronDown" size={14} color="#6B7280" strokeWidth={2}/></div>
                </div>
                {expandedReg===reg.reg&&(
                  <div style={{padding:"16px 18px"}}>
                    <div style={{fontSize:13,color:"#374151",lineHeight:1.7,marginBottom:14}}>{reg.summary}</div>
                    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                      <div style={{padding:"12px",background:"#EDF5FE",borderRadius:9,border:"1px solid #7A57D133"}}>
                        <div style={{fontSize:11,fontWeight:700,color:"#7A57D1",marginBottom:6,textTransform:"uppercase",letterSpacing:"0.5px"}}>What CQC looks for</div>
                        <div style={{fontSize:12,color:"#7A57D1",lineHeight:1.6}}>{reg.cqcFocus}</div>
                      </div>
                      <div style={{padding:"12px",background:"#FDF8EE",borderRadius:9,border:"1px solid #FF9A2F33"}}>
                        <div style={{fontSize:11,fontWeight:700,color:"#FF9A2F",marginBottom:6,textTransform:"uppercase",letterSpacing:"0.5px"}}>Common inspection findings</div>
                        {reg.commonFindings.map((f,i)=>(
                          <div key={i} style={{display:"flex",gap:6,alignItems:"flex-start",marginBottom:4,fontSize:12,color:"#FF9A2F"}}>
                            <span style={{flexShrink:0,fontWeight:700}}>→</span>{f}
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── SECTOR RESOURCES ── */}
      {tab==="resources"&&(
        <div>
          <div style={{background:"linear-gradient(135deg,#062B7A,#2A4A7A)",borderRadius:12,padding:"20px 24px",marginBottom:20,display:"flex",gap:14,alignItems:"center"}}>
            <div style={{width:48,height:48,borderRadius:12,background:"rgba(43,191,178,0.2)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
              <Icon name="trending" size={22} color="#16B5B8" strokeWidth={1.8}/>
            </div>
            <div>
              <div style={{fontSize:15,fontWeight:700,color:"#fff",marginBottom:4}}>Curated resources for care managers and directors</div>
              <div style={{fontSize:12,color:"rgba(255,255,255,0.55)",lineHeight:1.6}}>Skills for Care, CQC guidance, sector news, legal frameworks, and wellbeing support — all in one place. These are the resources that help you lead better, stay compliant, and develop professionally.</div>
            </div>
          </div>

          {SECTOR_RESOURCES.map(section=>(
            <div key={section.category} style={{marginBottom:20}}>
              <div style={{fontSize:14,fontWeight:800,color:"#062B7A",marginBottom:12,display:"flex",alignItems:"center",gap:8}}>
                <div style={{width:12,height:12,borderRadius:3,background:section.color}}/>
                {section.category}
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                {section.resources.map(res=>(
                  <div key={res.title} style={{background:"#fff",borderRadius:10,border:"1px solid #E5E7EB",padding:"14px 16px",display:"flex",gap:10,alignItems:"flex-start",boxShadow:"0 1px 3px rgba(0,0,0,0.04)",transition:"all 0.15s",cursor:"pointer"}}
                    onMouseEnter={e=>{e.currentTarget.style.borderColor=section.color+"55";e.currentTarget.style.transform="translateY(-1px)";e.currentTarget.style.boxShadow="0 4px 12px rgba(0,0,0,0.08)";}}
                    onMouseLeave={e=>{e.currentTarget.style.borderColor="#E5E7EB";e.currentTarget.style.transform="none";e.currentTarget.style.boxShadow="0 1px 3px rgba(0,0,0,0.04)";}}>
                    <div style={{width:36,height:36,borderRadius:9,background:`${section.color}15`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                      <Icon name="reports" size={15} color={section.color} strokeWidth={1.8}/>
                    </div>
                    <div style={{flex:1}}>
                      <div style={{fontSize:13,fontWeight:700,color:"#062B7A",marginBottom:3}}>{res.title}</div>
                      <div style={{fontSize:11,color:"#6B7280",lineHeight:1.5,marginBottom:5}}>{res.desc}</div>
                      <div style={{fontSize:10,color:section.color,fontWeight:600}}>🔗 {res.url}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

