// ════════════════════════════════════════════════════════════════
// GOVERNANCE INTELLIGENCE ENGINE
// Runs against live app data — no import needed
// Powers: Health Score, Inline Module Alerts, Sidebar Badges,
// Dashboard Governance Panel
// ════════════════════════════════════════════════════════════════

// ── Live governance alert generator ──────────────────────────
// Reads INITIAL_STAFF, INITIAL_SERVICE_USERS, INITIAL_SG_CONCERNS etc
// and generates real-time compliance alerts
// ── Activity log helper ─────────────────────────────────────
// Silently no-ops in demo mode or when Supabase is unavailable.
async function logActivity(action, module, description){
  if(!hasSupabase()) return;
  const cid = APP_CONFIG?.companyId;
  if(!cid||cid==="demo-company-001") return;
  try{
    await supabase.from("activity_log").insert({
      company_id: cid,
      user_email: APP_CONFIG?.managerEmail||"",
      user_name:  APP_CONFIG?.managerName||"User",
      action,
      category:   module,
      detail:     description,
    });
  }catch(e){ console.warn("[E360] logActivity failed:",e.message); }
}

function generateLiveAlerts(liveData){
  // liveData = { staff, serviceUsers, sgConcerns }
  // Falls back to INITIAL_ seed arrays when liveData not provided (demo mode)
  const alerts = [];
  const now    = new Date();

  const staffData       = liveData?.staff        || (typeof INITIAL_STAFF          !== 'undefined' ? INITIAL_STAFF          : []);
  const serviceUserData = liveData?.serviceUsers || (typeof INITIAL_SERVICE_USERS  !== 'undefined' ? INITIAL_SERVICE_USERS  : []);
  const sgData          = liveData?.sgConcerns   || (typeof INITIAL_SG_CONCERNS    !== 'undefined' ? INITIAL_SG_CONCERNS    : []);

  const daysDiff = (dateStr) => {
    if(!dateStr) return null;
    const diff = (new Date(dateStr) - now) / (1000*60*60*24);
    return Math.round(diff);
  };

  // ── Staff alerts ─────────────────────────────────────────
  if(staffData.length > 0){
    staffData.forEach(s=>{
      const name = `${s.firstName} ${s.lastName}`;

      // DBS
      if(s.recruitment?.dbs?.status==="Expired"||s.dbs?.status==="Expired"){
        alerts.push({id:`DBS_${s.id}`,module:"staff",priority:"Critical",
          title:`DBS Expired — ${name}`,
          detail:`DBS certificate has expired. This staff member must not work unsupervised until renewed.`,
          regulation:"Reg 19",action:"Submit urgent DBS application immediately",
          assignedTo:"Registered Manager",dueDate:TODAY});
      } else if(s.recruitment?.dbs?.expiryDate||s.dbs?.expiryDate){
        const d = daysDiff(s.recruitment?.dbs?.expiryDate||s.dbs?.expiryDate);
        if(d!==null && d>=0 && d<=30){
          alerts.push({id:`DBS_EXP_${s.id}`,module:"staff",priority:"High",
            title:`DBS Expiring in ${d} days — ${name}`,
            detail:`DBS renewal is due within 30 days.`,
            regulation:"Reg 19",action:"Initiate DBS renewal application now",
            assignedTo:"Registered Manager",dueDate:s.recruitment?.dbs?.expiryDate||s.dbs?.expiryDate});
        }
      }

      // Supervisions overdue (>8 weeks since last)
      const lastSupDate = s.supervisions?.[0]?.date||s.hr?.lastSupervision;
      if(lastSupDate){
        const d = daysDiff(lastSupDate);
        if(d!==null && d < -56){
          alerts.push({id:`SUP_${s.id}`,module:"staff",priority:"High",
            title:`Supervision Overdue — ${name}`,
            detail:`Last supervision was ${Math.abs(d)} days ago. Maximum interval is 8 weeks.`,
            regulation:"Reg 18",action:"Schedule supervision within 7 days",
            assignedTo:"Registered Manager",dueDate:addMonths(new Date(),0).toISOString().slice(0,10)});
        }
      }

      // Training expiry
      if(s.training){
        const expiringTraining = s.training.filter(t=>{
          if(!t.expiryDate||t.status==="Not required") return false;
          const d = daysDiff(t.expiryDate);
          return d!==null && d <= 30;
        });
        expiringTraining.forEach(t=>{
          const d = daysDiff(t.expiryDate);
          const expired = d < 0;
          alerts.push({id:`TRAIN_${s.id}_${t.name}`,module:"staff",
            priority:expired?"Critical":"High",
            title:`${expired?"Training Expired":"Training Expiring Soon"} — ${name}: ${t.name}`,
            detail:`${t.name} ${expired?`expired ${Math.abs(d)} days ago`:`expires in ${d} days`}.`,
            regulation:"Reg 18",action:`Book ${t.name} training for ${name}`,
            assignedTo:"Registered Manager",dueDate:t.expiryDate});
        });
      }
    });
  }

  // ── Service user alerts ───────────────────────────────────
  if(serviceUserData.length > 0){
    serviceUserData.forEach(su=>{
      const name = `${su.firstName} ${su.lastName}`;

      // Care plan review
      const cpReview = su.carePlanReviewDate||su.careplan?.nextReviewDate;
      if(cpReview){
        const d = daysDiff(cpReview);
        if(d!==null && d < 0){
          alerts.push({id:`CP_${su.id}`,module:"serviceusers",priority:"Critical",
            title:`Care Plan Review Overdue — ${name}`,
            detail:`Care plan review was due ${Math.abs(d)} days ago.`,
            regulation:"Reg 9",action:"Complete care plan review with service user and key worker",
            assignedTo:"Key Worker",dueDate:cpReview});
        } else if(d!==null && d<=14){
          alerts.push({id:`CP_DUE_${su.id}`,module:"serviceusers",priority:"High",
            title:`Care Plan Review Due — ${name}`,
            detail:`Care plan review is due in ${d} days.`,
            regulation:"Reg 9",action:"Schedule care plan review this week",
            assignedTo:"Key Worker",dueDate:cpReview});
        }
      }

      // DoLS expiry
      const dolsExpiry = su.mca?.dolsExpiryDate||su.dols?.expiryDate;
      if(dolsExpiry){
        const d = daysDiff(dolsExpiry);
        if(d!==null && d >= 0 && d <= 30){
          alerts.push({id:`DOLS_${su.id}`,module:"serviceusers",priority:d<=7?"Critical":"High",
            title:`DoLS Expiring in ${d} days — ${name}`,
            detail:`DoLS authorisation expires ${dolsExpiry}. Renewal must be submitted to the local authority now.`,
            regulation:"Reg 11, MCA 2005",action:"Submit DoLS renewal application to local authority immediately",
            assignedTo:"Registered Manager",dueDate:dolsExpiry});
        } else if(d!==null && d < 0){
          alerts.push({id:`DOLS_EXP_${su.id}`,module:"serviceusers",priority:"Critical",
            title:`DoLS Expired — ${name}`,
            detail:`DoLS authorisation expired ${Math.abs(d)} days ago. This is a serious legal risk.`,
            regulation:"Reg 11, MCA 2005",action:"Contact local authority immediately — urgent renewal required",
            assignedTo:"Registered Manager",dueDate:TODAY});
        }
      }

      // Risk assessment overdue
      const raReview = su.riskReviewDate||su.risks?.nextReviewDate;
      if(raReview){
        const d = daysDiff(raReview);
        if(d!==null && d < 0){
          alerts.push({id:`RA_${su.id}`,module:"serviceusers",priority:"Medium",
            title:`Risk Assessment Overdue — ${name}`,
            detail:`Risk assessment review was due ${Math.abs(d)} days ago.`,
            regulation:"Reg 9, 12",action:"Complete risk assessment review",
            assignedTo:"Key Worker",dueDate:raReview});
        }
      }
    });
  }

  // ── Safeguarding alerts ───────────────────────────────────
  if(sgData.length > 0){
    sgData.forEach(sg=>{
      if(sg.status==="Open"||sg.status==="Under Investigation"){
        const d = daysDiff(sg.dateRaised);
        if(d!==null && d < -14){
          alerts.push({id:`SG_${sg.id}`,module:"safeguarding",priority:"High",
            title:`Safeguarding Open ${Math.abs(d)} Days — ${sg.referenceNumber}`,
            detail:`${sg.concernType} concern for ${sg.serviceUserName} has been open for ${Math.abs(d)} days with no resolution.`,
            regulation:"Reg 13",action:"Update safeguarding record with progress or escalate to local authority",
            assignedTo:"Registered Manager",dueDate:TODAY});
        }
      }
    });
  }

  // ── Audit alerts ─────────────────────────────────────────
  // Mock: if no audit in last 90 days
  alerts.push({id:"AUDIT_DUE",module:"audits",priority:"Medium",
    title:"KLoE Audit Due — Q2 2026",
    detail:"No KLoE audit completed in the last 90 days. Quarterly audits are best practice for inspection readiness.",
    regulation:"Reg 17",action:"Schedule and complete Q2 2026 KLoE audit",
    assignedTo:"Registered Manager",dueDate:addMonths(new Date(),0).toISOString().slice(0,10)});

  // Sort: Critical first, then High, Medium, Low
  const order = {Critical:0,High:1,Medium:2,Low:3};
  return alerts.sort((a,b)=>(order[a.priority]||3)-(order[b.priority]||3));
}

// ── Governance health score ───────────────────────────────────
function calcGovernanceHealth(alerts){
  if(!alerts||alerts.length===0) return {score:100,grade:"Outstanding",color:"#16B5B8",bg:"#F0FDF4"};
  const weights = {Critical:15,High:8,Medium:3,Low:1};
  const deduction = alerts.reduce((s,a)=>s+(weights[a.priority]||1),0);
  const score = Math.max(0, Math.min(100, 100 - deduction));
  if(score>=85)  return {score,grade:"Outstanding",  color:"#16B5B8",bg:"#F0FDF4"};
  if(score>=70)  return {score,grade:"Good",         color:"#7A57D1",bg:"#EDF5FE"};
  if(score>=50)  return {score,grade:"Requires Improvement",color:"#FF9A2F",bg:"#FDF8EE"};
  return          {score,grade:"Inadequate",    color:"#FF5A6E",bg:"#FDF0F0"};
}

// ── Alert counts by module (for sidebar badges) ───────────────
function getModuleAlertCounts(alerts){
  const counts = {};
  alerts.forEach(a=>{
    if(!counts[a.module]) counts[a.module]=0;
    counts[a.module]++;
  });
  return counts;
}

// ── Governance Health Score Widget ───────────────────────────
function GovernanceHealthScore({alerts, onNavigate, compact=false}){
  const health  = calcGovernanceHealth(alerts);
  const counts  = {
    critical: alerts.filter(a=>a.priority==="Critical").length,
    high:     alerts.filter(a=>a.priority==="High").length,
    medium:   alerts.filter(a=>a.priority==="Medium").length,
  };
  const circumference = 2 * Math.PI * 38;
  const offset = circumference - (health.score/100) * circumference;

  if(compact){
    return(
      <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",background:health.bg,borderRadius:9,border:`1px solid ${health.color}33`,cursor:"pointer"}} onClick={()=>onNavigate&&onNavigate("briefing")}>
        <svg width="36" height="36" viewBox="0 0 36 36" style={{flexShrink:0}}>
          <circle cx="18" cy="18" r="14" fill="none" stroke="#E5E7EB" strokeWidth="4"/>
          <circle cx="18" cy="18" r="14" fill="none" stroke={health.color} strokeWidth="4"
            strokeDasharray={2*Math.PI*14} strokeDashoffset={2*Math.PI*14-(health.score/100)*2*Math.PI*14}
            strokeLinecap="round" transform="rotate(-90 18 18)" style={{transition:"stroke-dashoffset 1s ease"}}/>
          <text x="18" y="22" textAnchor="middle" fontSize="10" fontWeight="800" fill={health.color}>{health.score}</text>
        </svg>
        <div>
          <div style={{fontSize:12,fontWeight:700,color:health.color}}>{health.grade}</div>
          {counts.critical>0&&<div style={{fontSize:10,color:"#FF5A6E"}}>{counts.critical} critical item{counts.critical!==1?"s":""}</div>}
        </div>
      </div>
    );
  }

  return(
    <div style={{background:"#fff",borderRadius:12,padding:"20px 22px",boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",border:`1px solid ${health.color}22`,marginBottom:16}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
        <div>
          <div style={{fontSize:13,fontWeight:700,color:"#062B7A",marginBottom:2}}>Governance Health Score</div>
          <div style={{fontSize:11,color:"#6B7280"}}>Live · Based on your current compliance data</div>
        </div>
        <span style={{background:health.bg,color:health.color,padding:"3px 10px",borderRadius:20,fontSize:11,fontWeight:700,border:`1px solid ${health.color}33`}}>{health.grade}</span>
      </div>

      <div style={{display:"flex",alignItems:"center",gap:24,marginBottom:16}}>
        {/* Circular gauge */}
        <div style={{position:"relative",flexShrink:0}}>
          <svg width="100" height="100" viewBox="0 0 100 100">
            <circle cx="50" cy="50" r="38" fill="none" stroke="#E5E7EB" strokeWidth="8"/>
            <circle cx="50" cy="50" r="38" fill="none" stroke={health.color} strokeWidth="8"
              strokeDasharray={circumference} strokeDashoffset={offset}
              strokeLinecap="round" transform="rotate(-90 50 50)"
              style={{transition:"stroke-dashoffset 1.2s ease"}}/>
            <text x="50" y="46" textAnchor="middle" fontSize="22" fontWeight="900" fill={health.color}>{health.score}</text>
            <text x="50" y="60" textAnchor="middle" fontSize="9" fill="#6B7280">out of 100</text>
          </svg>
        </div>

        {/* Alert summary */}
        <div style={{flex:1}}>
          {[
            {label:"Critical",count:counts.critical,bg:"#FDF0F0",fg:"#FF5A6E"},
            {label:"High",    count:counts.high,    bg:"#FDF8EE",fg:"#FF9A2F"},
            {label:"Medium",  count:counts.medium,  bg:"#EDF5FE",fg:"#7A57D1"},
          ].map((b,i)=>(
            <div key={i} style={{display:"flex",alignItems:"center",gap:10,marginBottom:i<2?8:0}}>
              <div style={{width:32,height:28,borderRadius:6,background:b.bg,display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:800,color:b.fg,flexShrink:0}}>{b.count}</div>
              <div>
                <div style={{fontSize:11,fontWeight:600,color:"#062B7A"}}>{b.label} priority</div>
                <div style={{height:4,width:120,background:"#E5E7EB",borderRadius:2,marginTop:2,overflow:"hidden"}}>
                  <div style={{height:"100%",width:`${Math.min(100,(b.count/Math.max(alerts.length,1))*100)}%`,background:b.fg,borderRadius:2}}/>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Top 3 actions */}
      {alerts.slice(0,3).map((a,i)=>{
        const pc = a.priority==="Critical"?{bg:"#FDF0F0",fg:"#FF5A6E"}:a.priority==="High"?{bg:"#FDF8EE",fg:"#FF9A2F"}:{bg:"#EDF5FE",fg:"#7A57D1"};
        return(
          <div key={a.id} style={{display:"flex",gap:8,alignItems:"flex-start",padding:"8px 10px",background:"#F8FAFC",borderRadius:7,marginBottom:i<2?6:0,cursor:"pointer",transition:"background 0.15s"}}
            onClick={()=>onNavigate&&onNavigate(a.module)}
            onMouseEnter={e=>e.currentTarget.style.background="#E5E7EB"}
            onMouseLeave={e=>e.currentTarget.style.background="#F8FAFC"}>
            <span style={{background:pc.bg,color:pc.fg,padding:"1px 7px",borderRadius:20,fontSize:9,fontWeight:700,flexShrink:0,marginTop:1}}>{a.priority}</span>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:11,fontWeight:600,color:"#062B7A",lineHeight:1.4}}>{a.title}</div>
            </div>
            <span style={{fontSize:9,color:"#6B7280",flexShrink:0,marginTop:2}}>{a.module}</span>
          </div>
        );
      })}

      {alerts.length>3&&(
        <button onClick={()=>onNavigate&&onNavigate("briefing")} style={{marginTop:8,width:"100%",padding:"7px",borderRadius:7,border:"1px dashed #D1D5DB",background:"transparent",color:"#6B7280",fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>
          View all {alerts.length} governance alerts →
        </button>
      )}
    </div>
  );
}

// ── Inline module alert banner ────────────────────────────────
function ModuleAlertBanner({module, alerts, onNavigate}){
  const moduleAlerts = alerts.filter(a=>a.module===module);
  if(moduleAlerts.length===0) return null;

  const critical = moduleAlerts.filter(a=>a.priority==="Critical").length;
  const high     = moduleAlerts.filter(a=>a.priority==="High").length;
  const topAlert = moduleAlerts[0];

  const bg     = critical>0?"#FDF0F0":high>0?"#FDF8EE":"#EDF5FE";
  const border = critical>0?"#FF5A6E":high>0?"#FF9A2F":"#7A57D1";
  const color  = critical>0?"#FF5A6E":high>0?"#FF9A2F":"#7A57D1";
  const icon   = critical>0?"⚠":high>0?"⚡":"ℹ";

  return(
    <div style={{
      margin:"0 0 16px 0",
      background:bg,
      border:`1px solid ${border}33`,
      borderLeft:`4px solid ${border}`,
      borderRadius:"0 9px 9px 0",
      padding:"10px 14px",
      display:"flex",
      justifyContent:"space-between",
      alignItems:"center",
      gap:12,
      flexShrink:0,
    }}>
      <div style={{display:"flex",gap:10,alignItems:"center",flex:1,minWidth:0}}>
        <span style={{fontSize:16,flexShrink:0}}>{icon}</span>
        <div style={{minWidth:0}}>
          <div style={{fontSize:12,fontWeight:700,color,marginBottom:1}}>
            {critical>0?`${critical} critical alert${critical!==1?"s":""} — action required`:`${moduleAlerts.length} compliance alert${moduleAlerts.length!==1?"s":" "}`}
          </div>
          <div style={{fontSize:11,color:"#374151",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{topAlert.title}</div>
        </div>
      </div>
      <div style={{display:"flex",gap:6,flexShrink:0}}>
        {critical>0&&<span style={{background:"#FF5A6E",color:"#fff",padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:700}}>{critical} Critical</span>}
        {high>0&&<span style={{background:"#FF9A2F",color:"#fff",padding:"1px 7px",borderRadius:20,fontSize:10,fontWeight:700}}>{high} High</span>}
      </div>
    </div>
  );
}

// ── Dashboard Governance Panel ────────────────────────────────
function DashboardGovernancePanel({alerts, onNavigate}){
  const [expanded, setExpanded] = useState(false);
  const shown = expanded ? alerts : alerts.slice(0,5);

  const priorityColor = p=>({
    Critical:{bg:"#FDF0F0",fg:"#FF5A6E",dot:"#FF5A6E"},
    High:    {bg:"#FDF8EE",fg:"#FF9A2F",dot:"#FF9A2F"},
    Medium:  {bg:"#EDF5FE",fg:"#7A57D1",dot:"#7A57D1"},
    Low:     {bg:"#F0FDF4",fg:"#16B5B8",dot:"#16B5B8"},
  }[p]||{bg:"#F8FAFC",fg:"#374151",dot:"#6B7280"});

  const moduleIcon = m=>({
    staff:"staff",serviceusers:"serviceusers",safeguarding:"safeguarding",
    medication:"medication",audits:"audits",calendar:"calendar",
  }[m]||"shield");

  if(alerts.length===0){
    return(
      <div style={{background:"#F0FDF4",borderRadius:12,padding:"20px",textAlign:"center",border:"1px solid #16B5B833"}}>
        <div style={{fontSize:24,marginBottom:8}}>✅</div>
        <div style={{fontSize:13,fontWeight:700,color:"#16B5B8",marginBottom:4}}>No governance alerts</div>
        <div style={{fontSize:11,color:"#6B7280"}}>All compliance checks are up to date</div>
      </div>
    );
  }

  return(
    <div style={{background:"#fff",borderRadius:12,boxShadow:"0 1px 3px rgba(28,50,82,0.07), 0 4px 12px rgba(28,50,82,0.04)",overflow:"hidden",marginBottom:16}}>
      <div style={{padding:"12px 18px",borderBottom:"1px solid #E5E7EB",display:"flex",justifyContent:"space-between",alignItems:"center",background:"#F8FAFC"}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <div style={{width:28,height:28,borderRadius:7,background:"#FDF0F0",display:"flex",alignItems:"center",justifyContent:"center"}}>
            <Icon name="shield" size={13} color="#FF5A6E" strokeWidth={2}/>
          </div>
          <div>
            <div style={{fontSize:13,fontWeight:700,color:"#062B7A"}}>Governance Actions Required</div>
            <div style={{fontSize:10,color:"#6B7280"}}>Live · {alerts.length} item{alerts.length!==1?"s":""} need attention</div>
          </div>
        </div>
        <div style={{display:"flex",gap:6}}>
          {[
            {p:"Critical",c:"#FF5A6E"},
            {p:"High",c:"#FF9A2F"},
            {p:"Medium",c:"#7A57D1"},
          ].map(({p,c})=>{
            const cnt = alerts.filter(a=>a.priority===p).length;
            return cnt>0&&(
              <span key={p} style={{background:c,color:"#fff",padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{cnt} {p}</span>
            );
          })}
        </div>
      </div>

      {shown.map((alert,i)=>{
        const pc = priorityColor(alert.priority);
        return(
          <div key={alert.id}
            onClick={()=>onNavigate&&onNavigate(alert.module)}
            style={{
              display:"flex",alignItems:"flex-start",gap:12,
              padding:"11px 18px",
              borderBottom:i<shown.length-1?"1px solid #E5E7EB":"none",
              background:i%2===0?"#fff":"#F8FAFC",
              cursor:"pointer",transition:"background 0.12s",
            }}
            onMouseEnter={e=>e.currentTarget.style.background="#F0FBFA"}
            onMouseLeave={e=>e.currentTarget.style.background=i%2===0?"#fff":"#F8FAFC"}>
            {/* Priority dot */}
            <div style={{width:8,height:8,borderRadius:"50%",background:pc.dot,flexShrink:0,marginTop:5}}/>
            {/* Module icon */}
            <div style={{width:28,height:28,borderRadius:7,background:`${pc.bg}`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
              <Icon name={moduleIcon(alert.module)} size={12} color={pc.fg} strokeWidth={2}/>
            </div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2,flexWrap:"wrap"}}>
                <span style={{background:pc.bg,color:pc.fg,padding:"1px 7px",borderRadius:20,fontSize:9,fontWeight:700}}>{alert.priority}</span>
                <span style={{fontSize:12,fontWeight:700,color:"#062B7A"}}>{alert.title}</span>
              </div>
              <div style={{fontSize:11,color:"#374151",lineHeight:1.5}}>{alert.action}</div>
            </div>
            <div style={{flexShrink:0,textAlign:"right"}}>
              <div style={{fontSize:10,color:"#6B7280"}}>{alert.dueDate}</div>
              <span style={{fontSize:10,color:"#16B5B8",fontWeight:600}}>→</span>
            </div>
          </div>
        );
      })}

      {alerts.length>5&&(
        <div style={{padding:"10px 18px",borderTop:"1px solid #E5E7EB",background:"#F8FAFC",display:"flex",justifyContent:"center"}}>
          <button onClick={()=>setExpanded(e=>!e)} style={{background:"none",border:"none",cursor:"pointer",fontSize:12,fontWeight:600,color:"#16B5B8",fontFamily:"inherit"}}>
            {expanded?`Show less ↑`:`Show all ${alerts.length} alerts ↓`}
          </button>
        </div>
      )}
    </div>
  );
}


